-- Poems batch 75
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('546fb303-eb77-4109-9395-8f57c8e9e6b1','逍遥詠  其二','宋太宗','宋','宋诗','song-poetry','','[]','精心求一善，一善許相宗。',48,'全唐诗/poet.song.1000.json','["精心求一善，一善許相宗。", "利物無窮盡，分明理道通。", "正邪名恍惚，曉悟見真空。", "象外行持法，玄言顯聖功。"]'),
('2069f28d-7907-4e7c-a2d0-03a25cd817da','逍遥詠  其三','宋太宗','宋','宋诗','song-poetry','','[]','百法還丹數，玄門各自深。',48,'全唐诗/poet.song.1000.json','["百法還丹數，玄門各自深。", "真空光似日，解脫本由心。", "迷惑終無應，精修重古今。", "循環豈暫息，七寶聚高岑。"]'),
('14715e38-bbe8-4a51-9d10-45399349861f','逍遥詠  其四','宋太宗','宋','宋诗','song-poetry','','[]','剛氣縱橫合，無人到所思。',48,'全唐诗/poet.song.1000.json','["剛氣縱橫合，無人到所思。", "浮生看即易，至理杳難知。", "返覆因興念，恒持入遠期。", "孤雲霄漢外，花見晚霜悲。"]'),
('74483384-50a6-4a59-bebe-043489c0d54f','逍遥詠  其五','宋太宗','宋','宋诗','song-poetry','','[]','我說逍遥理，其如要妙深。',48,'全唐诗/poet.song.1000.json','["我說逍遥理，其如要妙深。", "悟來時頃刻，迷者豈通尋。", "達即隨情遣，真緣不可侵。", "從來皆是事，巧拙在人心。"]'),
('eb4867d2-cf0f-4894-b385-a9c5b3252f49','逍遥詠  其六','宋太宗','宋','宋诗','song-poetry','','[]','一法歸千法，真如即是真。',48,'全唐诗/poet.song.1000.json','["一法歸千法，真如即是真。", "迷情終不見，達了悟知因。", "海納分他境，心平故可親。", "但明修鍊路，善業盡隨身。"]'),
('4696904f-bebc-4355-a3e8-f723c9bd6fbc','逍遥詠  其七','宋太宗','宋','宋诗','song-poetry','','[]','真一生天地，因依認宿緣。',48,'全唐诗/poet.song.1000.json','["真一生天地，因依認宿緣。", "智高通理性，凡下少周旋。", "語默何奇絕，幽深隠聖賢。", "誰人解我意，大道寸心玄。"]'),
('a479182c-1778-49cf-a487-04c76d94116f','逍遥詠  其八','宋太宗','宋','宋诗','song-poetry','','[]','天上與人間，賢愚不暫閑。',48,'全唐诗/poet.song.1000.json','["天上與人間，賢愚不暫閑。", "精修歸至理，道大隠玄關。", "聖境皆奇絕，凡情豈易攀。", "羣仙寬坦蕩，却老盡童顔。"]'),
('c2ef30f0-00cf-42fa-a058-fc96ca6f69d2','逍遥詠  其九','宋太宗','宋','宋诗','song-poetry','','[]','探玄何妙理，元化得均勻。',48,'全唐诗/poet.song.1000.json','["探玄何妙理，元化得均勻。", "去住分明紀，終期遠大親。", "物華堪賞詠，離撓最名珍。", "碧落翻霞彩，千秋不老春。"]'),
('1b306609-b238-4e10-87c0-2e29e5821d41','逍遥詠  其一○','宋太宗','宋','宋诗','song-poetry','','[]','誰人信我說，我說亦非常。',48,'全唐诗/poet.song.1000.json','["誰人信我說，我說亦非常。", "苦行分明樂，緣深解即忙。", "乖持如似夢，慕道得清凉。", "影響隨聲應，玄門可度量。"]'),
('739059b7-58a9-453a-9535-cc77e475bef9','逍遥詠  其一一','宋太宗','宋','宋诗','song-poetry','','[]','逍遥通大道，物象古從今。',48,'全唐诗/poet.song.1000.json','["逍遥通大道，物象古從今。", "一氣無窮極，三才妙更深。", "愚迷皆自縛，聖境可周尋。", "消息存亡理，先憂力不任。"]'),
('75e0e3bd-515f-40f5-913e-277061682a3e','逍遥詠  其一二','宋太宗','宋','宋诗','song-poetry','','[]','法則定乾坤，千秋與萬春。',48,'全唐诗/poet.song.1000.json','["法則定乾坤，千秋與萬春。", "金烏飛絳闕，玉兔弄精神。", "達識逢堪笑，賢愚本是真。", "清風摇聖境，仙說洞中人。"]'),
('e6ef3ecc-d654-4484-b308-d7a686390ccb','逍遥詠  其一三','宋太宗','宋','宋诗','song-poetry','','[]','逍遥閑物外，大道體柔剛。',48,'全唐诗/poet.song.1000.json','["逍遥閑物外，大道體柔剛。", "山河窮不盡，人心自短長。", "塵泥常曖昧，日月瑩輝光。", "出沒機關內，調持迥有方。"]'),
('bd87617c-be10-492e-b0a4-afa7fd2cf05a','逍遥詠  其一四','宋太宗','宋','宋诗','song-poetry','','[]','發願行平等，天觀必照知。',48,'全唐诗/poet.song.1000.json','["發願行平等，天觀必照知。", "貪嗔常不見，善惡豈相規。", "利益恒將正，勿教亂所思。", "因緣如響合，變化杳無爲。"]'),
('606d4cc1-8fd2-4b5f-94e1-75c784544c6c','逍遥詠  其一五','宋太宗','宋','宋诗','song-poetry','','[]','具足人難得，聰明別是非。',48,'全唐诗/poet.song.1000.json','["具足人難得，聰明別是非。", "志誠符感應，清靜扣玄機。", "道大雄名久，真邪有順違。", "精專閑彼我，萬法一宗歸。"]'),
('0dfa25bd-d52a-4dda-98c2-5b5644b5136e','逍遥詠  其一六','宋太宗','宋','宋诗','song-poetry','','[]','志節還難得，剛柔說是非。',48,'全唐诗/poet.song.1000.json','["志節還難得，剛柔說是非。", "秋霜明至道，春日麗光輝。", "桂影芳紅樹，馨香入紫微。", "無窮天地理，語默自依依。"]'),
('e11714e2-23d0-471e-aea5-6cf57ea25956','逍遥詠  其一七','宋太宗','宋','宋诗','song-poetry','','[]','詩中包異境，解者不爲非。',48,'全唐诗/poet.song.1000.json','["詩中包異境，解者不爲非。", "深信含玄理，幽通是可依。", "達人皆論道，狂酒敗稜威。", "浩渺寰瀛內，寒暄隠聖機。"]'),
('635c1c91-1cd3-4ff6-a5b4-d6a548bd354e','逍遥詠  其一八','宋太宗','宋','宋诗','song-poetry','','[]','逍遥名不易，一法貫真宗。',48,'全唐诗/poet.song.1000.json','["逍遥名不易，一法貫真宗。", "入位誰分別，深玄隠大功。", "杳冥難測度，象外理皆同。", "洞府羣仙侶，三天順九重。"]'),
('85d12b37-5428-4838-8155-6d80ff2bcc9a','逍遥詠  其一九','宋太宗','宋','宋诗','song-poetry','','[]','虛無知者少，秘默在丹田。',48,'全唐诗/poet.song.1000.json','["虛無知者少，秘默在丹田。", "鉛化金根樹，鼎光玉液泉。", "相宗難且易，絕妙理深玄。", "真境猶來是，依經學昔賢。"]'),
('af7b3c68-8e64-45be-bf1f-8afbf53be58c','逍遥詠  其二○','宋太宗','宋','宋诗','song-poetry','','[]','得一便須休，真空象外求。',48,'全唐诗/poet.song.1000.json','["得一便須休，真空象外求。", "昭然寬世界，幻化似浮漚。", "秘隠玄中理，幽深事莫投。", "天涯無畔岸，寶月順波流。"]'),
('fca05e8e-2a49-4f9e-a205-7c78d0543295','逍遥詠  其一','宋太宗','宋','宋诗','song-poetry','','[]','逍遥利樂認天真，心印深藏喻海津。',64,'全唐诗/poet.song.1000.json','["逍遥利樂認天真，心印深藏喻海津。", "妙法須求經裏字，無緣勞問洞中人。", "研窮道德從何入，清浄玄通馭物親。", "此語苞含堪賞詠，丹臺羽客善鋪陳。"]'),
('63734515-c554-4f59-888d-3460c016f8f9','逍遥詠  其二','宋太宗','宋','宋诗','song-poetry','','[]','於身日毅但多爲，賢聖何曾免是非。',64,'全唐诗/poet.song.1000.json','["於身日毅但多爲，賢聖何曾免是非。", "大道幾時明鄙隔，真宗隠顯在玄機。", "周知物理通還感，俯仰從來有順違。", "宜且守恒存禮讓，難中輕重兩相依。"]'),
('91838e8c-54ee-49ce-8947-c512603a456f','逍遥詠  其三','宋太宗','宋','宋诗','song-poetry','','[]','神仙上界道清虛，那箇何親那箇疏。',64,'全唐诗/poet.song.1000.json','["神仙上界道清虛，那箇何親那箇疏。", "修鍊豈教人世識，歸真本是太陽居。", "三天定相玄中得，一氣須聞妙更殊。", "運偶不同他往日，老來自在見功夫。"]'),
('f2b928c9-de6e-4b90-b83c-50c76cf8cc54','逍遥詠  其四','宋太宗','宋','宋诗','song-poetry','','[]','休話還丹大鼎滬，我緣經歷盡皆虛。',64,'全唐诗/poet.song.1000.json','["休話還丹大鼎滬，我緣經歷盡皆虛。", "人間豈有神仙藥，天上難開玉匱書。", "彭祖自勞閑歲月，穆王謾說走龍駒。", "矜孤恤寡行公道，此乃名爲利益殊。"]'),
('24106b4d-f80b-49bd-9d84-84e258ec9e77','逍遥詠  其五','宋太宗','宋','宋诗','song-poetry','','[]','靈藥從來隠聖機，何人得達到玄微。',64,'全唐诗/poet.song.1000.json','["靈藥從來隠聖機，何人得達到玄微。", "真空入有皆知實，運化功能到者稀。", "汞裏金牙堪可重，爐中白雪共含輝。", "勿令陰氣侵陽位，走作丹砂赫弈飛。"]'),
('ecf9bfe0-7d18-4b49-b8de-78cb61a04891','逍遥詠  其六','宋太宗','宋','宋诗','song-poetry','','[]','時人不識理深玄，細意精修補業牽。',64,'全唐诗/poet.song.1000.json','["時人不識理深玄，細意精修補業牽。", "幻化杳冥隨物性，虛無豈是亂相遷。", "龍飛入位真堪仰，虎伏休閑有自然。", "洞裏煙霞何縹緲，神仙景致沒休年。"]'),
('b7f066ac-5616-4839-8bc6-b44431188742','逍遥詠  其七','宋太宗','宋','宋诗','song-poetry','','[]','澤瀉池塘灌藥畦，太清雲黯步紅霓。',64,'全唐诗/poet.song.1000.json','["澤瀉池塘灌藥畦，太清雲黯步紅霓。", "松花鍊鼎龍山側，甲第羣仙鳳鶴棲。", "分別要從華等級，微言道泰物須齊。", "自吟自詠求師侶，入品詩流旋作題。"]'),
('258b6fc9-2470-4cb8-92be-4f84fcc011e3','逍遥詠  其八','宋太宗','宋','宋诗','song-poetry','','[]','道高人世禮周旋，語默如癡似不言。',64,'全唐诗/poet.song.1000.json','["道高人世禮周旋，語默如癡似不言。", "冼滌要教心地靜，狐疑勿類水萍翻。", "經書說盡修真理，歲月休防罷引援。", "雅合無爲深見識，陰陽去住促寒暄。"]'),
('c4df4824-f4ab-45e4-9050-fad611e29bd1','逍遥詠  其九','宋太宗','宋','宋诗','song-poetry','','[]','猶龍景象駕翔鸞，道在虛無天地間。',64,'全唐诗/poet.song.1000.json','["猶龍景象駕翔鸞，道在虛無天地間。", "一二合將歸大體，五千言外不開關。", "儀形眇邈難相類，聖跡希夷語默閑。", "昔日西遊如似夢，化胡異域却應還。"]'),
('5e7b21bf-0889-420d-93cd-36b30c9fa857','逍遥詠  其一○','宋太宗','宋','宋诗','song-poetry','','[]','乾坤之內隠長生，藥變還丹道已成。',128,'全唐诗/poet.song.1000.json','["乾坤之內隠長生，藥變還丹道已成。", "救世神方堪自祕，樂耶語話勿相輕。", "眠雲卧水通玄識，點石爲金誰辯明。", "黄才身心皆得所，登壇善聽步虛聲。", "鍊礦勿教侵外域，真鉛豈得離中華。", "天然五色被雲遮，聖境由來路逕賒。", "苞含日月高還遠，自是人心識見邪。", "龍浴鳳池誰可意，神仙羣聚笑吟呀。"]'),
('4e7bc6e7-3cd7-4919-bf51-7149e9c585cf','逍遥詠  其一一','宋太宗','宋','宋诗','song-poetry','','[]','傾依慕善易爲興，却恐人心冷似冰。',64,'全唐诗/poet.song.1000.json','["傾依慕善易爲興，却恐人心冷似冰。", "含識昭然何不達，非同物類信誰憑。", "强其志節皆知有，未盡任持早愛憎。", "倏忽便經閑歲月，凡間聖事可升騰。"]'),
('f537bcf3-dd20-4120-8b0b-5e788666ad28','逍遥詠  其一二','宋太宗','宋','宋诗','song-poetry','','[]','逍遥我詠杳冥中，萬物齊歸各異同。',64,'全唐诗/poet.song.1000.json','["逍遥我詠杳冥中，萬物齊歸各異同。", "曉解精微無所著，先從含識踐真空。", "希夷自變剛柔理，述作縱橫道不窮。", "剖判三才堪測度，輝華積德上玄功。"]'),
('9f45e6b9-5454-4df3-88ad-dee236dcbb0b','逍遥詠  其一三','宋太宗','宋','宋诗','song-poetry','','[]','神丹妙道故延年，豈是凡流識大仙。',64,'全唐诗/poet.song.1000.json','["神丹妙道故延年，豈是凡流識大仙。", "老子尚猶能諱事，軒皇不許亂相傳。", "誰知造化功夫力，罕見今生度宿緣。", "猛虎伏來龍駕馭，雲騰五色思悠然。"]'),
('5eece569-8d1d-4420-bdaf-a550ea9c509a','逍遥詠  其一四','宋太宗','宋','宋诗','song-poetry','','[]','誰知學道本來真，鉛汞爲媒最好親。',64,'全唐诗/poet.song.1000.json','["誰知學道本來真，鉛汞爲媒最好親。", "非是虛傳經歲月，自緣無識探龍津。", "初凝白雪堪可貴，解點黄金妙入神。", "術數催驅依造化，老顔改作後生人。"]'),
('535d7be5-b3f4-491f-a4e6-36c5b95d8a2d','逍遥詠  其一五','宋太宗','宋','宋诗','song-poetry','','[]','非來非去亦非忙，所是凡爲自短長。',64,'全唐诗/poet.song.1000.json','["非來非去亦非忙，所是凡爲自短長。", "專志比徒歸一等，誰知禮度畏三光。", "相傳祇要達真境，勿說辛勤却易傷。", "授得道心皆語默，四時八節順陰陽。"]'),
('e4e2f1fc-767c-42fb-ace3-1b6cad776473','逍遥詠  其一六','宋太宗','宋','宋诗','song-poetry','','[]','十洲洞府養神仙，歲說桑田屢變遷。',64,'全唐诗/poet.song.1000.json','["十洲洞府養神仙，歲說桑田屢變遷。", "老子商周爲柱史，劉安拔宅上青天。", "名山隠遁非堪守，鍊藥修真本自然。", "想取儀形通感應，徒勞運智亂烹煎。"]'),
('5b0a22ac-c809-4e7e-a79a-923c4e563327','逍遥詠  其一七','宋太宗','宋','宋诗','song-poetry','','[]','真空達得便須休，二起生三一上求。',64,'全唐诗/poet.song.1000.json','["真空達得便須休，二起生三一上求。", "謾說希夷來遂古，還知造化不同流。", "伏藏密旨機關內，合會非常本自由。", "若遇逢師親口訣，才年返少保千秋。"]'),
('a1ff196f-009d-4826-b208-cec16257fbc9','逍遥詠  其一八','宋太宗','宋','宋诗','song-poetry','','[]','見他顔貌未知年，便說人間壽一千。',64,'全唐诗/poet.song.1000.json','["見他顔貌未知年，便說人間壽一千。", "修鍊要門皆的實，行持法度甚精專。", "於身有益何般是，指口爲明道理全。", "更擬細窮方外事，無言無語上青天。"]'),
('1037cf2a-7847-4b70-8b9b-44b3e2f73a81','逍遥詠  其一九','宋太宗','宋','宋诗','song-poetry','','[]','大底緣由比類深，能中此道費光陰。',64,'全唐诗/poet.song.1000.json','["大底緣由比類深，能中此道費光陰。", "若知濁浪澄清水，不達浮生認白金。", "走作真珠藏妙理，究推神室好相尋。", "功成穩審時間用，變轉無窮重古今。"]'),
('7ba1da29-d097-44df-b1c9-d43ee42f3daa','逍遥詠  其一','宋太宗','宋','宋诗','song-poetry','','[]','脫空謾語莫知真，誑惑愚蒙呼殺人。',64,'全唐诗/poet.song.1000.json','["脫空謾語莫知真，誑惑愚蒙呼殺人。", "愛者擬求名利用，被他誤賺怕論申。", "唯言草異生巖谷，更說天涯泛海津。", "有甚相干爭道理，幾家燒鍊幾家貧。"]'),
('e1e035cd-2375-4195-9e5e-d3852d4d4e8c','逍遥詠  其二','宋太宗','宋','宋诗','song-poetry','','[]','逍遥理路達三清，非是尋常取次名。',128,'全唐诗/poet.song.1000.json','["逍遥理路達三清，非是尋常取次名。", "此語不宗凡見識，籠羅大象顯昭明。", "傍通照料周遮遠，異境凡從智慧生。", "言丈室中誰口默，真心傳受一般平。", "大道逢來是宿緣，終期定可訪真仙。", "山中修鍊非州郡，城裏無荒隠市鄽。", "祕術豈教容易得，幽深還許遞相傳。", "超凡入聖渾閑事，問取人間十洞天。"]'),
('c8f53b4a-a392-45e0-8b57-e5f39b9a62ad','逍遥詠  其三','宋太宗','宋','宋诗','song-poetry','','[]','道法窮來理甚玄，知之修鍊口親傳。',64,'全唐诗/poet.song.1000.json','["道法窮來理甚玄，知之修鍊口親傳。", "棲真有象藏烏兔，自在遨遊本地仙。", "赤水華池須是祕，黄牙寶鼎要精研。", "靈胎變化無相剋，龍虎昇騰論汞鉛。"]'),
('2599991e-89a3-4552-bbfe-58174e7569bf','逍遥詠  其四','宋太宗','宋','宋诗','song-poetry','','[]','玄機聖境謾勞心，何似窮研道理深。',64,'全唐诗/poet.song.1000.json','["玄機聖境謾勞心，何似窮研道理深。", "升降自然隨我命，莫教虛度向光陰。", "幾人達得幽閑趣，如樹爭高力不任。", "闇裏差殊終墜墮，神仙尚恐有飛沈。"]'),
('db66c1de-d268-419b-ada9-f694990b72bf','逍遥詠  其五','宋太宗','宋','宋诗','song-poetry','','[]','濟世勤行任百年，方知大道自昭宣。',64,'全唐诗/poet.song.1000.json','["濟世勤行任百年，方知大道自昭宣。", "休誇解變黄金術，誰信空磨白玉穿。", "智慧宜從高見識，陰功及物最彌堅。", "是非達取此言語，宇宙常存隠聖賢。"]'),
('0811c5e8-4ed0-49d8-85d3-bc376d0bab85','逍遥詠  其六','宋太宗','宋','宋诗','song-poetry','','[]','青松本不樹蕭條，學士因何智自勞。',64,'全唐诗/poet.song.1000.json','["青松本不樹蕭條，學士因何智自勞。", "金水朗然明皎潔，雪山堆積就中高。", "志心但覓三神藥，凡目難觀萬里毫。", "我獨閑吟誰解意，悠哉麗日壓靈鼇。"]'),
('019ddb16-20bc-419c-bf58-9079afb5ce99','逍遥詠  其七','宋太宗','宋','宋诗','song-poetry','','[]','乘雲駕鶴自西東，修鍊真人意氣雄。',128,'全唐诗/poet.song.1000.json','["乘雲駕鶴自西東，修鍊真人意氣雄。", "出離凡爲高見識，周旋道理遠懷通。", "愚迷盡說皆非實，解者方知事不空。", "宿業大都心外障，有緣歲月易成功。", "八風雷動遶炎洲，巨海波浪四畔流。", "鼠向此中毛骨異，布成將舊火燃休。", "白銀絳闕光霞麗，紫玉黄芝瑞氣浮。", "聖境山林人莫訝，延年皆是衆仙遊。"]'),
('54d08ce2-af73-4127-a845-789ca3e079ff','逍遥詠  其八','宋太宗','宋','宋诗','song-poetry','','[]','窮真妙理訪仙鄉，雲水青山地久長。',64,'全唐诗/poet.song.1000.json','["窮真妙理訪仙鄉，雲水青山地久長。", "聞說洞中諸境異，誰知鼎內有非常。", "遭逢祇是因緣感，費力無成枉用忙。", "瑞氣青天含象彩，十洲閑坐論陰陽。"]'),
('0016164e-1153-4d11-af5c-06612142b5cc','逍遥詠  其九','宋太宗','宋','宋诗','song-poetry','','[]','豈將容易話長生，辛苦徒勞業未精。',64,'全唐诗/poet.song.1000.json','["豈將容易話長生，辛苦徒勞業未精。", "安肯便教貪上得，先須禮讓後純誠。", "絳霄音旨人難解，白雪消停豎有橫。", "象外仙山諸境趣，若非修鍊躡三清。"]'),
('c0ab6635-9d26-4f32-abe3-69b123cd87f5','逍遥詠  其一○','宋太宗','宋','宋诗','song-poetry','','[]','丹丘霧彩好林巒，盡是天宮不死仙。',64,'全唐诗/poet.song.1000.json','["丹丘霧彩好林巒，盡是天宮不死仙。", "常與神人爲窟宅，能興風雨秀山川。", "溪頭雲出摇紅葉，谷口村稀伴碧煙。", "題品洞門房密祕，隠藏蹤跡恐相傳。"]'),
('f30f48a3-8162-47af-8d6b-ed18bcdd55b1','逍遥詠  其一一','宋太宗','宋','宋诗','song-poetry','','[]','南來北去及東西，萬物難歸一等齊。',64,'全唐诗/poet.song.1000.json','["南來北去及東西，萬物難歸一等齊。", "倏忽爭知興變易，幽玄恬澹不昏迷。", "區分有截無邪見，軌範如空詠好題。", "天且豈容私輔德，功成自豎入雲梯。"]'),
('58d471b3-38b5-4332-949b-10d7048fc4ef','逍遥詠  其一二','宋太宗','宋','宋诗','song-poetry','','[]','天地爲爐我自知，人無遠慮必生疑。',64,'全唐诗/poet.song.1000.json','["天地爲爐我自知，人無遠慮必生疑。", "功夫未至勞懸想，增外聲聞不改移。", "機巧豈逢容易得，是非終究欲何之。", "思量大海深淵理，光陰虛度影參差。"]'),
('7f1ca303-38a5-4a82-9165-39427b312f7d','逍遥詠  其一三','宋太宗','宋','宋诗','song-poetry','','[]','流砂一味細堪觀，萬象籠羅幾百般。',64,'全唐诗/poet.song.1000.json','["流砂一味細堪觀，萬象籠羅幾百般。", "須向鉛中相假合，分成鼎內見其端。", "煙霞聚散歸深谷，水火相逢不用乾。", "養就大還昇世界，月宮乞取桂花看。"]'),
('0a61f478-8c09-4b98-93ef-ebbd807db4ab','逍遥詠  其一四','宋太宗','宋','宋诗','song-poetry','','[]','崑崙山上聚神仙，羽駕爭行意不偏。',64,'全唐诗/poet.song.1000.json','["崑崙山上聚神仙，羽駕爭行意不偏。", "積雪遠看欹下界，巔峰高認湧流泉。", "真空的實難堪比，異景皆從造化遷。", "祕密豈教容易辨，玄中之外更深玄。"]'),
('21c9407b-8ce8-4184-8087-8e5f462ef05f','逍遥詠  其一五','宋太宗','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','溟溟滄海浪濤深，霧蔽山巒不易尋。',64,'全唐诗/poet.song.1000.json','["溟溟滄海浪濤深，霧蔽山巒不易尋。", "紫蓋洞庭人駕鶴，虹霓城郭道爲林。", "幽玄相去何多少，巧拙無由智慧侵。", "盡是同緣相引接，從容語話八仙心。"]'),
('a3bb35a3-0efc-4b9b-bac7-fb6b527ecc8b','逍遥詠  其一六','宋太宗','宋','宋诗','song-poetry','','[]','大都滋味莫因循，減節從教歲月身。',64,'全唐诗/poet.song.1000.json','["大都滋味莫因循，減節從教歲月身。", "述作比圖人世解，凡情謾說內丹真。", "消停意上寬還遠，宗旨猶來最好親。", "動靜機關勿勞苦，坎離卦象善調勻。"]'),
('e917da8b-7742-4284-9637-96f8f8e56cc3','逍遥詠  其一七','宋太宗','宋','宋诗','song-poetry','','[]','逍遥但信莫狐疑，天自高兮地本卑。',64,'全唐诗/poet.song.1000.json','["逍遥但信莫狐疑，天自高兮地本卑。", "曉取聲聞歸至道，從來法則盡如斯。", "物情運化真純理，謾說周遮問不知。", "性識賢愚俱一體，善緣惡業影相隨。"]'),
('de44aa13-a5c5-44c4-ba4d-5d5b7d22a54f','逍遥詠  其一八','宋太宗','宋','宋诗','song-poetry','','[]','靈芝出見少人知，此是含玄故不疑。',64,'全唐诗/poet.song.1000.json','["靈芝出見少人知，此是含玄故不疑。", "隠逸大同非妄想，精誠自化豈參差。", "翺翔碧落乘雲駕，宛轉虹霓入室時。", "至道就中升降等，凡田日用有盈虧。"]'),
('546ee3c8-03e6-4d57-b1a1-4d06eb11dddf','逍遥詠  其一','宋太宗','宋','宋诗','song-poetry','','[]','先賢所誡恐心邪，不說神明道理耶。',64,'全唐诗/poet.song.1000.json','["先賢所誡恐心邪，不說神明道理耶。", "豈信爐中生白雪，是非汞內産丹砂。", "華池自有延齡藥，龍虎相逢王幾家。", "十月陰陽須滿足，餘殘審細勿教差。"]'),
('2e5846e7-3f71-4aa0-8587-37f011fc1366','逍遥詠  其二','宋太宗','宋','宋诗','song-poetry','','[]','彩雲輕舉壓天津，舞鶴迎鸞自在身。',64,'全唐诗/poet.song.1000.json','["彩雲輕舉壓天津，舞鶴迎鸞自在身。", "蟾影枝開三島樹，桃花風弄十洲春。", "相傳靈異無虛說，道理分明盡是真。", "但信此中深護慎，修行所願勿因循。"]'),
('9903e773-6b7a-4afd-bffb-f9f170cd37d6','逍遥詠  其三','宋太宗','宋','宋诗','song-poetry','','[]','剛柔得所自安寧，五色霞光景象清。',64,'全唐诗/poet.song.1000.json','["剛柔得所自安寧，五色霞光景象清。", "龍倚穴吟雲雨至，虎依巖嘯澗風生。", "從容海嶠非遥遠，倏忽煙蘿別有情。", "誰到真空閑密地，火輪玉闕鎮常明。"]'),
('d8947e72-ee1b-495b-b6ab-8a9ac772cc82','逍遥詠  其四','宋太宗','宋','宋诗','song-poetry','','[]','天非愛道許人修，學士愚迷不到頭。',64,'全唐诗/poet.song.1000.json','["天非愛道許人修，學士愚迷不到頭。", "內境擬將何所用，杳知深邃故難求。", "丹霞隠密堪依仗，雪月縱橫入品流。", "消息頓然潜世慮，凡岐聖路有剛柔。"]'),
('335dd204-3b5e-4830-957a-b3408418d5df','逍遥詠  其五','宋太宗','宋','宋诗','song-poetry','','[]','逍遥裏外混諸天，澹蕩其中四敘間。',64,'全唐诗/poet.song.1000.json','["逍遥裏外混諸天，澹蕩其中四敘間。", "拂拭塵埃明印月，徧驅神鬼鎖驪山。", "裝添出沒何奇異，祕隠藏真未是閑。", "但好消詳清景內，勿生疑慮動機關。"]'),
('bd2d3062-bec7-48d0-947b-cf5c8835c544','逍遥詠  其六','宋太宗','宋','宋诗','song-poetry','','[]','口稱千歲少年顔，不是天人即地仙。',64,'全唐诗/poet.song.1000.json','["口稱千歲少年顔，不是天人即地仙。", "四海五湖皆徧歷，十洲三島去周遷。", "道高舉措何優劣，精彩非常語更賢。", "物理開襟通象外，未知幾許達深玄。"]'),
('bf2fa889-6791-402e-b101-dc26c6920b91','逍遥詠  其七','宋太宗','宋','宋诗','song-poetry','','[]','鸞棲洞府影交加，金鼎將成豈用誇。',64,'全唐诗/poet.song.1000.json','["鸞棲洞府影交加，金鼎將成豈用誇。", "向日迎陽爐上火，中秋望月桂開華。", "丹砂伏定縱橫藥，白雪飛騰不離家。", "一種爲鉛鉛自化，靈胎母子笑天涯。"]'),
('60e4743c-c117-44a1-b4b7-a4e3b4e99c0b','逍遥詠  其八','宋太宗','宋','宋诗','song-poetry','','[]','離男坎女甚清廉，金鼎分毫上火炎。',64,'全唐诗/poet.song.1000.json','["離男坎女甚清廉，金鼎分毫上火炎。", "莫把餘心懷利用，古先學士誡無厭。", "深藏異寶參詳理，已漸成形旋要添。", "運轉但教經歲月，光揚溢目衆人瞻。"]'),
('b143439f-594d-4432-9150-6d328124f027','逍遥詠  其九','宋太宗','宋','宋诗','song-poetry','','[]','何人曉了是兼非，鉛汞從凡隠聖機。',64,'全唐诗/poet.song.1000.json','["何人曉了是兼非，鉛汞從凡隠聖機。", "福壽丹砂隨日變，長生藥鼎負龍威。", "秦皇漢武終邪見，大道神仙在杳微。", "學似牛毛成似角，故然堪笑兩無依。"]'),
('8abd5927-501e-4980-b46c-f94a23e0ef9e','逍遥詠  其一○','宋太宗','宋','宋诗','song-poetry','','[]','逍遥抱一豈相差，方便門開智慧花。',64,'全唐诗/poet.song.1000.json','["逍遥抱一豈相差，方便門開智慧花。", "神室分形添石髓，華池巨燄隠靈砂。", "穹隆務實歸宗旨，釋意從容不是賒。", "滋味勿教貪過度，必然混世老天涯。"]'),
('9b82c27c-a049-4e3e-be1f-ef153fd05eaa','逍遥詠  其一一','宋太宗','宋','宋诗','song-poetry','','[]','龍虎剛柔隠聖方，一時和合運陰陽。',64,'全唐诗/poet.song.1000.json','["龍虎剛柔隠聖方，一時和合運陰陽。", "周知配類無疏失，物性從來理自長。", "鼎裏花開裝五彩，心明火候制三黄。", "更能通得華池妙，南北東西不可當。"]'),
('091364e1-dd5e-407c-aa5a-b04a6b16f26a','逍遥詠  其一二','宋太宗','宋','宋诗','song-poetry','','[]','神仙不死幾人存，欲界從頭是可論。',64,'全唐诗/poet.song.1000.json','["神仙不死幾人存，欲界從頭是可論。", "真實自然歸至理，狂顛逢見道須尊。", "分明記取依經典，消息臨時度曉昏。", "四敘推遷由反覆，唯占日月順乾坤。"]'),
('3319138a-676f-4462-a94d-dbd3918dfa3d','逍遥詠  其一三','宋太宗','宋','宋诗','song-poetry','','[]','逍遥密化道希夷，宗習羣流我詠之。',64,'全唐诗/poet.song.1000.json','["逍遥密化道希夷，宗習羣流我詠之。", "應是有情聽譬論，莫教虛度悟參差。", "深窮動靜宜消息，測隠玄元善所爲。", "性識更能通幻夢，恬然存相似生知。"]'),
('beb6df93-8d19-44fd-a6c3-80b9f8c3ffd1','逍遥詠  其一四','宋太宗','宋','宋诗','song-poetry','','[]','水精宮殿月華明，白玉爲牆火不侵。',64,'全唐诗/poet.song.1000.json','["水精宮殿月華明，白玉爲牆火不侵。", "八境風高駢羽駕，九重天上絳霞深。", "物情晃朗無遮隔，非是凡間比類尋。", "汗漫真遊誰得到，桂花香潔影森森。"]'),
('bd845861-fb22-4165-bccb-20bac5f8a70c','逍遥詠  其一五','宋太宗','宋','宋诗','song-poetry','','[]','從凡入聖作梯媒，紅燄爐深豈易裁。',64,'全唐诗/poet.song.1000.json','["從凡入聖作梯媒，紅燄爐深豈易裁。", "點化縱橫名大藥，納驅雜類謾成灰。", "真鉛即是機關理，闇室皆明任衆猜。", "未究前言勞自苦，精窮玄妙樂康哉。"]'),
('1eafc7d0-159f-44c8-bf3f-8833d156ac79','逍遥詠  其一六','宋太宗','宋','宋诗','song-poetry','','[]','交結從頭有順違，方知霧散若雲飛。',64,'全唐诗/poet.song.1000.json','["交結從頭有順違，方知霧散若雲飛。", "超凡入聖含金體，拋棄迷蒙掛紫衣。", "細認消停無遠近，分明意外隠玄機。", "相逢配偶爲閑事，誰解調持得一歸。"]'),
('37112079-be77-4eab-bde3-8aa8630e4f79','逍遥詠  其一七','宋太宗','宋','宋诗','song-poetry','','[]','昭宣形體思悠然，那是愚夫那是仙。',64,'全唐诗/poet.song.1000.json','["昭宣形體思悠然，那是愚夫那是仙。", "不識饒教非遠近，誤來何事苦相懸。", "含容裏外無諸物，象法其由語話詮。", "品格調高奔世界，任從他寶四周遷。"]'),
('de7f1052-f495-4f53-adb6-b7e21fdcbafd','逍遥詠  其一八','宋太宗','宋','宋诗','song-poetry','','[]','知之修鍊但辛勤，若志由來離六塵。',64,'全唐诗/poet.song.1000.json','["知之修鍊但辛勤，若志由來離六塵。", "金鼎乍分紅燄火，月魂高鎖碧潭津。", "深思五嶺凡間路，好作三天物外人。", "萬里州通寬世俗，清虛境象善求真。"]'),
('f0b9216e-97d4-46ef-a8df-7608081ef997','逍遥詠  其一九','宋太宗','宋','宋诗','song-poetry','','[]','知來祕法諭恒沙，須是鉛開汞上花。',64,'全唐诗/poet.song.1000.json','["知來祕法諭恒沙，須是鉛開汞上花。", "燒鍊勿令傷血脈，凡情散亂損黄牙。", "離男合度分明說，坎女和同不用誇。", "大矣日中成九轉，紅漿一飲到仙家。"]'),
('bc1ff831-11cf-4bbc-8136-44e83d2293ee','逍遥詠  其二○','宋太宗','宋','宋诗','song-poetry','','[]','還源根本杳難窮，祕密玄微造化中。',64,'全唐诗/poet.song.1000.json','["還源根本杳難窮，祕密玄微造化中。", "白日昏迷常不見，青龍霧曉大家同。", "陰陽表裏和煙碧，天地相鮮似火紅。", "直要審詳知道理，丹成千載上昇功。"]'),
('09e549e7-eec2-4c8b-a5d0-fab12f25f041','逍遥詠  其一','宋太宗','宋','宋诗','song-poetry','','[]','還元到即見真歸，不是虛傳羽化飛。',64,'全唐诗/poet.song.1000.json','["還元到即見真歸，不是虛傳羽化飛。", "大道勿將閑設用，精修別得便忘機。", "安排穩入龍宮內，變易終藏虎鼎威。", "豁達乾坤神妙理，逍遥鉛汞共相依。"]'),
('1ff2f83c-e14d-43e9-879f-ea5c5fe0fcff','逍遥詠  其二','宋太宗','宋','宋诗','song-poetry','','[]','鶴骨巖巖混世間，不侵寒暑似童顔。',64,'全唐诗/poet.song.1000.json','["鶴骨巖巖混世間，不侵寒暑似童顔。", "精神爽麗方干典，舉步如飛思慮閑。", "起坐問他修鍊法，亂將詞理勿交關。", "生來靜却凡愚見，又說三仙有大還。"]'),
('015d24bc-8917-4b27-995b-daa002386545','逍遥詠  其三','宋太宗','宋','宋诗','song-poetry','','[]','停騰火候詰炎山，九轉方能濟世間。',64,'全唐诗/poet.song.1000.json','["停騰火候詰炎山，九轉方能濟世間。", "玉蘂花開真可愛，紅爐鼎內境幽閑。", "人逢藥就延長久，羽駕仙迎返少顔。", "盡在目前非是遠，定知時日好登攀。"]'),
('8b08baea-9af1-4f49-9d63-e08f0e9d62f8','逍遥詠  其四','宋太宗','宋','宋诗','song-poetry','','[]','泥丸本是命根宮，消息臨時語話通。',64,'全唐诗/poet.song.1000.json','["泥丸本是命根宮，消息臨時語話通。", "大道比來行氣術，其餘效驗藉陰功。", "物情之理皆清浄，造化玄微事莫同。", "珍重此言深可意，腹中日運鼎花空。"]'),
('52d576a8-3be6-4559-b794-2210aea6782f','逍遥詠  其五','宋太宗','宋','宋诗','song-poetry','','[]','無名蹤跡故難興，智者消詳冷似冰。',64,'全唐诗/poet.song.1000.json','["無名蹤跡故難興，智者消詳冷似冰。", "廓落異端隨日變，乖違法度受天懲。", "機關勿使招他謗，亮直溫和自舉升。", "好事相宗堪軌範，方言內外一般稱。"]'),
('0d977f00-b2ea-4ea7-a474-cb499b3caaf7','逍遥詠  其六','宋太宗','宋','宋诗','song-poetry','','[]','天生顔貌幾何般，鶴骨餐霞厭俗觀。',64,'全唐诗/poet.song.1000.json','["天生顔貌幾何般，鶴骨餐霞厭俗觀。", "赤水華池誰法則，白銀爲闕又堪看。", "來傳音旨俱然混，位有尊卑勿異端。", "逆順之中關理性，心田靜外豈相干。"]'),
('e9bcdbc3-159d-4f9f-ace9-d30e1d633ef7','逍遥詠  其七','宋太宗','宋','宋诗','song-poetry','','[]','靈草靈砂起自然，却將非外亂烹煎。',64,'全唐诗/poet.song.1000.json','["靈草靈砂起自然，却將非外亂烹煎。", "黄牙成土堪名藥，秋石爲胎本是鉛。", "樂道逢來忻且喜，周知體認更完全。", "陽施陰授宜消息，不識時人在眼前。"]'),
('44e344eb-eb99-44de-a835-7e241f77deca','逍遥詠  其八','宋太宗','宋','宋诗','song-poetry','','[]','逍遥我命在玄穹，鶴宿霞栖景致中。',64,'全唐诗/poet.song.1000.json','["逍遥我命在玄穹，鶴宿霞栖景致中。", "自得安寧兼養道，更將利益屏羣雄。", "淵深引古知今用，劈斫區分盡可通。", "和暢五音從豁達，乾坤之內靄溟濛。"]'),
('0ecf931d-b04d-43cd-940b-3f2e24671895','逍遥詠  其九','宋太宗','宋','宋诗','song-poetry','','[]','巔峰一望不深潭，誰解緣情語話堪。',64,'全唐诗/poet.song.1000.json','["巔峰一望不深潭，誰解緣情語話堪。", "暗室自開明日月，道心奇異老山菴。", "研窮妙理真消息，誡忌先賢讓不貪。", "稽古尚爲今法則，愚蒙太甚苦談談。"]'),
('9cb59f31-9fc8-4228-8fd3-6e418483ed26','逍遥詠  其一○','宋太宗','宋','宋诗','song-poetry','','[]','千年福壽自由人，萬象星羅仰在身。',64,'全唐诗/poet.song.1000.json','["千年福壽自由人，萬象星羅仰在身。", "寶馬不教龜鱉乳，嘉禾須問穀田神。", "根株種植華池內，藥鼎煎催運火勻。", "混沌分來皆是道，二儀交感八方親。"]'),
('19988973-36a2-452f-9fc3-6d1034dfbd35','逍遥詠  其一一','宋太宗','宋','宋诗','song-poetry','','[]','非人口似瀉汾河，此輩塵中有甚多。',64,'全唐诗/poet.song.1000.json','["非人口似瀉汾河，此輩塵中有甚多。", "心恨貌恭無定止，舌誇端正亂乖訛。", "爲官善政身榮祿，利劍休教石上磨。", "立待滿盈船陷水，惡風從被海神拖。"]'),
('fac63306-cb53-45fb-b73f-61c6ec58c3c6','逍遥詠  其一二','宋太宗','宋','宋诗','song-poetry','','[]','精詳語議四門開，舒慘陽和意外裁。',64,'全唐诗/poet.song.1000.json','["精詳語議四門開，舒慘陽和意外裁。", "遠見風塵思往事，無窮日月去還來。", "樂耶指趣歸三體，周旋道理遍九垓。", "賢聖人天常法則，卿雲嶺上白皚皚。"]'),
('45d11bb1-3625-4b52-a9c1-de5173918664','逍遥詠  其一三','宋太宗','宋','宋诗','song-poetry','','[]','飛騰自在莫教賒，坎女離男共一家。',64,'全唐诗/poet.song.1000.json','["飛騰自在莫教賒，坎女離男共一家。", "無礙逍遥通智慧，將求利樂勿須誇。", "靈根就看和春雪，神室之中有絳砂。", "彼是彼非堪可重，常娥倚樹笑唅呀。"]'),
('0e54f552-712f-4e79-8cf9-106d531f9495','逍遥詠  其一四','宋太宗','宋','宋诗','song-poetry','','[]','貪染猶來理不通，虛勞歲月面西東。',64,'全唐诗/poet.song.1000.json','["貪染猶來理不通，虛勞歲月面西東。", "從前自是凡心別，利益須歸上帝功。", "洞府名高同景致，塵泥蹤跡莫知空。", "去非但向鉛中作，變化飛騰大道雄。"]'),
('bf7d0777-fb9d-46a5-89ed-6daef3a4d8b9','逍遥詠  其一五','宋太宗','宋','宋诗','song-poetry','','[]','達道真人見者稀，豈教容易等閑知。',64,'全唐诗/poet.song.1000.json','["達道真人見者稀，豈教容易等閑知。", "陰陽造化無非實，天地元精動合宜。", "功行三千須及物，還丹九轉上昇時。", "忙中歲月忙中遣，我本愚來性不移。"]'),
('4f91ef50-c311-494b-b2f8-d2ad87482fd6','逍遥詠  其一六','宋太宗','宋','宋诗','song-poetry','','[]','栖心隠逸故非常，大約恒持要久長。',64,'全唐诗/poet.song.1000.json','["栖心隠逸故非常，大約恒持要久長。", "清浄好爲皆是益，周旋理度審安詳。", "法乾馭物須平穩，順日成功自酌量。", "倏忽之間堪疋配，臨時巧拙見圓方。"]'),
('33b8d66b-e81c-4618-8ec8-589d9515e996','逍遥詠  其一七','宋太宗','宋','宋诗','song-poetry','','[]','香湯沐浴更齋清，運動形軀四體輕。',64,'全唐诗/poet.song.1000.json','["香湯沐浴更齋清，運動形軀四體輕。", "魔鬼自然生怕怖，神魂必定轉安寧。", "從無入有皆真實，去住何難妙最精。", "五行聚散歸一體，靈源不用苦煎烹。"]'),
('e5acf6d3-f77b-4de6-be77-4c0c90e62f27','逍遥詠  其一八','宋太宗','宋','宋诗','song-poetry','','[]','一身獨善欲何之，爭及衣冠解撫綏。',64,'全唐诗/poet.song.1000.json','["一身獨善欲何之，爭及衣冠解撫綏。", "浮世淺情無限量，愚蒙自是不相規。", "直須憑仗分明說，語取靈源問得知。", "要覓洞中閑日月，除將濟事謾非爲。"]'),
('edfa1cf3-8223-4252-abbe-9742a531e87e','逍遥詠  其一九','宋太宗','宋','宋诗','song-poetry','','[]','尋思道味詠吟哦，去住先賢有幾何。',64,'全唐诗/poet.song.1000.json','["尋思道味詠吟哦，去住先賢有幾何。", "性識無凝關要妙，浮沈依約不言多。", "但將子細分明說，猶恐閑非却被魔。", "救世比來心所願，逍遥盡入扣玄歌。"]'),
('386ac4f4-ee4a-4c69-a153-fb1d78d8ef93','逍遥詠  其二○','宋太宗','宋','宋诗','song-poetry','','[]','鉛汞丹方不謾論，同歸一體有玄門。',64,'全唐诗/poet.song.1000.json','["鉛汞丹方不謾論，同歸一體有玄門。", "剛柔産取黄牙樹，遠近先明赤水魂。", "化質昭然清日月，縱橫無礙杳乾坤。", "龍吟虎嘯真非是，霧散雲飛似雨奔。"]'),
('74bc9c95-8bd1-4100-866d-4a0f6473e563','逍遥詠  其一','宋太宗','宋','宋诗','song-poetry','','[]','道妙懷真紀異常，人間天上若存亡。',64,'全唐诗/poet.song.1000.json','["道妙懷真紀異常，人間天上若存亡。", "潜機物類多中覷，納取虛無定久長。", "碧落遨遊歸洞府，黄金不買自馨香。", "參同契合諸經說，精魄奪來爛紫光。"]'),
('3b29c602-bc78-4c3f-ac35-33ef74ebeca7','逍遥詠  其二','宋太宗','宋','宋诗','song-poetry','','[]','無爲道大入幽玄，幾許風光慕昔賢。',64,'全唐诗/poet.song.1000.json','["無爲道大入幽玄，幾許風光慕昔賢。", "對境盡同閑見識，忙中皆是急相煎。", "配匹直須寬雅淡，會有逢時不偶然。", "修鍊但教堅志氣，參詳穩審更周旋。"]'),
('7e1715d8-cb93-4a7c-a43a-311905f03db8','逍遥詠  其三','宋太宗','宋','宋诗','song-poetry','','[]','含胎長養盡籠羅，豈離玄談道理麽。',64,'全唐诗/poet.song.1000.json','["含胎長養盡籠羅，豈離玄談道理麽。", "狐兔幾曾能乳馬，麥田斷定不生禾。", "目前便是真佳境，汞內消停自合和。", "認取門庭深見解，紅砂奇異湧恒河。"]'),
('1a1c9d2b-75a9-447d-8710-5d7f0fc69871','逍遥詠  其四','宋太宗','宋','宋诗','song-poetry','','[]','人心多是少相投，非識塵中上品流。',64,'全唐诗/poet.song.1000.json','["人心多是少相投，非識塵中上品流。", "不見真宗歸物理，難知妙道後先休。", "生前內鼎宜烹鍊，殊勝華池好漸修。", "但見完全憑土德，能調火候藥皆秋。"]'),
('a0c4d586-4aaf-48db-856d-7e86954bd859','逍遥詠  其五','宋太宗','宋','宋诗','song-poetry','','[]','玄之玄又見真空，巧拙臨時要妙中。',64,'全唐诗/poet.song.1000.json','["玄之玄又見真空，巧拙臨時要妙中。", "大智伏藏知遠近，纖微盡達了然通。", "周旋物性誰區別，坦蕩由來是且同。", "境致三才隨有位，神光照室瑩西東。"]'),
('fb0e20e4-b82c-47ad-88a1-e8efe2226c64','逍遥詠  其六','宋太宗','宋','宋诗','song-poetry','','[]','還丹未就且降魔，二八從教細攪和。',64,'全唐诗/poet.song.1000.json','["還丹未就且降魔，二八從教細攪和。", "離火摧駈凡入聖，坎鉛功力甚僂儸。", "紅塵自化真堪貴，白雪增盈不用多。", "九轉龍吟成虎嘯，人非人是狀巍峨。"]'),
('2dabc360-76a0-4a43-a653-44f1f606d33b','逍遥詠  其七','宋太宗','宋','宋诗','song-poetry','','[]','難求的當問愚癡，那箇堪言好事知。',64,'全唐诗/poet.song.1000.json','["難求的當問愚癡，那箇堪言好事知。", "名利猛貪無有足，多端動止沒規儀。", "浮生不實將何用，欲把非常亂作爲。", "謾語饒教能配類，一朝患害殢他誰。"]'),
('6416e2c1-6b7c-460a-b0bf-e8641a1d1e0e','逍遥詠  其八','宋太宗','宋','宋诗','song-poetry','','[]','千般萬類不相逢，天地尊地卑豈易窮。',65,'全唐诗/poet.song.1000.json','["千般萬類不相逢，天地尊地卑豈易窮。", "海岳高深隨日轉，神仙聚樂隠塵中。", "鮮求名利知貪少，多事閑忙總是空。", "幾箇心賢平坦蕩，十洲三島自從容。"]'),
('fe75273d-6785-4a21-a9da-a05c06050761','逍遥詠  其九','宋太宗','宋','宋诗','song-poetry','','[]','含元得一本真宗，誤者平論總是空。',64,'全唐诗/poet.song.1000.json','["含元得一本真宗，誤者平論總是空。", "萬象都來皆備數，千言譬諭了然通。", "才高俊彥優堪賞，竊祿偷安有異同。", "唯願他心如似我，不教陷惡罪身中。"]'),
('79791ec0-e81b-458e-8f3c-29ae4c565e1c','逍遥詠  其一○','宋太宗','宋','宋诗','song-poetry','','[]','乾關萬象審消停，子母相傳日月精。',64,'全唐诗/poet.song.1000.json','["乾關萬象審消停，子母相傳日月精。", "産藥要教千日化，玄門全藉五行清。", "靈胎脫體方知聖，鉛汞梯媒不是名。", "金鼎就來從變質，陽和陰氣兩俱生。"]'),
('eb32c873-d65a-47a1-9065-844646ed1c8a','逍遥詠  其一一','宋太宗','宋','宋诗','song-poetry','','[]','九重天上帝仙居，愚昧求真道理疏。',64,'全唐诗/poet.song.1000.json','["九重天上帝仙居，愚昧求真道理疏。", "混沌初分長日月，精魂聚散記丹書。", "離男坎女皆相類，壬子丙丁異境殊。", "歷劫因緣隨世在，陰功及物最玄殊。"]'),
('9a44af63-6dae-4d5a-bbd4-8e06c13cd819','逍遥詠  其一二','宋太宗','宋','宋诗','song-poetry','','[]','神水華池妙更精，非鉛非汞妄干名。',64,'全唐诗/poet.song.1000.json','["神水華池妙更精，非鉛非汞妄干名。", "河車本是延齡藥，戊子從教配類成。", "朱雀坎蛇安在後，青龍白虎免交爭。", "若使真金全二八，何憂住世不長生。"]'),
('da4d48ba-f798-437f-9c55-f1075cd56e0f','逍遥詠  其一三','宋太宗','宋','宋诗','song-poetry','','[]','還知受氣稟天然，百法方爲事理全。',64,'全唐诗/poet.song.1000.json','["還知受氣稟天然，百法方爲事理全。", "假合都來歸至道，修持遠大理通玄。", "二儀交感成祥瑞，八卦剛柔被俗牽。", "何謂此中生恍惚，直須欵曲細精研。"]'),
('e43c68f4-8a79-4f39-abf3-6ef17b254e1c','逍遥詠  其一四','宋太宗','宋','宋诗','song-poetry','','[]','玄門至道故無涯，自是人心所見邪。',64,'全唐诗/poet.song.1000.json','["玄門至道故無涯，自是人心所見邪。", "智識未能通大藥，豈將容易擬榮家。", "千年聖境何虛謬，百劫曾修不用遮。", "龍虎欲成堪鍊鼎，勿爲利路亂交加。"]'),
('de3be36f-2f58-4128-a6aa-c3514ab6165e','逍遥詠  其一五','宋太宗','宋','宋诗','song-poetry','','[]','論功須是一陽初，二八調和作楷模。',64,'全唐诗/poet.song.1000.json','["論功須是一陽初，二八調和作楷模。", "固濟但牢封密閉，莫教中道有差殊。", "依時消息專心記，在意停騰運火徐。", "日月無虧明節候，從容願所不躊躇。"]'),
('40f2c03c-79a4-488a-9d39-aaaa58e4790d','逍遥詠  其一六','宋太宗','宋','宋诗','song-poetry','','[]','還丹百數細須尋，以驗從來道理深。',64,'全唐诗/poet.song.1000.json','["還丹百數細須尋，以驗從來道理深。", "火候混成如白屑，水中凝結是黄金。", "循環復始周旋鼎，造化駈馳要用心。", "消息玄門窮八卦，飛騰自在遠山岑。"]'),
('750b4ae9-c3ea-456f-903b-ba53978f731b','逍遥詠  其一七','宋太宗','宋','宋诗','song-poetry','','[]','真空修鍊永長年，不識還丹在眼前。',64,'全唐诗/poet.song.1000.json','["真空修鍊永長年，不識還丹在眼前。", "一得清來光宇宙，千朝須是用烹煎。", "人間天上分明錄，汞裏花開豈偶然。", "達取但教依理路，勿貪世利悞周旋。"]'),
('c5ffa758-6783-4577-8557-058a43d9a8ff','逍遥詠  其一八','宋太宗','宋','宋诗','song-poetry','','[]','烘烘火色水中論，至寶須教鼎內存。',64,'全唐诗/poet.song.1000.json','["烘烘火色水中論，至寶須教鼎內存。", "點化自然常在手，區分道理有玄門。", "莫將容易誇言說，盡入虛無是我尊。", "天動地神邪可畏，丹能飛走似雲奔。"]'),
('f00bcafe-3f96-447a-a027-251d9c4838e1','逍遥詠  其一九','宋太宗','宋','宋诗','song-poetry','','[]','人是人非意頗同，較量此事盡歸空。',64,'全唐诗/poet.song.1000.json','["人是人非意頗同，較量此事盡歸空。", "無爲政化求真理，方表深仁大道雄。", "舉止但能恒有節，尋思何處不周通。", "寰瀛善惡知多少，莫忘生前積德功。"]'),
('52b71b15-7010-4480-8106-6dc2ea7f0120','逍遥詠  其二○','宋太宗','宋','宋诗','song-poetry','','[]','因緣業障遇真稀，黄帝乘龍豈是非。',64,'全唐诗/poet.song.1000.json','["因緣業障遇真稀，黄帝乘龍豈是非。", "達識尚凝常恍惚，愚蒙學解故相違。", "華池秘密人天授，神室光揚日月輝。", "智者無言皆口嘿，敢將容易論玄機。"]'),
('9fdd9c99-7425-4d1d-96df-75cc7316dde2','逍遥歌','宋太宗','宋','宋诗','song-poetry','','[]','逍遥自在何拘束，天地希夷無返覆。',384,'全唐诗/poet.song.1000.json','["逍遥自在何拘束，天地希夷無返覆。", "勿把他心向外求，真宗理道相和睦。", "人間天上盡修行，七寶山高混太清。", "玉樹玄珠明照室，命根悟者轉增盈。", "虛無入有何蹤跡，非是神光化金液。", "廓落方圓在杳冥，南來北去斷消息。", "靈元物象向天涯，古往今來聖事誇。", "無礙智通精進心，研窮理路互交加。", "奇哉離燄烹鉛水，清靜之中藏奧旨。", "出沒門庭景異常，十洲隠大神仙子。", "綿綿若論太幽深，即是流珠不是金。", "萬卷經文兼在目，機關絕妙有浮沈。", "開關寤寐來相逼，魄走魂歸天地力。", "風掃塵埃躡紫雲，睹其顔邈難別識。", "勿生疑慮變陰陽，須信丹砂道理長。", "若向此中明此義，十洲洞府藴馨香。", "康哉內景植仙桂，枝葉婆娑深根蒂。", "真宗妙法審來由，修鍊真空無涯際。", "要知逆順莫相非，廣演周遮隠玄機。", "先說艱難後始說，精窮運化遂相依。", "瑶池浴鳳通霄漢，金闕光舒何燦爛。", "丹成可驗不狐疑，常娥偷竊月中看。", "春間花卉一齊開，天上優游誰肯來。", "洞裏煙霞牢秘隠，水精宮殿白皚皚。"]'),
('3230af3a-769b-44ce-bede-be880ce93ce6','緣識  其一','宋太宗','宋','宋诗','song-poetry','','[]','靈無知大道，極意思悠然。',48,'全唐诗/poet.song.1000.json','["靈無知大道，極意思悠然。", "摩日雲中雁，瀟湘水似天。", "孤峰高遠近，實月瑩團圓。", "信解明開悟，青霄在目前。"]'),
('9413fd9a-170c-4018-ac24-ae438d95aaaa','緣識  其二','宋太宗','宋','宋诗','song-poetry','','[]','往事興人感，徘徊思寂寥。',48,'全唐诗/poet.song.1000.json','["往事興人感，徘徊思寂寥。", "湛然窮古道，羣品似相邀。", "春臺松柏靜，秋風海岳摇。", "時遷何倏忽，落葉自零飄。"]'),
('d24b1d10-f396-4858-9c49-33e222018b49','緣識  其三','宋太宗','宋','宋诗','song-poetry','','[]','誰測玄機聖，天功地久長。',48,'全唐诗/poet.song.1000.json','["誰測玄機聖，天功地久長。", "羣生皆是性，道德有圓方。", "姘醜隨情意，於戲細酌量。", "達人知澹薄，默默見非常。"]'),
('abe088c1-5179-4a26-8a47-abd518eca97f','緣識  其四','宋太宗','宋','宋诗','song-poetry','','[]','當看浮生業，朝觀暮亦悲。',48,'全唐诗/poet.song.1000.json','["當看浮生業，朝觀暮亦悲。", "笑迎先溟目，惡至聚愁眉。", "正直迴斜曲，冤逢不用推。", "小人心似獸，君子定無欺。"]'),
('e2f0ff50-d626-42b3-84b8-bca069e6510a','緣識  其五','宋太宗','宋','宋诗','song-poetry','','[]','恍惚人難曉，天仙語默玄。',48,'全唐诗/poet.song.1000.json','["恍惚人難曉，天仙語默玄。", "修心無道理，終日自忙然。", "我命真中趣，長生認宿緣。", "機權饒使用，聖事不虛傳。"]'),
('03e3b5e4-e955-4d03-a8c2-1668a1841f6e','緣識  其六','宋太宗','宋','宋诗','song-poetry','','[]','大道常恭謹，明靈不降威。',48,'全唐诗/poet.song.1000.json','["大道常恭謹，明靈不降威。", "少言知有信，多事自招非。", "年壽看松柏，冠簪短布衣。", "我心忙也樂，清浄得同歸。"]'),
('c10485d6-e8b8-4d15-a510-b535af9062f0','緣識  其七','宋太宗','宋','宋诗','song-poetry','','[]','清靜真空理，不無解者難。',48,'全唐诗/poet.song.1000.json','["清靜真空理，不無解者難。", "縱橫依見性，廓落智中觀。", "坦蕩歸仁德，辛勤久遠看。", "勿教爲逆順，平地入雲端。"]'),
('a9b1e3a0-742e-42b8-b252-2128effe5746','緣識  其八','宋太宗','宋','宋诗','song-poetry','','[]','寂靜人歌詠，愚情豈易知。',48,'全唐诗/poet.song.1000.json','["寂靜人歌詠，愚情豈易知。", "但求心自樂，不怕面相欺。", "枉直回邪滅，顛狂道德持。", "高明常鑒照，方寸欲何之。"]'),
('3376b6d9-0b41-4b95-8f9c-df48e1aa4806','緣識  其九','宋太宗','宋','宋诗','song-poetry','','[]','天界殊勝理，凡愚不易知。',48,'全唐诗/poet.song.1000.json','["天界殊勝理，凡愚不易知。", "曩因誰可究，淺近故懷疑。", "的實歸真性，回邪入正持。", "樂耶親大道，報應自然之。"]'),
('037bd240-486e-4a52-b550-931d76004353','緣識  其一○','宋太宗','宋','宋诗','song-poetry','','[]','浮生人怕死，螻蟻命何輕。',48,'全唐诗/poet.song.1000.json','["浮生人怕死，螻蟻命何輕。", "福業隨緣寂，慈悲響善名。", "在家行孝愛，食祿盡忠貞。", "天道不移改，佛心化有情。"]'),
('ef2bb60a-d251-4f5c-a207-f12d11316924','緣識  其一一','宋太宗','宋','宋诗','song-poetry','','[]','逍遥賢聖樂，我悶俗情愚。',48,'全唐诗/poet.song.1000.json','["逍遥賢聖樂，我悶俗情愚。", "鄙俚何堪數，斟量解卷舒。", "惡緣須盡去，善事好相於。", "忙急真如夢，乾坤造化殊。"]'),
('8946d892-9a4e-4233-8c37-7233658472c2','緣識  其一二','宋太宗','宋','宋诗','song-poetry','','[]','謙遜明然得，滋章道理疏。',48,'全唐诗/poet.song.1000.json','["謙遜明然得，滋章道理疏。", "榮枯皆定分，巧拙亦何如。", "撫俗從仁感，臨民用教敷。", "高明歸輔德，建立紀功書。"]'),
('cbc7611a-9f39-40d6-a9d7-4a4000b5e100','緣識  其一三','宋太宗','宋','宋诗','song-poetry','','[]','形影隨人得，精修道不迷。',48,'全唐诗/poet.song.1000.json','["形影隨人得，精修道不迷。", "研窮深理路，造化隠端倪。", "雲引龍吟穴，風生虎嘯溪。", "少知愚豈解，南北與東西。"]'),
('da9be0cd-9e2c-4eec-9e14-eda78d938818','緣識  其一四','宋太宗','宋','宋诗','song-poetry','','[]','無窮思廣大，幽隠便知深。',48,'全唐诗/poet.song.1000.json','["無窮思廣大，幽隠便知深。", "智達千經論，方關一寸心。", "總明懷往古，曩劫順從今。", "此理人須信，周旋子細尋。"]'),
('d31f1f70-67f7-431a-b923-7d8fc1da6811','緣識  其一五','宋太宗','宋','宋诗','song-poetry','','[]','伏藏終不見，巧拙是兼非。',48,'全唐诗/poet.song.1000.json','["伏藏終不見，巧拙是兼非。", "至道光懷古，周通隠聖機。", "清天何物性，濁地故相依。", "修鍊真堪惜，疏慵有順違。"]'),
('3b2ac118-b6cd-4421-b603-2ea06105fd5d','緣識  其一六','宋太宗','宋','宋诗','song-poetry','','[]','爲人能省己，就靜亦皆忙。',48,'全唐诗/poet.song.1000.json','["爲人能省己，就靜亦皆忙。", "春去秋來定，年諸日遠長。", "英姿終有異，賤品足顛狂。", "蠢動含靈性，善生惡自亡。"]'),
('970ad675-d479-4e5d-b70c-a22b3227adc0','緣識  其一七','宋太宗','宋','宋诗','song-poetry','','[]','知之修鍊法，便是聖中人。',48,'全唐诗/poet.song.1000.json','["知之修鍊法，便是聖中人。", "有象虛無境，邪緣不見真。", "恒持功行益，響應甚平均。", "渾然天地理，大道遍乾坤。"]'),
('c2a60dfb-7f91-40af-8ee1-71eb193f43b3','緣識  其一八','宋太宗','宋','宋诗','song-poetry','','[]','庶事情多感，光陰自古長。',48,'全唐诗/poet.song.1000.json','["庶事情多感，光陰自古長。", "貪癡何意遣，愚輩爲誰忙。", "紅葉隨時變，白頭最易傷。", "世途能及物，善德遠馨香。"]'),
('dba8de5f-8a2c-4e42-a9ff-5243f3d009f6','緣識  其一九','宋太宗','宋','宋诗','song-poetry','','[]','清虛閑靜得，奉道見真諦。',48,'全唐诗/poet.song.1000.json','["清虛閑靜得，奉道見真諦。", "契合皆堪用，因緣事好依。", "精誠求諦信，須有是兼非。", "達豁幽深遠，奧妙入玄機。"]'),
('e3755ce9-aa3f-4091-9518-acc7d3790715','緣識  其二○','宋太宗','宋','宋诗','song-poetry','','[]','終日窮經史，思惟事轉深。',48,'全唐诗/poet.song.1000.json','["終日窮經史，思惟事轉深。", "公忠懷士意，是理好相尋。", "總慧玄高鑒，回邪枉用心。", "從容閑歲月，學古便知今。"]'),
('9df6ef51-6b56-40ba-83d9-fffe208f4d56','緣識  其二一','宋太宗','宋','宋诗','song-poetry','','[]','真境堪依仗，周遷四敘移。',48,'全唐诗/poet.song.1000.json','["真境堪依仗，周遷四敘移。", "人忙閑聖跡，心達罷狐疑。", "俊造皆流品，逢能即是師。", "二從寒暑變，龍浴鳳皇池。"]'),
('d03c8e71-f200-45e4-9cb9-b3c6cfedc0c9','緣識  其二二','宋太宗','宋','宋诗','song-poetry','','[]','一逢又一別，來往幾時休。',48,'全唐诗/poet.song.1000.json','["一逢又一別，來往幾時休。", "處世皆名利，貪生去不留。", "善緣看似夢，惡事勿臨頭。", "如病心常怕，生前樂自由。"]'),
('a4d1efe5-81eb-42ba-a582-00db76b5874a','緣識  其二三','宋太宗','宋','宋诗','song-poetry','','[]','頂戴尊天地，聰明識見高。',48,'全唐诗/poet.song.1000.json','["頂戴尊天地，聰明識見高。", "無爲通理性，猛利豈虛勞。", "出沒終難認，因緣不可逃。", "中原多聖境，四海湧滔滔。"]'),
('33f3ca7b-9db1-45b4-b1bf-b89bc0caa96d','緣識  其二四','宋太宗','宋','宋诗','song-poetry','','[]','避罪勝修福，其爲理一般。',48,'全唐诗/poet.song.1000.json','["避罪勝修福，其爲理一般。", "資財豐利益，公道不欺瞞。", "濁世貪榮祿，明時善政官。", "遏强能撫弱，容此勢情觀。"]'),
('921ca3de-0ea7-4a9c-b910-56b7ff0cf31a','緣識  其二五','宋太宗','宋','宋诗','song-poetry','','[]','如水澹交疏，尋思道更殊。',48,'全唐诗/poet.song.1000.json','["如水澹交疏，尋思道更殊。", "乖張顛覆易，知己便相於。", "路坦如平掌，風傳語不書。", "煙霄明月靜，負志話清虛。"]'),
('af528b93-4c52-4e8a-9c5e-30c5366e7351','緣識  其二六','宋太宗','宋','宋诗','song-poetry','','[]','天上與人間，賢愚不蹔閑。',48,'全唐诗/poet.song.1000.json','["天上與人間，賢愚不蹔閑。", "精修歸至理，道大隠玄關。", "聖境皆奇絕，凡情豈易攀。", "羣仙寬坦蕩，却老盡童顔。"]'),
('f60c17d9-5f25-4cdb-acef-ce3da014b032','緣識  其二七','宋太宗','宋','宋诗','song-poetry','','[]','世途含萬象，稽古便知今。',48,'全唐诗/poet.song.1000.json','["世途含萬象，稽古便知今。", "大樹垂清影，如花耀碧岑。", "虛勞空自白，德行勝黄金。", "有過而能改，無爲積善深。"]'),
('dbbbc5be-5383-468b-b722-334f0bb9a685','緣識  其二八','宋太宗','宋','宋诗','song-poetry','','[]','法演雙林下，凡情世眼觀。',48,'全唐诗/poet.song.1000.json','["法演雙林下，凡情世眼觀。", "澹煙光雨際，孤月浄雲端。", "意思皆時暫，縱橫大教寬。", "含情能息慮，物外不相干。"]'),
('a3f7659a-0982-4d7e-b9cb-55f5c3b9b421','緣識  其二九','宋太宗','宋','宋诗','song-poetry','','[]','表裏分明說，深窮妙更玄。',48,'全唐诗/poet.song.1000.json','["表裏分明說，深窮妙更玄。", "愚迷行不到，聖事法中傳。", "欲界情無定，真空本自然。", "今生隨曩劫，清浄照三天。"]'),
('82b0a4c5-5915-4429-935d-814c5c3b1c7d','緣識  其三○','宋太宗','宋','宋诗','song-poetry','','[]','愛老及憐貧，逢迎善者親。',48,'全唐诗/poet.song.1000.json','["愛老及憐貧，逢迎善者親。", "道高明似日，民有幾般人。", "盛暑觀蚊蚋，窊魚探海津。", "閑忙皆自得，冬去後知春。"]'),
('19593ec7-2f3a-459a-9798-e823caa2976d','緣識  其三一','宋太宗','宋','宋诗','song-poetry','','[]','多言心不善，出口莫能追。',48,'全唐诗/poet.song.1000.json','["多言心不善，出口莫能追。", "如夢歡娛樂，歸家說盛衰。", "擬將何所用，理亂別公私。", "方寸巧旋設，小人亦可悲。"]'),
('9b66690f-dd71-4e2f-9940-c7206145c03e','緣識  其三二','宋太宗','宋','宋诗','song-poetry','','[]','雅澹玄中得，常人故不知。',48,'全唐诗/poet.song.1000.json','["雅澹玄中得，常人故不知。", "幽深無遠近，道外細推之。", "碧落神仙境，煙霞日月隨。", "參詳寰宇內，邪正豈相離。"]'),
('b0d388c8-02e3-4349-88ee-adea663123d0','緣識  其三三','宋太宗','宋','宋诗','song-poetry','','[]','世間何所益，樂善有馨香。',48,'全唐诗/poet.song.1000.json','["世間何所益，樂善有馨香。", "貴賤雖差等，非違定不祥。", "春臺宜勝地，花木收嚴霜。", "求取立身行，恒持但久長。"]'),
('faec79e0-99e3-43f2-8fb4-2d1ef9ecdf1e','緣識  其三四','宋太宗','宋','宋诗','song-poetry','','[]','逍遥能自在，大道亦何殊。',48,'全唐诗/poet.song.1000.json','["逍遥能自在，大道亦何殊。", "澹薄隨情遣，優遊靜惡除。", "春生凡作則，秋謝徧悲疏。", "利益玄穹鑒，公平信史書。"]'),
('bba95806-c95c-41a7-b9f1-fdeebfe97343','緣識  其三五','宋太宗','宋','宋诗','song-poetry','','[]','紫陌紅塵裏，貪名利好爭。',48,'全唐诗/poet.song.1000.json','["紫陌紅塵裏，貪名利好爭。", "世情皆擾攘，大道甚縱橫。", "弦直終無曲，心邪自不平。", "若能如遂意，復學法先生。"]'),
('737fb4c5-4879-4d3d-b53e-6840ca0ed0ea','緣識  其三六','宋太宗','宋','宋诗','song-poetry','','[]','民間天上事，通理一言之。',48,'全唐诗/poet.song.1000.json','["民間天上事，通理一言之。", "仙積千年壽，人終百歲期。", "禮容分次第，汎愛別尊卑。", "福業有輕重，那堪亂作爲。"]'),
('8fe2ee22-36d0-4636-aedd-f80203901500','緣識  其三七','宋太宗','宋','宋诗','song-poetry','','[]','世上多虛飾，方知一切心。',48,'全唐诗/poet.song.1000.json','["世上多虛飾，方知一切心。", "不羣終是異，僻學古同今。", "逸士寬懷釋，爲官理道深。", "移時非獨見，令我思沈吟。"]'),
('a378b591-2c8f-488d-86fa-c3daacec1ca9','緣識  其三八','宋太宗','宋','宋诗','song-poetry','','[]','真一生天地，因依認宿緣。',48,'全唐诗/poet.song.1000.json','["真一生天地，因依認宿緣。", "智高通理性，凡下少周旋。", "語默何奇絕，幽深隠聖賢。", "誰人解我意，大道寸心玄。"]'),
('265dd1ad-181c-41af-b29c-6823fdd92a29','緣識  其三九','宋太宗','宋','宋诗','song-poetry','','[]','石室巢新燕，人心在眼前。',48,'全唐诗/poet.song.1000.json','["石室巢新燕，人心在眼前。", "飛雲高去影，敗葉擁流泉。", "取捨憑認定，升沈勿自專。", "守貧知大道，盛事好攀緣。"]'),
('76fd4730-b0b1-4943-9056-8e898fc7c3a2','緣識  其四○','宋太宗','宋','宋诗','song-poetry','','[]','豁意何清浄，愚人不信迷。',48,'全唐诗/poet.song.1000.json','["豁意何清浄，愚人不信迷。", "石巖孤野鶴，仙路躡雲梯。", "棟木生深谷，寒鴉入夜啼。", "怡顔能待客，沽酒旋烹鷄。"]'),
('85526ff8-be91-4cde-b580-1c9a07f39691','緣識  其四一','宋太宗','宋','宋诗','song-poetry','','[]','利鈍猶根性，無緣枉用心。',48,'全唐诗/poet.song.1000.json','["利鈍猶根性，無緣枉用心。", "邪求皆是相，正定理玄深。", "巧拙高含識，輕浮力不任。", "大乘通語默，稽古便知今。"]'),
('4b945745-fd83-4e1a-9fa7-885f9f9f7872','緣識  其四二','宋太宗','宋','宋诗','song-poetry','','[]','智使千般用，思量也大愚。',48,'全唐诗/poet.song.1000.json','["智使千般用，思量也大愚。", "黄昏直至曉，皎日瑩康衢。", "瑞典通三界，華胥樂四隅。", "諭開方便治，平坦絕崎嶇。"]'),
('5acbd918-3e8d-476c-aa71-ce35cdf352f2','緣識  其四三','宋太宗','宋','宋诗','song-poetry','','[]','皆救眼前急，錐刀藴利名。',48,'全唐诗/poet.song.1000.json','["皆救眼前急，錐刀藴利名。", "愚心違善道，慧眼自分明。", "大海波浪沒，深山棟木成。", "旁求存古意，後學法先生。"]'),
('f5e073b7-716e-4aed-b3b0-771bad59506a','緣識  其四四','宋太宗','宋','宋诗','song-poetry','','[]','得道超凡聖，逍遥本是緣。',48,'全唐诗/poet.song.1000.json','["得道超凡聖，逍遥本是緣。", "羣迷難解會，我且不虛傳。", "但信恒無斷，精窮用意專。", "審聽明譬喻，勿被俗情牽。"]'),
('0631352d-c295-4fca-ba18-06c00140949d','緣識  其四五','宋太宗','宋','宋诗','song-poetry','','[]','古來高逸士，數目幾多人。',48,'全唐诗/poet.song.1000.json','["古來高逸士，數目幾多人。", "積德千花秀，溫良七寶珍。", "緣因終可作，好事福齊臻。", "宇內光陰速，仙天夜月春。"]'),
('41ca99d1-11c7-4005-88d5-363249f27e55','緣識  其四六','宋太宗','宋','宋诗','song-poetry','','[]','君子懷幽趣，謙恭禮樂才。',48,'全唐诗/poet.song.1000.json','["君子懷幽趣，謙恭禮樂才。", "經心皆識見，書史盡通該。", "有德馨還遠，清虛道亦開。", "先生宜法則，宿習自將來。"]'),
('d325e84a-54c5-4668-bbf0-754549288353','緣識  其四七','宋太宗','宋','宋诗','song-poetry','','[]','遁跡深巖谷，身閑未是閑。',48,'全唐诗/poet.song.1000.json','["遁跡深巖谷，身閑未是閑。", "研窮堪語默，寂靜杳冥間。", "祕密逢邪見，難開大道關。", "金丹無效用，弗可返童顔。"]'),
('344e7f09-c0f0-4ea4-a7c1-e03bc24d1252','緣識  其四八','宋太宗','宋','宋诗','song-poetry','','[]','人本心田靜，機關買是非。',48,'全唐诗/poet.song.1000.json','["人本心田靜，機關買是非。", "聰明存節操，曲直自相依。", "思寂知玄奧，區分有順違。", "精通含識性，理義愷然希。"]'),
('20a145bb-9f56-4391-9dd1-4e5690086dab','緣識  其四九','宋太宗','宋','宋诗','song-poetry','','[]','行止由修鍊，輝光朗自然。',48,'全唐诗/poet.song.1000.json','["行止由修鍊，輝光朗自然。", "深山藏虎豹，大海隠龍泉。", "鶴唳沖霄漢，龜生得壽年。", "怡情含道識，浩渺九重天。"]'),
('7f385859-0f48-4a80-ac38-53e155464023','緣識  其五○','宋太宗','宋','宋诗','song-poetry','','[]','誰人信我說，我說亦非常。',48,'全唐诗/poet.song.1000.json','["誰人信我說，我說亦非常。", "苦行分明樂，緣深解即忙。", "乖持如似夢，慕道行清凉。", "影響隨聲應，玄門可度量。"]'),
('3bcecc16-3d25-49ad-a9f3-921677d6a590','緣識  其一','宋太宗','宋','宋诗','song-poetry','','[]','高山石室半空嵌，選取靈芝草盡芟。',64,'全唐诗/poet.song.1000.json','["高山石室半空嵌，選取靈芝草盡芟。", "法意要修心一等，道情焉用口三緘。", "丹砂保重開清境，白髮相宜倚翠巖。", "曩劫緣中因種在，布衣鶴袖鳳來銜。"]'),
('323c4083-da45-4087-ae7b-a22a26d94cfc','緣識  其二','宋太宗','宋','宋诗','song-poetry','','[]','歸依妙法要精專，極目煙霄路不偏。',64,'全唐诗/poet.song.1000.json','["歸依妙法要精專，極目煙霄路不偏。", "日月明通三界眼，雲梯上有十洲仙。", "慈悲願力彌何遠，煩惱能除道最堅。", "救苦觀音名利益，經文曾與世間傳。"]'),
('eca6f2db-77bb-49c7-9694-fb572b038f94','緣識  其三','宋太宗','宋','宋诗','song-poetry','','[]','修心慕道入玄機，方便門停次第依。',64,'全唐诗/poet.song.1000.json','["修心慕道入玄機，方便門停次第依。", "種性莫教拘執定，因緣去住不相違。", "離他少欲陰功積，淡薄深來絕是非。", "浮世利名常自遣，真空妄想一時歸。"]'),
('d2ac7d9d-17b2-4578-9d28-57e195f72e16','緣識  其四','宋太宗','宋','宋诗','song-poetry','','[]','耳根清靜本來修，萬法從心不外求。',64,'全唐诗/poet.song.1000.json','["耳根清靜本來修，萬法從心不外求。", "海岳動摇山色異，玄珠盡在眼中收。", "持齋道士尋紅藥，醉卧仙人未白頭。", "麋鹿同羣方可信，逢春但笑樂花秋。"]'),
('49f84fb1-2b2d-4c68-b376-c7f0aefe272b','緣識  其五','宋太宗','宋','宋诗','song-poetry','','[]','忘機悟既見真詮，慕道威儀立善緣。',64,'全唐诗/poet.song.1000.json','["忘機悟既見真詮，慕道威儀立善緣。", "語默但教方外用，玄微通達自彌堅。", "利名染著還如夢，性相歸來猛似泉。", "三業之中堪發問，勿令萬法不精專。"]'),
('1ceda8e2-9d09-4d03-9d16-8f6dfa89b7d0','緣識  其六','宋太宗','宋','宋诗','song-poetry','','[]','隨機發問絕親疏，法界明文本不殊。',64,'全唐诗/poet.song.1000.json','["隨機發問絕親疏，法界明文本不殊。", "厭苦羣生含萬像，歸依大覺達三無。", "蓮開湛寂真如境，屋裏空勞總是虛。", "緣起性中平等用，直須樂道善心居。"]'),
('a703d780-3af7-42b8-a5ae-3dc08d2361d6','緣識  其七','宋太宗','宋','宋诗','song-poetry','','[]','道高人世禮周旋，語默如癡似不言。',64,'全唐诗/poet.song.1000.json','["道高人世禮周旋，語默如癡似不言。", "洗滌要教心地靜，狐疑勿類水蓱翻。", "經書說盡修真理，歲月休防罷引援。", "雅合無爲深見識，陰陽去住捉寒暄。"]'),
('f84c0da4-7d44-4939-88a5-9c6896e43077','緣識  其八','宋太宗','宋','宋诗','song-poetry','','[]','神丹妙道故延年，豈是凡流識大仙。',64,'全唐诗/poet.song.1000.json','["神丹妙道故延年，豈是凡流識大仙。", "老子尚猶能諱事，軒皇不許亂相傳。", "誰知造化功夫力，罕見今生度宿緣。", "猛虎伏來龍駕馭，雲騰五色思悠然。"]'),
('18639577-87ed-4440-812a-3c4e2a5f2cf1','緣識  其九','宋太宗','宋','宋诗','song-poetry','','[]','大道逢來是宿緣，終期定可訪真仙。',64,'全唐诗/poet.song.1000.json','["大道逢來是宿緣，終期定可訪真仙。", "山中修鍊非州郡，城裏無荒隠市鄽。", "祕術豈教容易得，幽深還許遞相傳。", "超凡入聖渾閑事，問取人間十洞天。"]'),
('35ddbe17-1562-4d84-8dbd-9c7195a55dae','緣識  其一○','宋太宗','宋','宋诗','song-poetry','','[]','青松本不樹蕭條，學士因何智自勞。',64,'全唐诗/poet.song.1000.json','["青松本不樹蕭條，學士因何智自勞。", "金水朗然明皎潔，雪山堆積就中高。", "志心但覓三神藥，凡目難觀萬里毫。", "我獨閑吟誰解意，悠哉麗日壓靈鼇。"]'),
('8c5de90a-72d3-4b6a-b0c9-5277af733822','緣識  其一一','宋太宗','宋','宋诗','song-poetry','','[]','天地爲爐我自知，人無遠慮必生疑。',64,'全唐诗/poet.song.1000.json','["天地爲爐我自知，人無遠慮必生疑。", "功夫未至勞懸想，境外聲聞不改移。", "機巧豈逢容易得，是非終究欲何之。", "思量大海深淵理，光陰虛度影參差。"]'),
('a39bfb7b-a0d0-4e02-90ed-f2b7f1fae79f','緣識  其一二','宋太宗','宋','宋诗','song-poetry','','[]','崑崙山上聚神仙，羽駕爭行意不偏。',64,'全唐诗/poet.song.1000.json','["崑崙山上聚神仙，羽駕爭行意不偏。", "積雪遠看欹下界，巔峰高認湧流泉。", "真空的實難堪比，異景皆從造化遷。", "祕密豈教容易辨，玄中之外更深玄。"]'),
('b93646c1-ed99-48b9-a0ef-6ac8cf356c38','緣識  其一三','宋太宗','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','溟溟滄海浪濤深，霧蔽山戀不易尋。',64,'全唐诗/poet.song.1000.json','["溟溟滄海浪濤深，霧蔽山戀不易尋。", "紫蓋洞庭人駕鶴，虹霓城郭道爲林。", "幽玄相去何多少，巧拙無由智慧侵。", "盡是同緣相引接，從容語話八仙心。"]'),
('f7db97c4-40ec-4446-9904-42fd811f774e','緣識  其一四','宋太宗','宋','宋诗','song-poetry','','[]','彩雲輕舉壓天津，舞鶴迎鸞自在身。',64,'全唐诗/poet.song.1000.json','["彩雲輕舉壓天津，舞鶴迎鸞自在身。", "蟾影枝開三島樹，桃花風弄十洲春。", "相傳靈異無虛說，道理分明盡是真。", "但信此中深護慎，修行所願勿因循。"]'),
('fd86e7b2-80cc-424a-8ae6-4220a527a647','緣識  其一五','宋太宗','宋','宋诗','song-poetry','','[]','天非愛道許人修，學士愚迷不到頭。',64,'全唐诗/poet.song.1000.json','["天非愛道許人修，學士愚迷不到頭。", "內境擬將何所用，杳知深邃故難求。", "丹霞隠密堪依仗，雪月縱橫入品流。", "消息須然潜世慮，凡岐聖路有剛柔。"]'),
('e0387e95-91fd-48c3-8755-4bd662e395ed','緣識  其一六','宋太宗','宋','宋诗','song-poetry','','[]','逍遥裏外混諸天，澹蕩其中四敘間。',64,'全唐诗/poet.song.1000.json','["逍遥裏外混諸天，澹蕩其中四敘間。", "拂拭塵埃明印月，徧駈神鬼鏁驪山。", "裝添出沒何奇異，祕隠藏直未是閑。", "但好消詳清景內，勿生疑慮動機關。"]'),
('497714dc-1afe-4e62-9401-9994d042fc1f','緣識  其一七','宋太宗','宋','宋诗','song-poetry','','[]','龍虎剛柔隠聖方，一時和合運陰陽。',64,'全唐诗/poet.song.1000.json','["龍虎剛柔隠聖方，一時和合運陰陽。", "周知配類無疏失，物性從來理自長。", "鼎裏花開裝五彩，心明火候制三黄。", "更能通得華池妙，南北東西不可當。"]'),
('5924c0da-a4a3-4466-a4a7-050f0d6dc11b','緣識  其一八','宋太宗','宋','宋诗','song-poetry','','[]','水精宮殿月華明，白玉爲牆火不侵。',64,'全唐诗/poet.song.1000.json','["水精宮殿月華明，白玉爲牆火不侵。", "八境風高駢羽駕，九重天上絳霞深。", "物情晃朗無遮隔，非是凡間比類尋。", "汗漫真遊誰得到，桂花香潔影森森。"]'),
('305b4176-71f8-4d51-a8ea-91a295d1fdc5','緣識  其一九','宋太宗','宋','宋诗','song-poetry','','[]','還元到即見真歸，不是虛傳羽化飛。',64,'全唐诗/poet.song.1000.json','["還元到即見真歸，不是虛傳羽化飛。", "大道勿將閑設用，精修別得便忘機。", "安排穩入龍宮內，變易終藏虎鼎威。", "豁達乾坤神妙理，逍遥鉛汞共相依。"]'),
('8dcede26-76ab-4ad6-9a4e-92af7b373295','緣識  其二○','宋太宗','宋','宋诗','song-poetry','','[]','泥丸本是命根宮，消息臨時語話通。',64,'全唐诗/poet.song.1000.json','["泥丸本是命根宮，消息臨時語話通。", "大道比來行氣術，其餘效驗藉陰功。", "物情之理皆清浄，造化玄微事莫同。", "珍重此言深可意，腹中日運鼎花空。"]'),
('34d678a2-6a7d-415b-81ea-49884d429064','緣識  其二一','宋太宗','宋','宋诗','song-poetry','','[]','天生顔貌幾何般，鶴骨餐霞厭俗觀。',64,'全唐诗/poet.song.1000.json','["天生顔貌幾何般，鶴骨餐霞厭俗觀。", "赤水華池誰法則，白銀爲闕又堪看。", "來傳音旨俱然混，位有尊卑勿異端。", "逆順之中關理性，心田靜外豈相干。"]'),
('48334b20-4019-4c75-92f0-af4572e148a7','緣識  其二二','宋太宗','宋','宋诗','song-poetry','','[]','逍遥我命在玄穹，鶴宿霞栖景致中。',64,'全唐诗/poet.song.1000.json','["逍遥我命在玄穹，鶴宿霞栖景致中。", "自得安寧兼養道，更將利益屏羣雄。", "淵深引古知今用，劈斫區分盡可通。", "和暢五音從豁達，乾坤之內靄溟濛。"]'),
('285fad9d-5649-4962-b112-b2e01e1475d3','緣識  其二三','宋太宗','宋','宋诗','song-poetry','','[]','巔峰一望水深潭，誰解緣情語話堪。',64,'全唐诗/poet.song.1000.json','["巔峰一望水深潭，誰解緣情語話堪。", "暗室自開明日月，道心奇異老山菴。", "研窮妙理真消息，誡忌先賢讓不貪。", "稽古尚爲今法則，愚蒙太甚苦惔惔。"]'),
('1dbb2d2e-3fae-4109-aff9-b90e645580d5','緣識  其二四','宋太宗','宋','宋诗','song-poetry','','[]','非人口似瀉汾河，此輩塵中有甚多。',64,'全唐诗/poet.song.1000.json','["非人口似瀉汾河，此輩塵中有甚多。", "心恨貌恭無定止，舌誇端正亂乖訛。", "爲官善政身榮祿，利劍休教石上磨。", "立待滿盈船陷水，惡風從被海神拖。"]'),
('79f9a5e2-4bdf-4850-9148-12f70ffc9d15','緣識  其二五','宋太宗','宋','宋诗','song-poetry','','[]','精詳語議四門開，舒慘陽和意外裁。',64,'全唐诗/poet.song.1000.json','["精詳語議四門開，舒慘陽和意外裁。", "遠見風塵思往事，無窮日月去還來。", "樂耶指趣歸三體，周旋道理遍九垓。", "賢聖人天常法則，卿雲嶺上白皚皚。"]'),
('bc27f5dc-f774-45f9-b135-05ecf31134f7','緣識  其二六','宋太宗','宋','宋诗','song-poetry','','[]','貪染猶來理不通，虛勞歲月面西東。',64,'全唐诗/poet.song.1000.json','["貪染猶來理不通，虛勞歲月面西東。", "從前自是凡心別，利益須歸上帝功。", "洞府名高同景致，塵泥蹤跡莫知空。", "雲非但向鉛中作，變化飛騰大道雄。"]'),
('23b40209-f3a0-4bf4-9a16-b084981a48ad','緣識  其二七','宋太宗','宋','宋诗','song-poetry','','[]','達道真人見者稀，豈教容易等閑知。',64,'全唐诗/poet.song.1000.json','["達道真人見者稀，豈教容易等閑知。", "陰陽造化無非實，天地元精動合宜。", "功行三千須及物，還丹九轉上昇時。", "忙中歲月忙中遣，我本愚來性不移。"]'),
('7f81f456-b9c6-44bc-b259-1d985df679b2','緣識  其二八','宋太宗','宋','宋诗','song-poetry','','[]','栖心隠逸故非常，大約恒持要久長。',64,'全唐诗/poet.song.1000.json','["栖心隠逸故非常，大約恒持要久長。", "清浄好爲皆是益，周旋理度審安詳。", "法乾馭物須平穩，順日成功自酌量。", "倏忽之間堪匹配，臨時巧拙見圓方。"]'),
('9fb15b8f-4db2-4af6-a240-87f648ed294f','緣識  其二九','宋太宗','宋','宋诗','song-poetry','','[]','香湯沐浴更齋清，運動形軀四體輕。',64,'全唐诗/poet.song.1000.json','["香湯沐浴更齋清，運動形軀四體輕。", "魔鬼自然生怕怖，神魂必定轉安寧。", "從無入有皆真實，去住何難妙最精。", "五行聚散歸一體，靈源不用苦煎烹。"]'),
('0ef2a9aa-445e-4904-b1f8-5596b557bc2a','緣識  其三○','宋太宗','宋','宋诗','song-poetry','','[]','一身獨善欲何之，爭及衣冠解撫綏。',64,'全唐诗/poet.song.1000.json','["一身獨善欲何之，爭及衣冠解撫綏。", "浮世淺情無限量，愚蒙自是不相規。", "直須憑仗分明說，詰取靈源問得知。", "要覓洞中閑日月，除將濟事謾非爲。"]'),
('050fda22-c340-4d56-8a70-098ebd50a851','緣識  其三一','宋太宗','宋','宋诗','song-poetry','','[]','尋思道味詠吟哦，去住先賢有幾何。',64,'全唐诗/poet.song.1000.json','["尋思道味詠吟哦，去住先賢有幾何。", "性識無凝關要妙，浮沈依約不言多。", "但將子細分明說，猶恐閑非却被魔。", "救世比心來所願，逍遥盡入扣玄歌。"]'),
('a811e18e-e280-43e8-9292-320a4a5bc005','緣識  其三二','宋太宗','宋','宋诗','song-poetry','','[]','無爲道大入幽玄，幾許風光慕昔賢。',64,'全唐诗/poet.song.1000.json','["無爲道大入幽玄，幾許風光慕昔賢。", "對境盡同閑見識，忙中皆是急相煎。", "配匹直須寬雅淡，會有逢時不偶然。", "修鍊但教堅志氣，參詳穩審更周旋。"]'),
('3091c53a-6a1c-4a37-8aca-116542720c49','緣識  其三三','宋太宗','宋','宋诗','song-poetry','','[]','人心多是少相投，非識塵中上品流。',64,'全唐诗/poet.song.1000.json','["人心多是少相投，非識塵中上品流。", "不見真宗歸物理，難知妙道後先休。", "生前內鼎宜烹鍊，殊勝華池好漸修。", "但見完全憑土德，能調火候藥皆秋。"]'),
('9615b340-11d6-4aad-a977-39a7e3a933e3','緣識  其三四','宋太宗','宋','宋诗','song-poetry','','[]','玄之玄又見真空，巧拙臨時要妙中。',64,'全唐诗/poet.song.1000.json','["玄之玄又見真空，巧拙臨時要妙中。", "大智伏藏知遠近，纖微盡達了然通。", "周旋物性誰區別，坦蕩由來是且同。", "境致三才隨有位，神光照室瑩西東。"]'),
('06cfd12c-1210-4214-957d-97cccf75a0fc','緣識  其三五','宋太宗','宋','宋诗','song-poetry','','[]','千般萬類不相逢，天地尊卑豈易窮。',64,'全唐诗/poet.song.1000.json','["千般萬類不相逢，天地尊卑豈易窮。", "海岳高深隨日轉，神仙聚樂隠塵中。", "鮮求名利知貪少，多事閑忙總是空。", "幾箇心賢平坦蕩，十洲三島自從容。"]'),
('ccd2da50-8f29-4124-b212-443c8956f254','緣識  其三六','宋太宗','宋','宋诗','song-poetry','','[]','九重天上帝仙居，愚昧求真道理疏。',64,'全唐诗/poet.song.1000.json','["九重天上帝仙居，愚昧求真道理疏。", "混沌初分長日月，精魂聚散記丹書。", "離男坎女皆相類，壬子丙丁異境殊。", "歷劫因緣隨世在，陰功及物最玄珠。"]'),
('593a8626-7874-4211-977a-ab8b3950df7e','緣識  其三七','宋太宗','宋','宋诗','song-poetry','','[]','還知受氣稟天然，百法方爲事理全。',64,'全唐诗/poet.song.1000.json','["還知受氣稟天然，百法方爲事理全。", "假合都來歸至道，修持遠大更通玄。", "二儀交感成祥瑞，八卦剛柔被俗牽。", "何謂此中生恍惚，直須款曲細精研。"]'),
('493908db-69c3-4f77-bdc4-cd5cb71f1f3a','緣識  其三八','宋太宗','宋','宋诗','song-poetry','','[]','玄門至道故無涯，自是人心所見邪。',64,'全唐诗/poet.song.1000.json','["玄門至道故無涯，自是人心所見邪。", "智識未能通大藥，豈將容易擬榮家。", "千年聖境何虛謬，百劫曾修不用遮。", "龍虎欲成堪鍊鼎，勿爲利路亂交加。"]'),
('9ea2dfb5-0c07-4c48-9dca-3b0f84390652','緣識  其三九','宋太宗','宋','宋诗','song-poetry','','[]','因緣業障遇真稀，黄帝乘龍豈是非。',64,'全唐诗/poet.song.1000.json','["因緣業障遇真稀，黄帝乘龍豈是非。", "達識尚凝常恍惚，愚蒙學解故相違。", "華池祕密人天授，神室光揚日月輝。", "智者無言皆口默，敢將容易論玄機。"]'),
('e4545f5d-e421-4cba-aac3-bf04ff49ea9c','緣識  其四○','宋太宗','宋','宋诗','song-poetry','','[]','鳳皇燕雀不同羣，非類宜然信有聞。',64,'全唐诗/poet.song.1000.json','["鳳皇燕雀不同羣，非類宜然信有聞。", "好景銷磨還爾夢，方在虛誕似浮雲。", "閑吟比喻明如日，雅道留情舊典墳。", "堪與言論誰是識，舜琴惠愛皷南薰。"]'),
('111b32d7-d4ef-4c66-9212-efd4ac3ffb7c','緣識  其四一','宋太宗','宋','宋诗','song-poetry','','[]','何爲禪定性心同，解說真如物外空。',64,'全唐诗/poet.song.1000.json','["何爲禪定性心同，解說真如物外空。", "幾許修行緣上得，惑多妄想障於聰。", "名彰道理千世永，善惡都歸萬法中。", "應現機關俱寂默，始知明鑒照昏蒙。"]'),
('4dacdc79-c2dc-4f31-9df3-077ccec56081','緣識  其四二','宋太宗','宋','宋诗','song-poetry','','[]','無縈無慮鬢如黳，手執仙經杖一藜。',64,'全唐诗/poet.song.1000.json','["無縈無慮鬢如黳，手執仙經杖一藜。", "猛利銷磨閑歲月，玄中妙道入雲霓。", "紅塵世界何拘束，白日山川高又低。", "去住自然皆寂默，逍遥不假上仙梯。"]'),
('1050ae1d-a245-4b13-bed9-1b61ab7696b9','緣識  其四三','宋太宗','宋','宋诗','song-poetry','','[]','高山樹葉翠森森，寂靜因中道最深。',64,'全唐诗/poet.song.1000.json','["高山樹葉翠森森，寂靜因中道最深。", "利得崑崙皆璞玉，不須麗水有真金。", "澆漓漸變同堯日，薄俗將重理舜琴。", "禍福年長隨世改，玄門大戒喻飛沈。"]'),
('1e32bfae-eff6-4a06-a09c-07b5cb4b4bcf','緣識  其四四','宋太宗','宋','宋诗','song-poetry','','[]','玄珠道在口中銜，未信前人明似鑒。',64,'全唐诗/poet.song.1000.json','["玄珠道在口中銜，未信前人明似鑒。", "試問心田佯兀兀，可憐肌骨瘦巖巖。", "自言世界歸依重，志誦經文不用攙。", "鍊得氣來身且健，日斜常望鶴栖杉。"]'),
('a101a72f-ba01-4142-b20f-78b4a46cc671','緣識  其四五','宋太宗','宋','宋诗','song-poetry','','[]','四敘相遷亦可觀，斜扉半掩半欹關。',64,'全唐诗/poet.song.1000.json','["四敘相遷亦可觀，斜扉半掩半欹關。", "詩吟海岳皆空盡，扇覺秋凉漸放閑。", "樹影臨窗迷遠思，渴禽戀水復飛還。", "旋教摘果瞑心話，葉木蒼蒼天地間。"]'),
('784416a7-2b12-4929-a7b8-b4ccd01e1529','緣識  其四六','宋太宗','宋','宋诗','song-poetry','','[]','秋鏁煙嵐日未蟻，道情欲話老僧期。',64,'全唐诗/poet.song.1000.json','["秋鏁煙嵐日未蟻，道情欲話老僧期。", "旋烹茶竈心先喜，摇撼松風睡思遲。", "鶴唳九霄堪入畫，雲平三界化無私。", "真宗象教非虛說，對境成空是我師。"]'),
('40d446b0-f0bd-4a84-95ae-c494eba419cc','緣識  其四七','宋太宗','宋','宋诗','song-poetry','','[]','夜醮星壇海嶽飛，龍車摇曳羽雲衣。',64,'全唐诗/poet.song.1000.json','["夜醮星壇海嶽飛，龍車摇曳羽雲衣。", "紅霞影裏輕煙色，玉燭風清皓月輝。", "三島花明鋪錦繡，千年鶴送下金扉。", "仙家莫道無多事，十二瓊樓恨不歸。"]'),
('489e85d8-deb9-4384-8696-18af00ec282f','緣識  其四八','宋太宗','宋','宋诗','song-poetry','','[]','往事悲歡笑一場，乾坤有甚可思量。',64,'全唐诗/poet.song.1000.json','["往事悲歡笑一場，乾坤有甚可思量。", "空知造化情多矣，却是愚蒙不久長。", "世上周通添眷戀，人間善惡自舒張。", "熙熙盡入無爲內，明月清風道路忙。"]'),
('f587e1a2-8475-4a0f-a694-cbcfd726542b','緣識  其四九','宋太宗','宋','宋诗','song-poetry','','[]','尋思往事便堪疏，空有閑雲萬里餘。',64,'全唐诗/poet.song.1000.json','["尋思往事便堪疏，空有閑雲萬里餘。", "滿目都來情郁郁，勞心誰把謾驅驅。", "星辰日月高天際，雲散煙花徧海隅。", "道德流行寬世界，時捻筆硯亦看書。"]'),
('96533be7-f957-4c77-8ca5-dd21e62656fe','緣識  其五○','宋太宗','宋','宋诗','song-poetry','','[]','是非人我利名心，情僞言同海似深。',64,'全唐诗/poet.song.1000.json','["是非人我利名心，情僞言同海似深。", "浩渺無涯成理性，無爲志大可勝任。", "千年歲月周遊在，萬卷詩書不易尋。", "世界之中寬更遠，從分混沌至如今。"]'),
('323a2abd-0a18-41cf-b9dc-7ecfdacd8ce8','緣識  其一','宋太宗','宋','宋诗','song-poetry','','[]','我一囊盛寬世界，從頭點取人數在。',156,'全唐诗/poet.song.1000.json','["我一囊盛寬世界，從頭點取人數在。", "萬里山河寬更寬，一切衆生智者解。", "因緣殊勝是因緣，方便法門天最大。", "天最大，無比擬，經文祕在無生理。", "知之修鍊是聖人，光陰急速流如水。", "孤雲野鶴笑龍吟，扣寂希夷求妙旨。", "但知慙愧常親善，更能通達解區遣。", "辜負琴書得自由，勿令縈恨金刀剪。", "離煩惱，大仙上品十洲好。", "利他貴重無親疏，便是菩提心至老。"]'),
('5604d181-7da3-4500-ad5e-22a87e675b6a','緣識  其二','宋太宗','宋','宋诗','song-poetry','','[]','自家未達莫來看，解者衆生真是漢。',160,'全唐诗/poet.song.1000.json','["自家未達莫來看，解者衆生真是漢。", "世塗煩惱一齊休，修取菩提心不亂。", "天覺因明凡聖同，苦空圓滿光不散。", "含識緣中曉了難，愛河須渡達彼岸。", "我見人見衆生見，菩薩行持終不憚。", "離貪嗔，絕情欲，定相安然無反覆。", "從頭法歸鎮長開，鬰鬰黄花生翠竹。", "天高地廣遍周遊，十方妙色能照燭。", "七寶山高三界中，拔去浮雲沈水淥。", "離他一念是因緣，珍重賢聖皆知足。"]'),
('ceb7ffdb-e014-48ea-b9da-d3d7eb883d37','緣識  其三','宋太宗','宋','宋诗','song-poetry','','[]','天心即是道，佛心即是佛。',72,'全唐诗/poet.song.1000.json','["天心即是道，佛心即是佛。", "人生有善緣，修行豈廢力。", "悟來瞬息間，曖昧藏五賊。", "非干智慧中，虛妄不可得，小乘尚執迷，大乘堪法則。", "經教有明文，守白便知黑。"]'),
('cbbb71ce-cbea-4a49-a882-6c426a8b5c32','緣識  其四','宋太宗','宋','宋诗','song-poetry','','[]','春長秋風敗黄葉，白髮老人慵把鑷。',64,'全唐诗/poet.song.1000.json','["春長秋風敗黄葉，白髮老人慵把鑷。", "光景如箭亦如飛，我不聰明賢者說。", "知近知深知更遠，善緣惡境勿交涉。", "勿交涉，語重疊，古往今來閑日月。"]'),
('60b1dde5-73ca-47f4-b8fd-ceee12842c50','緣識  其五','宋太宗','宋','宋诗','song-poetry','','[]','還淳返朴非用智，黄老之術何簡易。',74,'全唐诗/poet.song.1000.json','["還淳返朴非用智，黄老之術何簡易。", "不衒聰明時俗清，盡使人人懷忠義。", "密賤得之不下堂，單父得之公私利。", "無爲之道隨時化，無爲之道隨時理，若能可行，則清浄矣。"]'),
('e84ebb25-ce54-4986-810a-5cbcfe4c3b38','緣識  其六','宋太宗','宋','宋诗','song-poetry','','[]','予持齋，常清浄，心田澄寂無爭競。',65,'全唐诗/poet.song.1000.json','["予持齋，常清浄，心田澄寂無爭競。", "聞爾志念誦真經，明月窗中轉孤影。", "風自悠颺香滿室，因地修行不可得。", "善事是芝蘭，惡事是荆棘，實實實實。"]'),
('28d7f05f-a480-45d4-8635-cd520eca3053','緣識  其七','宋太宗','宋','宋诗','song-poetry','','[]','勤恤憂勞，夙夜匪怠。',90,'全唐诗/poet.song.1000.json','["勤恤憂勞，夙夜匪怠。", "政教猶豫，從誡中外。", "三皇致理，百姓爲心。", "不嚴而肅，自古從今。", "刑賞不忒，後代爲箴。", "求己之短，利害知深。", "就人所欲，良吏不酷，繩直於木，政無反覆。", "旰食宵衣，無是無非。"]'),
('3d2d97c2-776d-4546-9cdb-fbb8fbd22ec9','緣識  其八','宋太宗','宋','宋诗','song-poetry','','[]','孤雲野鶴鎮常閑，隨宜自在杳冥間。',64,'全唐诗/poet.song.1000.json','["孤雲野鶴鎮常閑，隨宜自在杳冥間。", "杉松高拔千萬尺，寒泉引望峭青山。", "大道煙霞看更遠，將臨海嶠叩玄關。", "知之修鍊凡超聖，歲月空深不易攀。"]'),
('f73c42a4-6e25-4ea8-adad-14ea5ea74f01','緣識  其九','宋太宗','宋','宋诗','song-poetry','','[]','茅菴養道靜深山，解笑光陰解駐顔。',64,'全唐诗/poet.song.1000.json','["茅菴養道靜深山，解笑光陰解駐顔。", "誰能苦志離人間，孤雲情僻豈容攀。", "日餐松柏知其味，不問王侯朱紫貴。", "修行但好倍精專，十洲洞府有神仙。"]'),
('2125e5ba-db23-49aa-bcb0-e4b49ab18504','緣識  其一○','宋太宗','宋','宋诗','song-poetry','','[]','無爲本從清靜出，知之修鍊皆寂默。',128,'全唐诗/poet.song.1000.json','["無爲本從清靜出，知之修鍊皆寂默。", "大道玄門幾百般，不拘東西及南北。", "觀其形貌欵共語，風雲可變龍與虎。", "靈源欲訪不曾閑，捉得之時爲伴侶。", "日有魂，月有魄，業累袪除離死厄。", "十二時中可逍遥，五行造化人豈測。", "也曾嗔，也曾笑，世間心爲求諸要。", "長生之法在目前，天門地戶無顛倒。"]'),
('361c73d3-76e4-4c1d-8a31-7a8a3e94e3ca','緣識  其一一','宋太宗','宋','宋诗','song-poetry','','[]','秋風主遠思，令我上高臺。',56,'全唐诗/poet.song.1000.json','["秋風主遠思，令我上高臺。", "花木將零落，雲雨舊山來。", "世間何事有情疏，南雁藏賓萬里餘。", "去有其聲爲誰去，來有其聲爲誰來。"]'),
('146af506-c49c-4cd3-bfc1-92f7431d18e7','緣識  其一二','宋太宗','宋','宋诗','song-poetry','','[]','尋常無事信天緣，饒得憨癡滿眼前。',32,'全唐诗/poet.song.1000.json','["尋常無事信天緣，饒得憨癡滿眼前。", "名利世間多用意，愚迷不肯學先賢。"]'),
('8d6c0cb0-29ce-4329-afcf-ba6b6cd8d150','緣識  其一三','宋太宗','宋','宋诗','song-poetry','','[]','玄珠玄珠存今古，總在眼前無一睹。',260,'全唐诗/poet.song.1000.json','["玄珠玄珠存今古，總在眼前無一睹。", "圓似明珠照十方，或來或去寒無雨。", "本是真，玄中聖，天仙地仙收不盡。", "虛無出向方寸間，方寸之間還遠近。", "此玄珠，何分別，超凡得道須自證。", "四時運轉如等閑，任從顛倒非常性。", "玄珠玄珠實非實，虛非空，五色相依橘似紅。", "境象軿羅安掌內，不在言外隠形中。", "扣玄關，深奇異，具足凡情兼四智。", "人或達識此玄珠，一念失則心如醉。", "可速求，可尋討，明取閑忙身內了。", "經年作相熟知之，三載漸即離懷抱。", "買亦無，顯奇祕，混在世間無滋味。", "龍宮海藏不拘收，離男坎女難匹配。", "神仙道，陰陽是，幾人順從幾人背。", "凡情不識智者會，坐卧行持窮三昧。"]'),
('514aed84-b867-4a04-ac0d-06a0faebc6cc','緣識  其一四','宋太宗','宋','宋诗','song-poetry','','[]','耳根唯願常清靜，更得四時風雨順。',32,'全唐诗/poet.song.1000.json','["耳根唯願常清靜，更得四時風雨順。", "開得眼來一切心，盡爲好事善相近。"]'),
('ff708fed-04d2-463b-b513-c2f0e3b50a4d','緣識  其一五','宋太宗','宋','宋诗','song-poetry','','[]','三天境象驗人間，不在江湖不在山。',32,'全唐诗/poet.song.1000.json','["三天境象驗人間，不在江湖不在山。", "大約頗同隨報應，耳根清靜道心閑。"]'),
('249c5c0a-8d7f-4c7c-89a9-08273640ec2b','緣識  其一六','宋太宗','宋','宋诗','song-poetry','','[]','善惡由人作，修心勿亂爲。',192,'全唐诗/poet.song.1000.json','["善惡由人作，修心勿亂爲。", "邪求無實事，如影定相隨。", "妄想終成僞，行貪未可知。", "天生分異等，道德立尊卑。", "日月須明照，聲文垂大教。", "非言患不及，長順歸仁考。", "志廣來遐邇，忠臣持節操。", "腥膻戎自伏，洞達總機要。", "遂性減予憂，玄門境象幽。", "躬躬勤政理，化被遍恩流。", "省己光陰速，一春度一秋。", "輸他閑取靜，每藉更溫柔。", "智者審詳意，聾聽如夢寐。", "玄穹平覆載，種種乾坤惠。", "煩惱深無岸，量寬苞天地。", "眼前一切類，孰非孰爲是。"]'),
('356d3144-b35b-4ec7-8f7d-c5aeff536f7d','緣識  其一七','宋太宗','宋','宋诗','song-poetry','','[]','每逢清夜坐更深，白日忙忙各是情。',32,'全唐诗/poet.song.1000.json','["每逢清夜坐更深，白日忙忙各是情。", "南北東西誰定準，無窮天地始知名。"]'),
('cd951cac-0e30-4e04-9c30-4fb39687a1e9','緣識  其一八','宋太宗','宋','宋诗','song-poetry','','[]','上元齋醮卷清風，暗使虔誠望聖功。',32,'全唐诗/poet.song.1000.json','["上元齋醮卷清風，暗使虔誠望聖功。", "星彩動容光碧落，步虛聲在半天中。"]'),
('05942939-61cc-4ddc-b9d7-587b58ec69fb','緣識  其一九','宋太宗','宋','宋诗','song-poetry','','[]','京都繁盛誰比矣，十二樓臺重重起。',96,'全唐诗/poet.song.1000.json','["京都繁盛誰比矣，十二樓臺重重起。", "九衢車騎日喧喧，廣陌歡呼歌帝里。", "我今御宇臨天下，物泰熙熙忻朝野。", "村夫擊壤荷豐年，侯門朱紫皆風雅。", "無爲一坦已成功，關防絕慮閑戰馬。", "唯願君臣千萬世，六合同心歸華夏。"]'),
('642f881b-7a6e-45a1-a513-ca761570eb39','緣識  其二○','宋太宗','宋','宋诗','song-poetry','','[]','逢春總有看花情，時節心迷不可輕。',32,'全唐诗/poet.song.1000.json','["逢春總有看花情，時節心迷不可輕。", "但秪追遊貪聚樂，幾人頂戴愧三清。"]'),
('88b4465b-5cda-473a-8320-01b9d2056a36','緣識  其二一','宋太宗','宋','宋诗','song-poetry','','[]','君子淡交如似水，小人交結甘如醴。',64,'全唐诗/poet.song.1000.json','["君子淡交如似水，小人交結甘如醴。", "微漥浪息派分流，倏忽之間生謗毀。", "但去驕矜添意氣，貞松全勝凡花卉。", "狂風秪是有塵埃，大海潮宗深無底。"]'),
('e3bc8f6e-8a2b-4c3d-8597-c18b2eda741b','緣識  其二二','宋太宗','宋','宋诗','song-poetry','','[]','偃亞松，筆跡高。',191,'全唐诗/poet.song.1000.json','["偃亞松，筆跡高。", "來更妙，甚奇特，三十年前曾收得。", "上下度量有短長，平頭一樣青煙色。", "半枯半嫩小枝斜，篩風陰石皆法則。", "左隈右倚四維絕，懸在書堂誰分別，喝起諸山未是奇，千年鶴坐方可說。", "根蟠龍，籠春雪，團團引出桂華月。", "暗聚風生欹枕觀，駈逐邪魔無情滅。", "若在靈山片時久，感動天人師子吼。", "掃教心地起自然，好看縱橫如意手。", "偃亞松，偃亞松，或真箇。", "生在深谷，爲棟梁之異木。", "任從霜雪摧殘，終歸衆人之瞻矚。"]'),
('b5e56e04-8fc9-41c1-84d2-50236af7ce09','緣識  其二三','宋太宗','宋','宋诗','song-poetry','','[]','看花終不似春雷，牽引詩情瞑目開。',32,'全唐诗/poet.song.1000.json','["看花終不似春雷，牽引詩情瞑目開。", "雨順風調爲上瑞，蒼生家足降天來。"]'),
('8d5b8c57-f822-4d2e-a434-cefc7513f141','緣識  其二四','宋太宗','宋','宋诗','song-poetry','','[]','中秋夜，圓轉魄，東昇慢上露先濕。',64,'全唐诗/poet.song.1000.json','["中秋夜，圓轉魄，東昇慢上露先濕。", "起清風，明似雪，薄衣階下寒泉滴。", "隨宜情，何豁達，五音罷去無蹤迹。", "星稀斗暗天寬窄，桂華望處誰不惜。"]'),
('aec000fc-1ee0-4f35-a514-f71f282f2f77','緣識  其二五','宋太宗','宋','宋诗','song-poetry','','[]','蔟蔟排弦聲流美，因風獨弄無宮徵。',128,'全唐诗/poet.song.1000.json','["蔟蔟排弦聲流美，因風獨弄無宮徵。", "閑庭引思道情中，五音不入行人耳。", "仰望雲霄聽未足，何期到了不成曲。", "秋蟬夜噪素琴鳴，邊城角罷春水淥。", "高懸韻響聲來去，常深興寐無相阻。", "不類樂中得此名，圓月明時何自苦。", "凄清激節繁空影，日夜如流後天永。", "無窮之外更無窮，依傍羣弦方始品。"]'),
('f71021d2-b912-42c3-9830-2b7d4d694a05','緣識  其二六','宋太宗','宋','宋诗','song-poetry','','[]','逍遥本意離塵埃，日見愚癡足可哀。',32,'全唐诗/poet.song.1000.json','["逍遥本意離塵埃，日見愚癡足可哀。", "唯願人心齊一等，花香常近慧風開。"]'),
('fbecfa7d-bc4c-4d6c-993f-dc286847a3cc','緣識  其二七','宋太宗','宋','宋诗','song-poetry','','[]','棲真大道於南北，清浄之間求愛力，堅持雅志窮諸識。',56,'全唐诗/poet.song.1000.json','["棲真大道於南北，清浄之間求愛力，堅持雅志窮諸識。", "尋常如觀在眼前，唯仰三光無蹔息。", "憂念蒼生不暇食，自挫周遮嘗反側。"]'),
('3d6215bd-1ad6-46b5-a877-b43e7a9cf079','緣識  其二八','宋太宗','宋','宋诗','song-poetry','','[]','阮咸初立意，偷得姮娥月。',120,'全唐诗/poet.song.1000.json','["阮咸初立意，偷得姮娥月。", "三柱應琴徽，五音更互發。", "堪聽諸調弄，勾鏁無休歇。", "閑暇優遊子，順風吟案揭。", "時聞宣九奏，鳳翅手輪抹。", "引思何奇妙，廣陵散白雪。", "稀中逢絕藝，解彈能指撥。", "放縱知狂逸，四弦憑審察。", "慢來長不斷，急則聲相軋。", "春鶑雖好語，難將比並說。"]'),
('41fe93ba-69a4-4107-9d2c-0523969e576e','緣識  其二九','宋太宗','宋','宋诗','song-poetry','','[]','月琴三柱四條水，圓魄移來混俗耳。',128,'全唐诗/poet.song.1000.json','["月琴三柱四條水，圓魄移來混俗耳。", "自古從今清且奇，五音一弄驚神鬼。", "勾挑指下何纖細，傍觀側聽心先醉。", "胡茄十八笑思歸，悲風切切摇朱翠。", "鳳遊雲裏情蕩颺，不無蕭灑真高尚。", "寒暄聚散得馨香，奚爲絲竹兼歌唱。", "慢鏁朱弦急如雨，疑似春鶑相共語。", "莫憚辭勞用意彈，堪對鸞吟與鳳舞。"]'),
('79debc5f-9734-447b-b8df-cbad0e020449','緣識  其三○','宋太宗','宋','宋诗','song-poetry','','[]','一言有善亦須聽，終日飽餐不易任。',32,'全唐诗/poet.song.1000.json','["一言有善亦須聽，終日飽餐不易任。", "他織他耕無憫念，世途誰是愛人心。"]'),
('0d5911a8-37e0-41fc-8bf2-374295f5f1e8','緣識  其三一','宋太宗','宋','宋诗','song-poetry','','[]','日月何忙忙，相逢有出沒。',60,'全唐诗/poet.song.1000.json','["日月何忙忙，相逢有出沒。", "催將壯志心，少年如頃剋。", "人生苦海中，否泰知通寒。", "四季倏忽來，寒暑變爲賊。", "偷人面上花，奪人頭上黑。"]'),
('0b5df613-bf7e-4182-808f-fd152948498d','緣識  其三二','宋太宗','宋','宋诗','song-poetry','','[]','結束分朋相間錯，立在殿庭還不弱。',192,'全唐诗/poet.song.1000.json','["結束分朋相間錯，立在殿庭還不弱。", "錦繡爲袍供奉儀，流星電轉爭揮霍。", "文裏鳥巾皆一樣，三春景色花蕩颺。", "承平此事比應難，盛世歡娛情好尚，添肖況，堪可愛，香塵墜裏無妨礙。", "月杖懷挾擊雲門，引聚風光何意態。", "令人駭目潜窺睹，雜劇教坊羅袂舉。", "鑾鈴珂珮白玉鞍，恣縱奔馳汗如雨。", "笑中語，審聽旨，速排絲竹調宮徵。", "高高樹影柳疏陰，頭籌先得稱心喜。", "畫鼓紅旗雙對鳳，笛發龍吟能送斷。", "年少來來善乘騎，因依所習且隨衆。"]'),
('a07679e8-a2f5-403e-aa0c-d761d6fe9ad5','緣識  其三三','宋太宗','宋','宋诗','song-poetry','','[]','駈駈席不蹔安時，勤苦終朝景易移。',32,'全唐诗/poet.song.1000.json','["駈駈席不蹔安時，勤苦終朝景易移。", "達得物情深道理，無爲堪作後人師。"]'),
('906d3557-f0b5-45da-8bef-cb2008860eef','緣識  其三四','宋太宗','宋','宋诗','song-poetry','','[]','六銖衣帔是神仙，劫劫曾修不偶然。',32,'全唐诗/poet.song.1000.json','["六銖衣帔是神仙，劫劫曾修不偶然。", "大道目前人豈會，九天常有萬千千。"]'),
('0660b2d3-0169-41b2-9c1f-01225d5d47c6','緣識  其三五','宋太宗','宋','宋诗','song-poetry','','[]','白髮長，眉似雪，宗禪和尚何分別。',160,'全唐诗/poet.song.1000.json','["白髮長，眉似雪，宗禪和尚何分別。", "百尺高山足浮雲，萬丈海中有明月。", "十地本因菩薩證，大乘俱是如來說。", "有空相，無空相，深淺是非皆爲妄。", "一切諸法歸何物，忽然覺悟波浪沒。", "安樂常在信心中，真空根本難緘默。", "貪嗔戒定如幻夢，祖師凝流歡者衆。", "方便門，羣生用，除他煩惱知識重。", "誘引迷途如風止，慧眼觀瞻恒沙水。", "三昧八萬四千智，清浄法身依道理。"]'),
('649ea1ce-96bd-4189-841d-1729eaa391f6','緣識  其三六','宋太宗','宋','宋诗','song-poetry','','[]','大道何異，俗情如花。',40,'全唐诗/poet.song.1000.json','["大道何異，俗情如花。", "生前境趣，車碾黄砂。", "無垢住相，勿用稱誇。", "非親我親，六合爲家。"]'),
('2392d846-26fb-4ebf-aa2d-3404353f7b87','緣識  其三七','宋太宗','宋','宋诗','song-poetry','','[]','忙即但忙，閑即便閑。',130,'全唐诗/poet.song.1000.json','["忙即但忙，閑即便閑。", "無爲之見，與道相關。", "言雖鄙俚，勿生謗毀。", "利他何疑，嗔乃興喜。", "善惡萬端，古今如此。", "非善稱君，非過稱己。", "道大幽玄，世使如然。", "君臨宇宙，輔弼須賢。", "求之不見，形表影連。", "論而非細，我慙知媿。", "救世心勞，方便之智。", "短又何難，長又何易。", "真實語言，勿將爲戲。"]'),
('d98fb347-0be3-49ca-a1ac-d55c2546cdef','緣識  其三八','宋太宗','宋','宋诗','song-poetry','','[]','終朝煩惱謾相牽，却是他非我自然。',32,'全唐诗/poet.song.1000.json','["終朝煩惱謾相牽，却是他非我自然。", "秪願蒼生添景福，康寧常得遇豐年。"]'),
('d818d780-3adc-4325-99b8-75be62d9e65b','緣識  其三九','宋太宗','宋','宋诗','song-poetry','','[]','從來非不求知己，言覺俗情似流水。',32,'全唐诗/poet.song.1000.json','["從來非不求知己，言覺俗情似流水。", "消息毫端總是空，奇哉道味深無比。"]'),
('265f1b46-e629-4bd2-8f05-75dd37d3fdae','緣識  其四○','宋太宗','宋','宋诗','song-poetry','','[]','若言筆法窮絕藝，書一字，至百字，八法從前亦非細。',379,'全唐诗/poet.song.1000.json','["若言筆法窮絕藝，書一字，至百字，八法從前亦非細。", "分間布白要審詳，濃淡均勻看可戲。", "一則一，二則二，消息蹤由無縱恣。", "紙爲陣，筆爲矟，將軍須是有謀略。", "墨要乾研清神思，點畫臨時要廓落。", "形勢奇狀似龍蛇，平頭大小宜斟酌。", "曲須曲，直須直，意氣方剛須雅飾。", "閑暇規矩有指歸，圓轉楷模堪法則。", "堪法則，有遲速，相鈎相連光熠目。", "古隸參雜故不拘，顛草縱橫似花蔟。", "偃仰莫把筆鋒挫，先須順䟐迴收左。", "經心健硬曉浮沈，鏗鏘啟發勿怠墮。", "研窮體象貌亦同，博學精微先賢播。", "化陰陽，勢出矣，藏頭護尾深有理。", "稟乎人性是常情，遞相映带可行止。", "遲澀飛動似玲瓏，慢引急牽如流水。", "上捺下挑猛如虎，蜂腰鶴膝不堪睹。", "壯士屈臂鳳皇飛，張弓發箭勝於弩。", "提撕祕思不可傳，常存形影勿孤露。", "勿孤露，誰別辨，義之平穩知深淺。", "自然觀察往還來，斗迴角立能駈遣。", "痾瘵纏身，溺水之禽。", "長似死蛇，短似蝦𢋙。", "古人最慎，愚蒙大忌，名爲不嘉。"]'),
('59044388-5db6-46d1-8ebc-d163d00fcfa2','緣識  其四一','宋太宗','宋','宋诗','song-poetry','','[]','二月寒食經新雨，開花綻柳人無語。',64,'全唐诗/poet.song.1000.json','["二月寒食經新雨，開花綻柳人無語。", "近水溪邊嫩枝條，攀折悠颺還似舞。", "車騎園林看不若，村笛歌聲更互作。", "光陰番次不因循，民安萬歲家家樂。"]'),
('a8f54ec4-4ef2-4f8f-9fec-b81cf3c49a06','緣識  其四二','宋太宗','宋','宋诗','song-poetry','','[]','性成孤僻愛清山，鶴唳雲霄意自閑。',32,'全唐诗/poet.song.1000.json','["性成孤僻愛清山，鶴唳雲霄意自閑。", "物外更將和氣約，精修便得扣玄關。"]'),
('684ff86f-5702-45d1-9f6f-957fbc48dd1e','緣識  其四三','宋太宗','宋','宋诗','song-poetry','','[]','河决洪波東南流迤邐，蒼生昏墊困其止。',174,'全唐诗/poet.song.1000.json','["河决洪波東南流迤邐，蒼生昏墊困其止。", "去年今歲豈遑安，勞我關心情不已。", "奔衡浩渺故無涯，十二州民皆憂水。", "諸般度議自裁之，乃出禁軍爲夫使。", "倍加慰諭願登先，悅隨容易能如此。", "大將聞命效駈馳，連夜侵晨順從理。", "未經月餘便成功，龍門一合士民喜。", "歡乎歡，忻斯睹，土木如山杵如雨。", "浪平變化盡爲空，力役忙忙無朝暮。", "錫賜錢與衣，遭災免稅租。", "皇天睠命八方同，惟德惟馨依是輔。"]'),
('2e71482b-e977-46bc-a2e8-ba5ffdbb14a6','緣識  其四四','宋太宗','宋','宋诗','song-poetry','','[]','神仙洞府好逍遥，不似人間歲月銷。',32,'全唐诗/poet.song.1000.json','["神仙洞府好逍遥，不似人間歲月銷。", "海岳高深誰可測，九重天上自相邀。"]'),
('ef0b8b46-b3b5-4761-8f08-60fa4cf818e2','緣識  其四五','宋太宗','宋','宋诗','song-poetry','','[]','我有真金色，常銀染不得。',48,'全唐诗/poet.song.1000.json','["我有真金色，常銀染不得。", "我有智慧空，從頭即是實。", "我有兜羅綿，豈受凡情墨。", "勸爾世間人，善道須平直。"]'),
('6e24e7a0-89fd-4380-b73f-07df28b172d2','緣識  其四六','宋太宗','宋','宋诗','song-poetry','','[]','人心樂樂聚神州，秀麗煙霞勝十洲。',128,'全唐诗/poet.song.1000.json','["人心樂樂聚神州，秀麗煙霞勝十洲。", "細柳高來齊拂岸，飛鳬時下傍輕舟。", "風摇碧浪藏魚窟，園裏朱櫻滿樹頭。", "歌唱新聲雙揭調，花前別是一般流。", "揎衫整羽揩金鏃，圓月開弓射白鷗。", "雲與山連恒爲白，春生夏長莫知秋。", "三天得路迷仙府，百辟盈衢從冕旒。", "務本含靈皆自化，和平盛世縱遨遊。"]'),
('5e27a3bf-64b5-45da-8236-7a596e1d072e','緣識  其四七','宋太宗','宋','宋诗','song-poetry','','[]','心問心，心非色相心，清靜之心道理深。',50,'全唐诗/poet.song.1000.json','["心問心，心非色相心，清靜之心道理深。", "驗在目前諸境界，不是凡音有正音。", "大道本來人難解，豈教離樂易求尋。"]'),
('a59c45bd-f3b7-4b54-8f42-7de1f9af69ef','緣識  其四八','宋太宗','宋','宋诗','song-poetry','','[]','恤刑徧空於囹圄，八風調順興時雨。',80,'全唐诗/poet.song.1000.json','["恤刑徧空於囹圄，八風調順興時雨。", "我且慙無及物功，哀哉獄訟經炎暑。", "清凉坐起受官榮，幾許能仁善規矩。", "倏忽從天降下來，霶沱敢望如斯睹。", "預豐苗稼瑞三秋，有感必通消灾苦。"]'),
('78d281c0-73d9-4419-9104-b87d2647d9d4','緣識  其四九','宋太宗','宋','宋诗','song-poetry','','[]','中秋旱直至臘月，憂煩情緒不堪說。',128,'全唐诗/poet.song.1000.json','["中秋旱直至臘月，憂煩情緒不堪說。", "闇祈頂戴上玄穹，今日高明降瑞雪。", "時聞喜處萬千家，片逐輕風四六花。", "寒透衣寬何所思，紅鑪旋煖酒須誇。", "觸面來往渾無力，幾處人憐幾處惜。", "想得歡心盡一般，先報田農後稼穡。", "呈祥天地共盈懷，白沙擁砌玉爲階。", "動靜蒼生絕災害，安康四敘壓氛霾。"]'),
('50b97622-3997-4807-9cfc-7441a4cdd70a','緣識  其五○','宋太宗','宋','宋诗','song-poetry','','[]','金剛般若心，善破無明因。',48,'全唐诗/poet.song.1000.json','["金剛般若心，善破無明因。", "我佛慈悲日，祇園見法身。", "菩薩開慧眼，生死轉爲輪。", "五藴皆空盡，六根不染塵。"]'),
('d4ae6b95-d48f-4d81-a95a-4d54f9579114','緣識  其五一','宋太宗','宋','宋诗','song-poetry','','[]','不曾師受有文章，天與聰明作久長。',32,'全唐诗/poet.song.1000.json','["不曾師受有文章，天與聰明作久長。", "道味自然玄境外，凡中奇異必非常。"]'),
('7977e54e-c8d0-48be-b7ef-558594254c7a','緣識  其五二','宋太宗','宋','宋诗','song-poetry','','[]','從小莫顛謏，長大始成人。',132,'全唐诗/poet.song.1000.json','["從小莫顛謏，長大始成人。", "經史須勤學，然可待尊親。", "勿談他己短，但秪自脩身。", "所作行慈善，見者生欽羨。", "好事審還聽，憎愛去貪戀。", "我即說分明，誡逸絕驕矜。", "孺子受天廕，不織不蠶耕。", "願爾多聰悟，考順於君父。", "逆耳必從之，少慾減嗔怒。", "謹守作童兒，緣是正愚癡。", "重貴在心知，認取世間爲。"]'),
('a009c465-5a32-484e-b9d3-8209737d86f3','緣識  其五三','宋太宗','宋','宋诗','song-poetry','','[]','道門長嘯扣玄關，咀嚼盈虛口不閑。',32,'全唐诗/poet.song.1000.json','["道門長嘯扣玄關，咀嚼盈虛口不閑。", "峰頂怡情松作笠，五湖來往看人間。"]'),
('fe269768-80cf-48cd-9abd-a68dd8b63b54','緣識  其五四','宋太宗','宋','宋诗','song-poetry','','[]','年過百幾鬢如鴉，到處安然便是家。',32,'全唐诗/poet.song.1000.json','["年過百幾鬢如鴉，到處安然便是家。", "醉後有時相詰問，更言我解種黄芽。"]'),
('09734e70-f7e1-4fb2-9521-91c158f9d946','緣識  其五五','宋太宗','宋','宋诗','song-poetry','','[]','善事多兮惡事少，君子能言兮心自了。',113,'全唐诗/poet.song.1000.json','["善事多兮惡事少，君子能言兮心自了。", "杳杳冥冥幻化中，舉目因緣還大小。", "勿縱貪，勿縱巧，知有寒人饑是飽。", "良圖子細寬更寬，下見如癡何草草。", "逆莫嗔，順莫好，尋思久遠生煩惱。", "雖然我漸近中年，歸依佛，歸依道。", "餘外閑來物外閑，誰聽庸音聲浩浩。"]'),
('a480159c-af09-4f1f-b719-6ffebf7584c4','緣識  其五六','宋太宗','宋','宋诗','song-poetry','','[]','崑崙山上玉樓前，五色祥光混紫煙。',32,'全唐诗/poet.song.1000.json','["崑崙山上玉樓前，五色祥光混紫煙。", "景物不同人世界，羣仙時醉卧花眠。"]'),
('88c6dcbc-876f-421e-98ff-9bc28d344b43','緣識  其五七','宋太宗','宋','宋诗','song-poetry','','[]','一莖枯竹作漁竿，同畏蛟螭坐釣灘。',32,'全唐诗/poet.song.1000.json','["一莖枯竹作漁竿，同畏蛟螭坐釣灘。", "若獲得魚舡許大，應想恐悚不心安。"]'),
('d6ce6f38-c2d4-4ea6-aaa6-713d60d4f142','緣識  其一','宋太宗','宋','宋诗','song-poetry','','[]','慈悲與喜捨，歷劫自然深。',24,'全唐诗/poet.song.1000.json','["慈悲與喜捨，歷劫自然深。", "法要無抱束，緣歸一寸心。"]'),
('29697829-3fd7-4948-8b5c-a8359b1d4bcc','緣識  其二','宋太宗','宋','宋诗','song-poetry','','[]','性相華嚴海，愛河渡要津。',24,'全唐诗/poet.song.1000.json','["性相華嚴海，愛河渡要津。", "法門千萬偈，奧妙演無倫。"]'),
('7e80c4be-ee68-4952-8867-1a55500ec284','緣識  其三','宋太宗','宋','宋诗','song-poetry','','[]','玄微達造化，得一不言三。',24,'全唐诗/poet.song.1000.json','["玄微達造化，得一不言三。", "利益衆生願，情迷謾口談。"]'),
('82feb861-4c2b-46da-b17e-9b94b7142e1f','緣識  其四','宋太宗','宋','宋诗','song-poetry','','[]','靜非山裏住，鬧即擬何之。',24,'全唐诗/poet.song.1000.json','["靜非山裏住，鬧即擬何之。", "緣識歸空寂，生前舊亦知。"]'),
('78463403-9c45-49e5-8bfb-d28dfc1dddd1','緣識  其五','宋太宗','宋','宋诗','song-poetry','','[]','時流求法界，問取本真詮。',24,'全唐诗/poet.song.1000.json','["時流求法界，問取本真詮。", "了悟空皆寂，心明海月圓。"]'),
('53d32665-284f-408c-9b33-327cdd1f5612','緣識  其六','宋太宗','宋','宋诗','song-poetry','','[]','如夢復性坐，尋思境外忙。',24,'全唐诗/poet.song.1000.json','["如夢復性坐，尋思境外忙。", "因緣開利鈍，語默自清凉。"]'),
('3e4316be-6b83-45cf-9b3f-b35942c189ce','緣識  其七','宋太宗','宋','宋诗','song-poetry','','[]','邪見終成僻，真如是久長。',24,'全唐诗/poet.song.1000.json','["邪見終成僻，真如是久長。", "閑心通物外，日月四時忙。"]'),
('9699b29e-bf2b-45c9-bb15-883741c5c730','緣識  其八','宋太宗','宋','宋诗','song-poetry','','[]','出利袪煩惱，紅塵指道衣。',24,'全唐诗/poet.song.1000.json','["出利袪煩惱，紅塵指道衣。", "悟來持一念，尊大默玄機。"]'),
