('add71dbb-9900-473a-a875-3224acf105bd','緣識  其六三','宋太宗','宋','宋诗','song-poetry','','[]','潔志清齋仰昊穹，九天雲雨正濛濛。',32,'全唐诗/poet.song.1000.json','["潔志清齋仰昊穹，九天雲雨正濛濛。", "都緣學道心無定，豈是靈仙秘爾功。"]'),
('781a2d38-ee38-457f-af72-852b3949b5d9','緣識  其六四','宋太宗','宋','宋诗','song-poetry','','[]','懸鑒高明鬼亦愁，方知研醜更玄幽。',32,'全唐诗/poet.song.1000.json','["懸鑒高明鬼亦愁，方知研醜更玄幽。", "恒持大道真空理，清靜烟波可自由。"]'),
('6c8c188d-bc8c-4b74-a5dc-c1a7566035aa','緣識  其六五','宋太宗','宋','宋诗','song-poetry','','[]','遥觀極自望雲頭，碧海波澄瑞日浮。',32,'全唐诗/poet.song.1000.json','["遥觀極自望雲頭，碧海波澄瑞日浮。", "霞彩連天長不斷，須憑仙子敘蹤由。"]'),
('86d6e878-0f0e-4581-82e4-a6f39336dcbf','緣識  其六六','宋太宗','宋','宋诗','song-poetry','','[]','大衆仙壇幾萬秋，碧雲拖翠照崑丘。',32,'全唐诗/poet.song.1000.json','["大衆仙壇幾萬秋，碧雲拖翠照崑丘。", "抱書童子無言話，笑阻迷情不解愁。"]'),
('cb57568e-a625-44c8-ae2c-45321f057db4','緣識  其六七','宋太宗','宋','宋诗','song-poetry','','[]','緊峻焚修彼自知，天嗔不許亂施爲。',32,'全唐诗/poet.song.1000.json','["緊峻焚修彼自知，天嗔不許亂施爲。", "真心實行終歸德，善事緣多惡可悲。"]'),
('b41dcae5-3a98-4f33-9d01-3b9d00af820c','緣識  其六八','宋太宗','宋','宋诗','song-poetry','','[]','照燭靈源理甚長，直須清浄有馨香。',32,'全唐诗/poet.song.1000.json','["照燭靈源理甚長，直須清浄有馨香。", "俱含萬像人難見，鬰鬰黄花翠竹光。"]'),
('57fbbb22-22c3-446f-8e6f-19f9634b2033','緣識  其六九','宋太宗','宋','宋诗','song-poetry','','[]','功成一旦等閑休，豈信昇沈滿眼愁。',32,'全唐诗/poet.song.1000.json','["功成一旦等閑休，豈信昇沈滿眼愁。", "莫道盈虛干甚事，天仙滅靜鎮常幽。"]'),
('21e9740e-3791-4bea-95bb-2c28490acdb8','緣識  其七○','宋太宗','宋','宋诗','song-poetry','','[]','玉殿金扉百道光，迴旋隠密對朝陽。',32,'全唐诗/poet.song.1000.json','["玉殿金扉百道光，迴旋隠密對朝陽。", "世人不悟幽深理，却說浮生事久長。"]'),
('5430fe72-8d03-4019-a21f-8445abc946cf','緣識  其七一','宋太宗','宋','宋诗','song-poetry','','[]','堅心不退道皆同，元始天尊大教通。',32,'全唐诗/poet.song.1000.json','["堅心不退道皆同，元始天尊大教通。", "多是世人迷自惑，豈能容易見仙蹤。"]'),
('63b9a92b-e24c-4ae3-ac63-a8284105dbd7','緣識  其七二','宋太宗','宋','宋诗','song-poetry','','[]','乾剛展轉運陰陽，一味清虛道不忙。',32,'全唐诗/poet.song.1000.json','["乾剛展轉運陰陽，一味清虛道不忙。", "玄妙永通天地久，未言大海變田桑。"]'),
('adb07d99-c547-4a58-b85d-2a9ca8dad23b','緣識  其七三','宋太宗','宋','宋诗','song-poetry','','[]','一年去住幾周遊，日月高懸萬億秋。',32,'全唐诗/poet.song.1000.json','["一年去住幾周遊，日月高懸萬億秋。", "但好心求方外境，勿教妄想沒剛柔。"]'),
('89ef74f7-8e2a-4971-8af0-ac47b7889524','緣識  其七四','宋太宗','宋','宋诗','song-poetry','','[]','道在希夷不易尋，忘言息慮便知深。',32,'全唐诗/poet.song.1000.json','["道在希夷不易尋，忘言息慮便知深。", "黄金白玉將何用，爭比靈源一寸心。"]'),
('70098cad-861d-4723-a15a-91f9f6765733','緣識  其七五','宋太宗','宋','宋诗','song-poetry','','[]','蠻夷夷必盡無知，上聖功成亦化之。',32,'全唐诗/poet.song.1000.json','["蠻夷夷必盡無知，上聖功成亦化之。", "大道須歸真見性，灰心達善即爲師。"]'),
('92dd6836-2440-4970-9ccf-f3c7e85bbfb3','緣識  其七六','宋太宗','宋','宋诗','song-poetry','','[]','照耀乾坤大道光，神仙隠見不相妨。',32,'全唐诗/poet.song.1000.json','["照耀乾坤大道光，神仙隠見不相妨。", "非凡非聖能迴向，始信三天日月長。"]'),
('f9a80eb7-7b92-4d6c-9c02-b2e201bd7300','緣識  其七七','宋太宗','宋','宋诗','song-poetry','','[]','天門地戶秘機深，誰測玄微妙理心。',32,'全唐诗/poet.song.1000.json','["天門地戶秘機深，誰測玄微妙理心。", "唯有丹田身外境，清虛恬澹影森森。"]'),
('3e20cbcf-5867-4c06-8f07-4f7af722be1b','緣識  其七八','宋太宗','宋','宋诗','song-poetry','','[]','慕道虔心仰翠微，玄關寂寂少人知。',32,'全唐诗/poet.song.1000.json','["慕道虔心仰翠微，玄關寂寂少人知。", "不求世寶兼名利，始悟無心合道時。"]'),
('dcb4ab73-a1f7-43b6-9db1-b49cfd7308d2','緣識  其七九','宋太宗','宋','宋诗','song-poetry','','[]','故無形像顯教尋，隠秘蹤由自古今。',32,'全唐诗/poet.song.1000.json','["故無形像顯教尋，隠秘蹤由自古今。", "妙法不傳經上字，玄門消息岡知深。"]'),
('f74f03d0-6cf7-451b-a51d-e6bb273d4c12','緣識  其八○','宋太宗','宋','宋诗','song-poetry','','[]','浮生好道勿虛忙，鍊藥修行事久長。',32,'全唐诗/poet.song.1000.json','["浮生好道勿虛忙，鍊藥修行事久長。", "輕舉不由他假借，一登清境入仙鄉。"]'),
('03662f2a-c2e9-4d00-9ff4-901eac4cfc9a','緣識  其八一','宋太宗','宋','宋诗','song-poetry','','[]','能知養性道中求，須要虔祈事轉幽。',32,'全唐诗/poet.song.1000.json','["能知養性道中求，須要虔祈事轉幽。", "通達遠開明了悟，一真守靜萬緣休。"]'),
('20921585-6943-4e65-8232-1fcd8c8ea6c9','緣識  其八二','宋太宗','宋','宋诗','song-poetry','','[]','誰是知非便肯休，空言大道眼前頭。',32,'全唐诗/poet.song.1000.json','["誰是知非便肯休，空言大道眼前頭。", "惟思利己浮名重，豈信功高入品流。"]'),
('ef3482c2-b54d-420a-838e-ba3c53d6551a','緣識  其八三','宋太宗','宋','宋诗','song-poetry','','[]','心專慕道真空法，恬澹清虛好到頭。',32,'全唐诗/poet.song.1000.json','["心專慕道真空法，恬澹清虛好到頭。", "如此修行皆盡達，十洲仙侶道相求。"]'),
('72a97ba2-4e7e-440b-acfd-fc3ea4561da7','緣識  其八四','宋太宗','宋','宋诗','song-poetry','','[]','初分上下順陰陽，草木浮生地久長。',32,'全唐诗/poet.song.1000.json','["初分上下順陰陽，草木浮生地久長。", "日月星辰隨大道，天心便是法中王。"]'),
('8c0cd5cf-280c-4d9e-b2e6-eb503001cb12','緣識  其八五','宋太宗','宋','宋诗','song-poetry','','[]','治世求歸濟物功，希夷入我道情中。',32,'全唐诗/poet.song.1000.json','["治世求歸濟物功，希夷入我道情中。", "從頭日日被煩惱，煩惱思量摠是空。"]'),
('23877ac4-9071-4c60-b474-44d6f979b298','緣識  其八六','宋太宗','宋','宋诗','song-poetry','','[]','五色雲煙聚十洲，蓬萊海浪壓鼇頭。',32,'全唐诗/poet.song.1000.json','["五色雲煙聚十洲，蓬萊海浪壓鼇頭。", "化成宮闕遥瞻禮，大衆神仙玉洞遊。"]'),
('cb2569b9-3f61-437c-8b48-808d81369bab','緣識  其八七','宋太宗','宋','宋诗','song-poetry','','[]','人愚學道謗神仙，豈達虛無物外緣。',32,'全唐诗/poet.song.1000.json','["人愚學道謗神仙，豈達虛無物外緣。", "多是六情貪愛障，更兼朝暮不心堅。"]'),
('4dc768cb-952c-4064-a4fd-7f8836ca2150','緣識  其八八','宋太宗','宋','宋诗','song-poetry','','[]','沖和道德勿相違，聖事超凡好仗依。',32,'全唐诗/poet.song.1000.json','["沖和道德勿相違，聖事超凡好仗依。", "但有陰功存世界，何疑白日化身飛。"]'),
('82ea4540-63d9-47f1-9ee5-d849cec971e2','緣識  其八九','宋太宗','宋','宋诗','song-poetry','','[]','寒銷暄盛同天色，花柳逢春誰不惜。',32,'全唐诗/poet.song.1000.json','["寒銷暄盛同天色，花柳逢春誰不惜。", "幾許人心達久長，光陰知道留難得。"]'),
('9b43201d-92b8-4dd0-989a-ff008e2c8aa4','緣識  其九○','宋太宗','宋','宋诗','song-poetry','','[]','經到玄科大法中，先持道德濟陰功。',32,'全唐诗/poet.song.1000.json','["經到玄科大法中，先持道德濟陰功。", "三清有路人難到，但守虛無一逕同。"]'),
('848f9b6e-0505-4243-a73e-6601308fc05e','緣識  其九一','宋太宗','宋','宋诗','song-poetry','','[]','細月銜山似玉鈎，先陳蹤跡問瀛洲。',32,'全唐诗/poet.song.1000.json','["細月銜山似玉鈎，先陳蹤跡問瀛洲。", "從來萬劫垂名在，王母行天得自由。"]'),
('283721a2-b681-48ab-9f20-d6b2bb45eb28','緣識  其九二','宋太宗','宋','宋诗','song-poetry','','[]','逢春便見野花新，往覆閑忙舊路塵。',32,'全唐诗/poet.song.1000.json','["逢春便見野花新，往覆閑忙舊路塵。", "輪走足輕多少意，世途常似夢中人。"]'),
('ddbad7c1-7861-4981-9cac-d490d9f1fa38','緣識  其九三','宋太宗','宋','宋诗','song-poetry','','[]','慕道焚修萬法通，一心清淡奉真宗。',32,'全唐诗/poet.song.1000.json','["慕道焚修萬法通，一心清淡奉真宗。", "方知異境人難見，見即虛無事不空。"]'),
('7b62d612-51b2-4503-8a00-09c95d71fde9','緣識  其九四','宋太宗','宋','宋诗','song-poetry','','[]','世俗忙忙似海深，愚迷豈解聖人心。',32,'全唐诗/poet.song.1000.json','["世俗忙忙似海深，愚迷豈解聖人心。", "分明教法生虛妄，慵鍊歸真不易金。"]'),
('421a624a-c339-4d14-9cd3-2a3b467a696f','緣識  其九五','宋太宗','宋','宋诗','song-poetry','','[]','莫問仙家不死鄉，泥丸秘密隠身光。',32,'全唐诗/poet.song.1000.json','["莫問仙家不死鄉，泥丸秘密隠身光。", "華池禹潤無拘束，勤習通流看上方。"]'),
('4e9e7af5-9b14-4c07-bad2-4a2768b0b4b3','緣識  其九六','宋太宗','宋','宋诗','song-poetry','','[]','聖人棄智妄中尋，質實先明朴在心。',32,'全唐诗/poet.song.1000.json','["聖人棄智妄中尋，質實先明朴在心。", "坦蕩玄門常不達，那非那是秘源深。"]'),
('201ccf10-baae-4a25-bf8b-1974db3fa07e','緣識  其九七','宋太宗','宋','宋诗','song-poetry','','[]','修持須是要精專，常恐他人業類牽。',32,'全唐诗/poet.song.1000.json','["修持須是要精專，常恐他人業類牽。", "莫把我言爲戲弄，輪迴斷定不遷延。"]'),
('63690b9d-5863-44d7-baa2-3bdd03398c8b','緣識  其九八','宋太宗','宋','宋诗','song-poetry','','[]','救物功深好自持，知之修鍊善心爲。',32,'全唐诗/poet.song.1000.json','["救物功深好自持，知之修鍊善心爲。", "神仙豈謂人間惜，自是迷流識見卑。"]'),
('db68503b-52cd-40de-a6a0-43345f263e28','緣識  其九九','宋太宗','宋','宋诗','song-poetry','','[]','語言端謹易求尋，己是他非禍返侵。',32,'全唐诗/poet.song.1000.json','["語言端謹易求尋，己是他非禍返侵。", "忠信先修銷大僞，何曾鄙隔聖緣心。"]'),
('aa05032a-ddd7-4db4-ace8-0637f7e8983d','緣識  其一○○','宋太宗','宋','宋诗','song-poetry','','[]','報應從教見祖宗，先持清靜後論功。',32,'全唐诗/poet.song.1000.json','["報應從教見祖宗，先持清靜後論功。", "紅蓮花出青泥裏，方信仙凡道本同。"]'),
('974a4760-4cbb-44ba-bf78-fe4009631b73','緣識  其一○一','宋太宗','宋','宋诗','song-poetry','','[]','任從寒暑鎮常侵，一氣韜藏萬種心。',32,'全唐诗/poet.song.1000.json','["任從寒暑鎮常侵，一氣韜藏萬種心。", "堪笑愚癡澆蕩甚，却非淳朴不幽深。"]'),
('7eaa02b5-5edd-4836-88e9-573b0150692b','緣識  其一','宋太宗','宋','宋诗','song-poetry','','[]','淳化四年立春節，喜遇韶光看白雪。',160,'全唐诗/poet.song.1000.json','["淳化四年立春節，喜遇韶光看白雪。", "祥雲景象一時呈，凝情靄郁比難說。", "人心丕變顔容別，樂天順敘皆胥悅。", "土牛擊後便駈耕，萬物從茲萌牙發。", "麗日遲遲影漸長，梅花嶺上明皎潔。", "懽抃陳儀隘九重，乾坤瑞氣初融泄。", "真風大布色無窮，春盤鮮盛排羅列。", "隆興煥耀太平宜，預祈豐稔名香藝。", "淺情之人莫共語，引爾回邪非處所。", "爭似淡交得久長，小人終是無規矩。"]'),
('5111cabf-577b-4038-b547-5db0d0e3af11','緣識  其二','宋太宗','宋','宋诗','song-poetry','','[]','玉漿時復嚥於津，通暢全勝百味珍。',32,'全唐诗/poet.song.1000.json','["玉漿時復嚥於津，通暢全勝百味珍。", "滿口馨香兼自得，顔容改變作真人。"]'),
('ac69cb06-0c92-46e5-a2d1-3693366a70d7','緣識  其三','宋太宗','宋','宋诗','song-poetry','','[]','紫檀金線槽偏蹙，撥弄朱弦敲冰玉。',224,'全唐诗/poet.song.1000.json','["紫檀金線槽偏蹙，撥弄朱弦敲冰玉。", "指法從來天下聞，翻成盡入昇平曲。", "傳之世上五音足，希夷道聽化民俗，盤龍面對壓鼇頭，玄微風散萬般流。", "長春苑內半酣酒，陽和自態低迴首。", "聲高細咽浪潛幽，不勝情處稀還有。", "韻響寒空明月裏，亦非滌蕩凡愚耳。", "謾說仙家調宮徵，絲竹那堪將比擬。", "溫柔腕軟一雙輕，滿坐馨香來四起。", "珠囊抉破無多力，好似鳳皇張羽翼。", "昔時皆總用心勞，幾許名揚彈盡得。", "和合象同琴與瑟，凝神巧妙通南北。", "鶑嬌舌急戀芳菲，水精簾外欲含輝。", "此藝人間堪可重，杏花楊柳色依依。"]'),
('ec882a04-aba6-46e1-b49a-47174bf40f19','緣識  其四','宋太宗','宋','宋诗','song-poetry','','[]','雅頌文章順化風，馨香不必在芳叢。',32,'全唐诗/poet.song.1000.json','["雅頌文章順化風，馨香不必在芳叢。", "陽和遠近隨田畝，春雨如膏有大功。"]'),
('5444f8fe-08b7-4f77-97cc-2f9b85cceb2d','緣識  其五','宋太宗','宋','宋诗','song-poetry','','[]','如花遇雨濕瀧凍，審此言談大道中。',32,'全唐诗/poet.song.1000.json','["如花遇雨濕瀧凍，審此言談大道中。", "世上幾人知舉措，故然不與我心同。"]'),
('e26dd526-efb4-48fa-b58c-49e68d4120fd','緣識  其六','宋太宗','宋','宋诗','song-poetry','','[]','月光紅燄影參差，九衢麗景意躕踟。',128,'全唐诗/poet.song.1000.json','["月光紅燄影參差，九衢麗景意躕踟。", "車馬往來珠無礙，幾人相逐幾人隨。", "天河夜靜色如銀，半擁紅街半擁春。", "山高市邑弦管處，燭殘露顯伴香塵。", "傳更漏唱欲將催，百萬燈花燄裏開。", "醉酒狂歌家家客，行坐歡如莫自裁。", "去年今夕一般遊，桂樹蟾宮慢欹樓。", "更深漸覺寒氣冷，雲摇五色順情流。"]'),
('6bb04082-0aa9-419d-90e6-e58801f2edd9','緣識  其七','宋太宗','宋','宋诗','song-poetry','','[]','上短下長人莫笑，信緣披得便前行。',32,'全唐诗/poet.song.1000.json','["上短下長人莫笑，信緣披得便前行。", "衣裳不是顛來倒，憑仗丹青畫取成。"]'),
('c828f54a-41e1-44d7-9925-18af23dd057a','緣識  其八','宋太宗','宋','宋诗','song-poetry','','[]','花間春鳥語喈喈，道在其中動我懷。',32,'全唐诗/poet.song.1000.json','["花間春鳥語喈喈，道在其中動我懷。", "紅艷幾時長久住，年年依舊看相挨。"]'),
('350571aa-c443-46a1-88ab-f5834769cb78','緣識  其九','宋太宗','宋','宋诗','song-poetry','','[]','露含千滴瀝，幻化杳無跡。',168,'全唐诗/poet.song.1000.json','["露含千滴瀝，幻化杳無跡。", "心重一時間，寸陰堪可惜。", "明根生惠性，德行多饒益。", "掌握驪龍珠，縱橫不改易。", "浮生在眼前，海變黄沙磧。", "萬里似閑雲，天高難障隔。", "春來又復秋，正自銷邪僻。", "慾界共知深，恒河豈蕩滌。", "虛空有路岐，人迷慵去覓。", "影裏架金梯，堅持須是一。", "愚癡恍惚中，返朴歸淳質。", "毀譽謾勞煩，終身還不吉。", "河水注東流，自然無漂溢。", "上下立尊卑，端恭何得失。"]'),
('bc30c3f5-dfa8-4094-af80-f3cbe34878ea','緣識  其一○','宋太宗','宋','宋诗','song-poetry','','[]','年年柳與韶光契，春風便作開花使。',32,'全唐诗/poet.song.1000.json','["年年柳與韶光契，春風便作開花使。", "黄鶑到處不絕聲，嫩葉芽新生悲翠。"]'),
('e9a8080f-eb0e-4fdc-8220-be4f984e6332','緣識  其一一','宋太宗','宋','宋诗','song-poetry','','[]','信天緣便信天緣，那是凡夫那仙。',31,'全唐诗/poet.song.1000.json','["信天緣便信天緣，那是凡夫那仙。", "勿枉用心閑過日，來隨福報猛如泉。"]'),
('f6ede9b4-fa22-41f1-8f4d-6a532b852a0e','緣識  其一二','宋太宗','宋','宋诗','song-poetry','','[]','我曾聞昆吾有鐵，九鍊方成冰似雪。',102,'全唐诗/poet.song.1000.json','["我曾聞昆吾有鐵，九鍊方成冰似雪。", "玉彩精晶耀日月，風霜凜凜甚威烈。", "新磨刃上七星文，誰敢鋒前布陳雲。", "黯黯凌空魑魅怕，銷盡邪魔并詭詐。", "寒光到處鬼神愁，哮吼乾坤一片秋。", "龍泉劍，龍泉劍，我用似波流，昇平無事匣中收。"]'),
('b1b6da3e-d21c-4f7a-a643-f79b68df903e','緣識  其一三','宋太宗','宋','宋诗','song-poetry','','[]','五惡貪嗔皆自起，高深海嶽猶窮矣。',32,'全唐诗/poet.song.1000.json','["五惡貪嗔皆自起，高深海嶽猶窮矣。", "無明發在一時間，對面如同千萬里。"]'),
('97dd7b57-cb57-42c1-9a66-ecb2465b50f5','緣識  其一四','宋太宗','宋','宋诗','song-poetry','','[]','酒一杯，深深情不足，倚檻迢迢青草綠。',126,'全唐诗/poet.song.1000.json','["酒一杯，深深情不足，倚檻迢迢青草綠。", "舉目煙飛勻灼灼，柳摇似舞春風曲。", "葉嫩舒張芽徧拆，觸處芳菲尋未得。", "妖妍艷艷爲誰流，鶑銜花墜落人頭。", "世間萬事難裁剪，樂送樓臺聲遠遠。", "斷續高低去復來，稀疏霧郁松枝偃。", "暄和思滿郊，燕拂綠楊梢。", "暖日倍添紅杏密，從容閑被野禽嘲。"]'),
('6e98db32-b79a-4e00-8f69-c230a63a379f','緣識  其一五','宋太宗','宋','宋诗','song-poetry','','[]','凡愚不取自逍遥，其奈心如似火燒。',32,'全唐诗/poet.song.1000.json','["凡愚不取自逍遥，其奈心如似火燒。", "虛過光陰速似夢，隨緣盡向暗中銷。"]'),
('de1794c3-c254-4c86-97c8-e7b4af8129ed','緣識  其一六','宋太宗','宋','宋诗','song-poetry','','[]','三春二月一樣同，翠柳峨峨解舞風。',48,'全唐诗/poet.song.1000.json','["三春二月一樣同，翠柳峨峨解舞風。", "池水湛然經雨後，桃花始覺半開紅。", "半開紅，麗天輝，新燕未歸鶑亦飛。"]'),
('5a63963e-c920-4e1c-a9e1-a1383b66b11d','緣識  其一七','宋太宗','宋','宋诗','song-poetry','','[]','君恩重，人心重，未知各各將何用。',140,'全唐诗/poet.song.1000.json','["君恩重，人心重，未知各各將何用。", "思量二事一般情，賢愚憂樂皆相踵。", "大道不見是非心，名利囂塵如幻夢。", "朕緣寡昧愧周旋，未信鴉巢鷄生鳳。", "此理言淺究深言，意馬能調袪恣縱。", "荆棘太賤任從荒，粟麥本體隨他種。", "凡夫豈料自家身，開眼如盲堪笑弄。", "季於亂世遇時平，掌握縱橫誰紀頌。", "善念入無邊，惡也不知痛。"]'),
('a91b8a66-4b62-4f74-bb8a-3da41bfdeb2c','緣識  其一八','宋太宗','宋','宋诗','song-poetry','','[]','大矣哉文，道合南薰。',40,'全唐诗/poet.song.1000.json','["大矣哉文，道合南薰。", "包含六義，洞究三墳，傍通造化，察變聲聞。", "垂其懿範，萬一之分。"]'),
('66d6d001-9f14-4cdf-ad82-80950136db80','緣識  其一九','宋太宗','宋','宋诗','song-poetry','','[]','道泰希夷，乃詠歌之。',40,'全唐诗/poet.song.1000.json','["道泰希夷，乃詠歌之。", "羣材奮發，迭奏相追。", "風騷不失，千載一時。", "倜儻沿革，大啟箴規。"]'),
('70c86abb-efc7-4167-ac83-165525d46969','緣識  其二○','宋太宗','宋','宋诗','song-poetry','','[]','體道前賢，禮樂爲先。',40,'全唐诗/poet.song.1000.json','["體道前賢，禮樂爲先。", "縱橫逸豫，言發自然。", "多知博物，文德心懸。", "孰能若此，宇宙推遷。"]'),
('cf71c15a-4453-427c-8aa0-9ec9a0143dc6','緣識  其二一','宋太宗','宋','宋诗','song-poetry','','[]','繼出寵材，睹奧自開。',40,'全唐诗/poet.song.1000.json','["繼出寵材，睹奧自開。", "揣摩三教，百行俱來。", "真宗起思，撫掌堪咍。", "識業之敏，談論熙哉。"]'),
('d19df844-adfc-47b0-92cd-64b39264aa47','緣識  其二二','宋太宗','宋','宋诗','song-poetry','','[]','造化等齊，不分高低。',40,'全唐诗/poet.song.1000.json','["造化等齊，不分高低。", "神筆才智，海嶽凄凄。", "稀代爲寶，舉意東西。", "毫端萬象，沃蕩狂迷。"]'),
('1708237b-21a7-4c01-b4f3-b4729f7448ef','緣識  其二三','宋太宗','宋','宋诗','song-poetry','','[]','春色春兮景媚妍，薰風暖潤物華鮮。',380,'全唐诗/poet.song.1000.json','["春色春兮景媚妍，薰風暖潤物華鮮。", "上林花結和香霧，絮壓輕輕軟似綿。", "寰中運啟大平年，文武須精百藝全。", "弄影馬驕難控勒，龜茲韻雅奏鈞天。", "仙仗儀排親自注，電轉星毬來進御。", "玄之寂妙得其玄，更重人前舉止措。", "靴衫束带兩分行，七寶鞭擎呈內庫。", "一坦平兮殿毬場，國樂調兮甚鏘洋。", "掀天沸渭轟鼉皷，返朴純誠斅三皇。", "折旋俯仰怡情悅，乾坤日月盡舒光。", "龍馬徘徊多步驟，生獰堪羨困垂韁。", "繡䪌紅絛金蹀躞，鑾鈴珂珮水精裝。", "五雲慶集鶴爲駕，短袍新樣甚風雅。", "東西相望賀頭籌，歡呼蹈舞金階下。", "隔宿閤門宣侍臣，廐中令揀馴良馬。", "紫氣盤旋分月仗，庭蕪盡去平如掌。", "趫捷雄雄鏤鐙輕，雷聲唱徹迎空響。", "俄然斗轉俱渾霍，亦非駭目猶人作。", "學之玄妙似通神，鳳翼藏珠豈易落。", "傍捎正擊有多門，斜身用力輕敲斫。", "我因閑暇自銷停，對手臨時相架閣。", "深似交鋒立戰軾，匹馬縱橫藉筋脚。", "孤星遠迸向人飛。", "雲開瑞色天，清廓打三籌，公子王孫第一流。"]'),
('8ae4a338-7299-4d7b-9619-33da5c156886','緣識  其二四','宋太宗','宋','宋诗','song-poetry','','[]','皇天不事但多羅，莫道無緣奈我何。',32,'全唐诗/poet.song.1000.json','["皇天不事但多羅，莫道無緣奈我何。", "上有天堂下地獄，分明種麥不生禾。"]'),
('41ca26bd-3ccd-4577-822e-9098c20cd2f0','緣識  其二五','宋太宗','宋','宋诗','song-poetry','','[]','南來北去無時節，舉翅抬頭飛似雪。',32,'全唐诗/poet.song.1000.json','["南來北去無時節，舉翅抬頭飛似雪。", "當日離春今日秋，汀江浦上舊明月。"]'),
('da01bd8e-24b8-4735-b172-12ee7d131ce7','緣識  其二六','宋太宗','宋','宋诗','song-poetry','','[]','具蹄凡夫，何行何著。',110,'全唐诗/poet.song.1000.json','["具蹄凡夫，何行何著。", "靜鏁天台，高知嵩岳。", "拘束迷情，人天離樂。", "聖境芝蘭，名山採藥。", "啖柏餐松，清神去濁。", "入口馨香，風和露嚼。", "可以放曠，千年之鶴。", "審取來由，勿自繫縛。", "洞有桃源，化成雲閣。", "上有鳳皇，下水魚躍。", "本從自然，豈用圖度。"]'),
('a1832e81-df98-4eb0-9035-5445a6cc0aaa','緣識  其二七','宋太宗','宋','宋诗','song-poetry','','[]','春風綠野徧天地，枯朽漸隨紅日麗。',64,'全唐诗/poet.song.1000.json','["春風綠野徧天地，枯朽漸隨紅日麗。", "世界包含雨露新，東郊舒暢芳菲媚。", "煙波柳嫩摇拂水，時遷蕩颺情已矣。", "不言往昔與今來，海岳高深升萬里。"]'),
('5697307b-2273-42f3-b6fb-b4f0006e0009','緣識  其二八','宋太宗','宋','宋诗','song-poetry','','[]','朱明日盛殘花卉，瓊苑爭遊諠帝里。',128,'全唐诗/poet.song.1000.json','["朱明日盛殘花卉，瓊苑爭遊諠帝里。", "寶馬香車去復來，幾許人心歡不已。", "金明水上浮仙島，畫舸龍舟非草草。", "世寧清靜驗如然，老者携小少隨老。", "匼匝煙雲楊柳岸，羅綺縱橫長不斷。", "五穀豐登順四時，億兆歌謠絕愁嘆。", "康哉闐咽芳林下，一看難醻千萬價。", "千平聽在樂聲中，比屋可封民自化。"]'),
('dad91d22-4b8a-4c04-a0d5-8f7ca8aff4de','沖虛觀','胡宿','宋','宋诗','song-poetry','','[]','五粒青松護翠苔，石門岑寂斷纖埃。',64,'全唐诗/poet.song.10000.json','["五粒青松護翠苔，石門岑寂斷纖埃。", "水浮花片知仙路，風遞鸞聲認嘯臺。", "桐井曉寒千乳斂，茗園春嫩一旗開。", "馳煙未勒山亭字，可是英靈許再來。"]'),
('a820f955-c696-4b7b-ba8c-4e41e127216e','淮南發運趙邢州被詔歸闕','胡宿','宋','宋诗','song-poetry','','[]','天臺封詔紫泥馨，馬首前瞻北斗城。',64,'全唐诗/poet.song.10000.json','["天臺封詔紫泥馨，馬首前瞻北斗城。", "人在函關先望氣，帝于京兆最知名。", "一區東第趨晨近，數刻西廂接晝榮。", "正是兩宮裁化日，百金雙璧拜虞卿。"]'),
('11c7624d-4d29-4ea8-96a6-a832588eb399','雪後登秘閣','胡宿','宋','宋诗','song-poetry','','[]','消盡層陰上盡梯，雪餘宮瓦弄晴暉。',64,'全唐诗/poet.song.10000.json','["消盡層陰上盡梯，雪餘宮瓦弄晴暉。", "碧簷交照虬爭聳，朱闕相聯鳳欲飛。", "日向金溝春溜動，風來珠樹曉寒微。", "帝家池籞饒芳物，白鳥翩翩接翼歸。"]'),
('9eea306f-d950-4dbb-b4ad-e5f478c48cf7','謝叔子陽丈惠詩','胡宿','宋','宋诗','song-poetry','','[]','老子詩名久廢閒，喜君步驟少陵壇。',64,'全唐诗/poet.song.10000.json','["老子詩名久廢閒，喜君步驟少陵壇。", "句敲金玉聲名遠，韵險車斜心膽寒。", "傾出囊中和月露，皎如盤底走珠丸。", "苦藏難沒詩家事，會看塵冠早一彈。"]'),
('ad7b3f16-ab14-4377-b066-94f51803075f','又和前人','胡宿','宋','宋诗','song-poetry','','[]','作者傍邊好見聞，速來就汝作比鄰。',64,'全唐诗/poet.song.10000.json','["作者傍邊好見聞，速來就汝作比鄰。", "詩中活法無多子，眼裏知音有幾人。", "爾許精奇花粲筆，豈容塵俗海翻銀。", "老夫幸有千機錦，尚欠江頭一浣新。"]'),
('0a7dd082-8b8b-423e-957a-2da765a6b4f9','侯家','胡宿','宋','宋诗','song-poetry','','[]','洞戶春遲漏箭長，短轅初返洛城傍。',64,'全唐诗/poet.song.10000.json','["洞戶春遲漏箭長，短轅初返洛城傍。", "彩雲按曲青岑醴，沈水薰衣白璧堂。", "前檻蘭苕依玉樹，後園桐葉護銀牀。", "宴殘紅燭長庚爛，還促朝珂謁未央。"]'),
('11c3747b-0876-4bc5-b545-c610ae219d2c','秋風','胡宿','宋','宋诗','song-poetry','','[]','瑟瑟新聲脫綠槐，半寒天氣日相催。',64,'全唐诗/poet.song.10000.json','["瑟瑟新聲脫綠槐，半寒天氣日相催。", "西樓夜色吟偏好，南國朝雲夢未回。", "翠影暗牽蘋葉動，清香遥獵桂枝來。", "重陽漸近松醪熟，白菊如何爲放開。"]'),
('15423939-fb1e-45f7-8a91-598c16aa834e','送馬少卿赴襄陽','胡宿','宋','宋诗','song-poetry','','[]','冰操從來畏四知，漢江南畔擁藩麾。',64,'全唐诗/poet.song.10000.json','["冰操從來畏四知，漢江南畔擁藩麾。", "地經謝守開油幕，人憶山公倒接䍦。", "風入射堂飄鼓吹，雨隨行縣濕旌旗。", "前朝叔子流遺愛，拂蘚應看峴首碑。"]'),
('2855f50a-0330-4a89-a3e4-ef86728b8d12','送寶應李尉','胡宿','宋','宋诗','song-poetry','','[]','曾飛麗藻清堯問，猶屈長才尉楚城。',64,'全唐诗/poet.song.10000.json','["曾飛麗藻清堯問，猶屈長才尉楚城。", "官是神仙標秀領，縣因靈寶紀嘉名。", "西崑已挾凌雲譽，外戶全消擊柝聲。", "早晚聲名來謁帝，會看雙璧賜虞卿。"]'),
('48b20377-77ae-4ff5-a9e2-d53b7cdc6a8d','竹','胡宿','宋','宋诗','song-poetry','','[]','修篁百箇靜無埃，憶共山僧競日栽。',64,'全唐诗/poet.song.10000.json','["修篁百箇靜無埃，憶共山僧競日栽。", "夭矯翠虬身欲化，婆娑青鳳尾全開。", "風含爽籟依朱檻，月鏤青陰覆翠苔。", "曾爲檀欒衝雪看，玉枝相亞曉皚皚。"]'),
('791e213a-82a7-46ff-a5d0-91bd13237a8f','送周學士歸永嘉','胡宿','宋','宋诗','song-poetry','','[]','三最初承予告恩，一雙青翰出都門。',64,'全唐诗/poet.song.10000.json','["三最初承予告恩，一雙青翰出都門。", "關繻舊棄人多識，橋柱前題墨未昏。", "南國歸雲聊送目，河梁新月暫消魂。", "玉山丹府重來日，好拾風謠奏帝閽。"]'),
('b808348b-b969-4993-a541-89423af06ef3','送聶學士赴闕','胡宿','宋','宋诗','song-poetry','','[]','臺召西來二節榮，清江浮舸鴨頭平。',64,'全唐诗/poet.song.10000.json','["臺召西來二節榮，清江浮舸鴨頭平。", "十行受詔龍綸重，五兩占風鳥羽輕。", "目送華林春雨色，夢隨長樂曉鐘聲。", "竚看隻日延英對，丸墨宮毫屬長卿。"]'),
('4135267a-e675-4c30-9308-a9718371834b','送張學士赴邵武兼過吳中別墅','胡宿','宋','宋诗','song-poetry','','[]','青蔾香灺掩殘書，越絕東南駕隼旟。',64,'全唐诗/poet.song.10000.json','["青蔾香灺掩殘書，越絕東南駕隼旟。", "紫陌花期經祓禊，清淮潮信待蟾蜍。", "鳥聲百囀春芳際，蠶候三眠夏葉初。", "吳地吟朋如見問，爲言江令憶鳀魚。"]'),
('f84f4541-e3e9-4c1b-a259-026511f8eff3','寄張唐公學士','胡宿','宋','宋诗','song-poetry','','[]','朱航東下忽經春，藏室離居作惡頻。',64,'全唐诗/poet.song.10000.json','["朱航東下忽經春，藏室離居作惡頻。", "簡上蠹蟫終日在，樹間靈鵲至今馴。", "北宮自有咿嚘客，天祿誰同寂寞人。", "昨夜西窗有佳月，此心迢遞思冰輪。"]'),
('357397ad-8939-48a6-8c91-d6e2d4185c86','千葉瑞荷花','胡宿','宋','宋诗','song-poetry','','[]','絳蕊層層吐翠羅，水妃冠重曉峨峨。',64,'全唐诗/poet.song.10000.json','["絳蕊層層吐翠羅，水妃冠重曉峨峨。", "應嫌菖本開花少，却鬥榴房著子多。", "含露自知芳意在，偃風無奈落英何。", "更憐玉骨藏深怨，暗結千絲在綠波。"]'),
('5c96a857-8149-4861-ae08-d21cdb8ef666','題漣漪亭','胡宿','宋','宋诗','song-poetry','','[]','檻底凝漪碧漫天，角巾東路主人賢。',64,'全唐诗/poet.song.10000.json','["檻底凝漪碧漫天，角巾東路主人賢。", "汀花照席供春醉，沙鳥窺簾伴晝眠。", "何必馭風追汗漫，不妨乘月弄潺湲。", "流杯若仿山陰事，兼有蛙聲當管絃。"]'),
('8bbc11c9-4a60-425b-b7b6-2c82a7b08451','津亭','胡宿','宋','宋诗','song-poetry','','[]','津亭歌闋戒棠舟，五兩風輕不少留。',64,'全唐诗/poet.song.10000.json','["津亭歌闋戒棠舟，五兩風輕不少留。", "西北浮雲來魏闕，東南初日背秦樓。", "層城渺渺人傷別，芳草萋萋客倦遊。", "平樂舊歡收未得，更憑飛夢到瀛洲。"]'),
('6572d3dc-b901-4bc9-a2d5-263b07c6d0ae','有懷松江','胡宿','宋','宋诗','song-poetry','','[]','多年襆被玉山岑，鬢雪欺人忽滿簪。',64,'全唐诗/poet.song.10000.json','["多年襆被玉山岑，鬢雪欺人忽滿簪。", "駑馬雖然貪短豆，野麋終是憶長林。", "鱸魚未得乘歸興，鷗鳥惟應信此心。", "見說新橋好風景，會須乘月濯煩襟。"]'),
('ede565ca-394b-4a15-9379-82ace4ba7b66','寄題齊氏山齋','胡宿','宋','宋诗','song-poetry','','[]','有客稽山岸角巾，寶書盈笈日怡神。',64,'全唐诗/poet.song.10000.json','["有客稽山岸角巾，寶書盈笈日怡神。", "雲銜別嶺搘筇久，月上前峰隠几頻。", "窗上蘿陰猿警旦，塢中茶候鳥啼春。", "一經鄒喭能傳世，子舍于今兩綬新。"]'),
('d08d0c59-d8cc-4106-ba53-f789f60c06cc','送崔諫議都運河東','胡宿','宋','宋诗','song-poetry','','[]','行臺西北接參墟，仗節重乘駟馬車。',64,'全唐诗/poet.song.10000.json','["行臺西北接參墟，仗節重乘駟馬車。", "水是晉君沈璧後，地經唐叔賜圭餘。", "蕃酋重足虔條教，部吏承風畏簡書。", "武帳歲終還奏事，康侯三接聽新除。"]'),
('661fd72b-d081-4630-ba43-5412dc5e902b','送益州運使田學士','胡宿','宋','宋诗','song-poetry','','[]','劍棧秋旗拂過鴻，行臺西去撫蠶叢。',64,'全唐诗/poet.song.10000.json','["劍棧秋旗拂過鴻，行臺西去撫蠶叢。", "民間幼艾餐和氣，徼外酋豪偃德風。", "巴漢靜歸籌筆內，岷峨閒入畫圖中。", "時平幕府無留事，樂職何妨頌聖功。"]'),
('9bdd51ee-4330-4d6c-81da-f6a681aeeb2e','寄題蘭皋亭','胡宿','宋','宋诗','song-poetry','','[]','亭下春芳接楚波，金堤勃窣路相過。',64,'全唐诗/poet.song.10000.json','["亭下春芳接楚波，金堤勃窣路相過。", "窗中霽景煙姿遠，簾外晨香露氣多。", "紅頰倚牆花並蒂，綠陰翻檻樹交柯。", "朝陽定有浮杯樂，醉墨何妨記永和。"]'),
('132cee61-c26e-413a-ac96-8e34f1eafa75','採蓮女','胡宿','宋','宋诗','song-poetry','','[]','碧蓋緗葩映素秋，此中蘭櫂好銷憂。',64,'全唐诗/poet.song.10000.json','["碧蓋緗葩映素秋，此中蘭櫂好銷憂。", "相將共挈青絲籠，一笑同迴翠羽舟。", "日暮鳴榔隨下瀨，夜深歸櫂怯中流。", "東方自有羅敷婿，不顧江邊越鄂州。"]'),
('f5861c25-111c-4ed8-a667-e098f61c5be4','送柳先輩從事桐廬','胡宿','宋','宋诗','song-poetry','','[]','甘櫻離會酒初醒，還赴東侯拱璧迎。',64,'全唐诗/poet.song.10000.json','["甘櫻離會酒初醒，還赴東侯拱璧迎。", "江上桃歌傳樂錄，坐中鸚鵡占賓榮。", "仙車過洛人偏識，繡騎還邛客盡傾。", "後夜嚴陵臺上望，紫雲西北是神京。"]'),
('5ba923db-d7d0-4dbc-b057-6854bf304a95','寄杭州子文屯田兼簡真公上人','胡宿','宋','宋诗','song-poetry','','[]','目斷江南佳麗城，欄干樓角幾長憑。',64,'全唐诗/poet.song.10000.json','["目斷江南佳麗城，欄干樓角幾長憑。", "越人抱膝吟遍苦，吳客觀濤病未能。", "此地旃檀多勝剎，一時龍象有高僧。", "知君暇日尋猿鳥，閒上靈峰第幾層。"]'),
('f6f1db9b-a34a-47ce-a6ec-9a7c97547fbf','寄題王舍人書齋','胡宿','宋','宋诗','song-poetry','','[]','北地當衢拂斗魁，竹林清暑似巖隈。',64,'全唐诗/poet.song.10000.json','["北地當衢拂斗魁，竹林清暑似巖隈。", "將壇緒業傳金版，文苑新書集玉杯。", "數篋龍拏藏寶刻，一泓蟾滴試烟煤。", "好辭戴鶡飛千牘，東武原從禁衛來。"]'),
('f892816c-c6af-40af-898e-590aae85d963','霜野','胡宿','宋','宋诗','song-poetry','','[]','啄兔青骹直下飛，霜雲慘慘楚楓披。',64,'全唐诗/poet.song.10000.json','["啄兔青骹直下飛，霜雲慘慘楚楓披。", "秋林月迥聞樵斧，晚市風沈見酒旗。", "江上敗荷無限柄，雨中殘菊不盈枝。", "物華怨盡仍傷別，塢笛聲中一涕垂。"]'),
('aeb82d0d-3b60-4a8f-93f1-1b452558d31b','送陳諫東歸','胡宿','宋','宋诗','song-poetry','','[]','顔詩摛錦有高文，席上經年未聘珍。',64,'全唐诗/poet.song.10000.json','["顔詩摛錦有高文，席上經年未聘珍。", "鵠板乍停公府詔，貂裘還敝洛城塵。", "雪園授簡誰爲賦，煙渚歸艎不待春。", "何日子虛聞夜誦，尚方給札對嚴宸。"]'),
('a6f1afad-08b0-4637-9bc5-f850aeb1936c','送華濤東歸','胡宿','宋','宋诗','song-poetry','','[]','江上丹楓墮夜霜，式微愁思豈禁傷。',64,'全唐诗/poet.song.10000.json','["江上丹楓墮夜霜，式微愁思豈禁傷。", "壯圖萬里青雲在，舊徑三條碧草長。", "匹馬歸來江練白，惡氛收盡楚天凉。", "大明繼照光華旦，提筆相期翰墨場。"]'),
('f62d2bd9-438e-44cc-a440-17cf2912ea25','郊祀慶成','胡宿','宋','宋诗','song-poetry','','[]','齋輅虔郊報，祠宮就國陽。',120,'全唐诗/poet.song.10000.json','["齋輅虔郊報，祠宮就國陽。", "繁雲猶待族，霽日忽迎長。", "圭璧紛佳氣，粢盛馥異香。", "人情欣眷祐，天意益端莊。", "被衮侵寒霧，升壇躡早霜。", "左方虛小次，午陛却中黄。", "六樂乾祇格，三登海宇康。", "千官森劍珮，萬里走梯航。", "神筴膺符命，天壺飲福祥。", "從今瓜瓞慶，鼎業熾彌昌。"]'),
('8ffb2c86-32c6-4d51-935f-63bb37f8c3ff','閣前紫薇花','胡宿','宋','宋诗','song-poetry','','[]','高鬟美人髻，妝閣一何鮮。',96,'全唐诗/poet.song.10000.json','["高鬟美人髻，妝閣一何鮮。", "迷路來春後，開花近日邊。", "居常澆御水，動欲絢非烟。", "分潤從仙掌，流薰自帝絃。", "雅當翻藥地，繁極曝衣天。", "色映芝泥熟，香交蕙炷燃。", "吟殘秋蕊脫，睡起午陰圓。", "應笑憑欄者，相看已幾年。"]'),
('07361bcb-a3d8-424b-b844-13dba075571e','陳生遊金山兼簡世昌師','胡宿','宋','宋诗','song-poetry','','[]','寶勢嵐光秀，濃春物景鮮。',72,'全唐诗/poet.song.10000.json','["寶勢嵐光秀，濃春物景鮮。", "飛峰凌巨浸，精構起中天。", "鳥畏雲濤險，僧安石室禪。", "貫花應作偈，望月定陳篇。", "不爲青霄桂，同裁白社蓮。", "羨君飄鵠舫，獨自號神仙。"]'),
('fd19355f-2442-4e45-a03c-d082079dcb36','狀元張監丞倅陝郊兼之閬中省親','胡宿','宋','宋诗','song-poetry','','[]','藻衮御中楹，詳延得世英。',144,'全唐诗/poet.song.10000.json','["藻衮御中楹，詳延得世英。", "賓鄉具三物，題塔冠千名。", "玉擅崑山價，箎兼仲氏聲。", "平淵二龍躍，碣石一鴻輕。", "慈宴堯厨洽，宸章禹律鳴。", "入辭瞻翠葆，去候過朱櫻。", "贊治崤陵險，歸寧蜀棧橫。", "都門百壺送，宿館五漿迎。", "帝所銜標雋，親前戲綵榮。", "勒銘知有作，叱馭肯辭行。", "桂色窅窊秀，棠陰蔽芾清。", "期年隨詔入，脩路接瑶京。"]'),
('d8cab170-658e-4ccc-8af0-4ee2942f8887','歲晚禁直呈承旨侍郎同院五學士','胡宿','宋','宋诗','song-poetry','','[]','廣內施重闥，承明敞直廬。',240,'全唐诗/poet.song.10000.json','["廣內施重闥，承明敞直廬。", "上清通帝所，方丈擬仙居。", "漢后前釐席，淮王重報書。", "時宗登賈馬，暮召得嚴徐。", "玉至光秦璽，珠來照魏車。", "高文參正始，密旨奉權輿。", "王澤宣從綍，天香對滿裾。", "論思皆藥石，咳唾亦瓊琚。", "弱水滄波在，然山老墨餘。", "睿篇朱雁刻，宸翰白龍攄。", "寶肆還容礫，珍林誤植樗。", "匪躬無謇謇，每食有渠渠。", "寒日分宵直，繁雲向歲除。", "九門催鑰下，三殿警籤初。", "北斗低層掖，明河拂太虛。", "求衣欽德盛，襆被省才疏。", "多病長思越，知非晚學蘧。", "煙霄叨步武，江海隔樵漁。", "榆性誠爲鈍，葵心但欲舒。", "日祈同舍進，躋俗到華胥。"]'),
('c838c68c-832f-48fb-aa68-27fe25759924','次韵曼卿冬直因以勉贈','胡宿','宋','宋诗','song-poetry','','[]','八舍嚴周衛，千門肅漢閨。',96,'全唐诗/poet.song.10000.json','["八舍嚴周衛，千門肅漢閨。", "金胥催遞宿，玉羽伴歸棲。", "禁樹驚寒斂，仙雲拂夜低。", "星河紫牆外，霜月碧城西。", "汲字紛難整，鈞音怳易迷。", "有人歌白雪，此曲妙清溪。", "文獻初登亮，君王益徇齊。", "因知函鼎器，那復久烹雞。"]'),
('598393b7-7bdc-44c3-aa22-186a7183468d','后土觀瓊花','胡宿','宋','宋诗','song-poetry','','[]','楚地五千里，揚州獨一株。',96,'全唐诗/poet.song.10000.json','["楚地五千里，揚州獨一株。", "香名從此貴，芳格灑然殊。", "國艷何勞粉，天姿不掩瑜。", "濃薰霏麝氣，細蕊列蜂鬚。", "雲朵垂三素，仙衣著六銖。", "吳中休插柰，天上枉栽榆。", "神物疑長擁，靈根此未枯。", "人間如定價，百琲睡龍珠。"]'),
('e639e716-07b4-457c-9a2a-7a858918cd05','石曼卿學士輓詞','胡宿','宋','宋诗','song-poetry','','[]','才出羣英表，文推一代雄。',144,'全唐诗/poet.song.10000.json','["才出羣英表，文推一代雄。", "靈蛇操掌上，雲夢納胸中。", "醉墨千峰立，吟毫八極空。", "居官疏皎覈，處世倦磨礱。", "綠酒常埋照，清琴自寄通。", "昌言曾拂治，密疏早談戎。", "天子知亭伯，時人重孟公。", "何言執戟滯，便到闔棺窮。", "鵀鳥巢門止，驊騮挶櫪終。", "芝筋留御帳，簫賦落王宮。", "薄葬依莊叟，殘書付所忠。", "惟餘身後得，凜凜是英風。"]'),
('08959ff9-2c66-43c7-bf1f-0a9274ed31af','射熊館','胡宿','宋','宋诗','song-poetry','','[]','別館拋雙闕，飛除鎮一方。',96,'全唐诗/poet.song.10000.json','["別館拋雙闕，飛除鎮一方。", "黄山縈蹕道，青檜繞宮牆。", "緹騎千羣合，周阹四面張。", "管絃繁欲沸，旌旆鬰相望。", "走馬長楸密，更衣別寢凉。", "星飄肅慎矢，雪擁羽林槍。", "歡樂何曾極，盤遊不可狂。", "吾聞堯舜治，垂拱在巖廊。"]'),
('329cd769-d87d-4911-b067-581ed5088cf3','將家子','胡宿','宋','宋诗','song-poetry','','[]','北地良家子，山西舊將兒。',120,'全唐诗/poet.song.10000.json','["北地良家子，山西舊將兒。", "新從羽林射，得赴雁門期。", "橫死人無比，微行世不知。", "長安偏重俠，趙國素多奇。", "照地連錢錦，迷春鑿落巵。", "喝盧燕市客，顧笑楚臺姬。", "烟樹黄山路，霜雲白草時。", "雕弓孤月滿，騁馬一塵隨。", "應手雙雕落，回頭赤日移。", "却歸東第去，高宴九燈枝。"]'),
('b63c7aaa-e8d9-4813-9f0e-1cf35db169e1','詔福聖宮燒香','胡宿','宋','宋诗','song-poetry','','[]','徼道西華內，觚棱北斗傍。',144,'全唐诗/poet.song.10000.json','["徼道西華內，觚棱北斗傍。", "神靈安肯構，恩澤賜燔香。", "渤澥通驪窟，崑崙拱畫梁。", "清壇浮早景，碧瓦霽初霜。", "甲帳嚴如在，丹簷迥欲翔。", "隆姿瞻漢后，餘烈畏軒皇。", "埋劍橋山遠，游冠閣道長。", "白雲迷處所，仙掌鎮相望。", "五岳扶封域，三辰緯典章。", "升歌留寶鼎，刻號在神房。", "盛德尊原廟，遺仁睦鬼方。", "聖文名善繼，百世溢流光。"]'),
('68f6cc75-1822-4888-b4e5-79eb149f76bc','歲除','胡宿','宋','宋诗','song-poetry','','[]','暝色凝無際，寒雞悄未晨。',72,'全唐诗/poet.song.10000.json','["暝色凝無際，寒雞悄未晨。", "蓂枝將換朔，斗柄漸歸寅。", "水火猶分漏，龍蛇尚蟄身。", "四時寧有暇，萬物又勞春。", "樹喜丹葩秀，人憂白髮新。", "明朝趨寶殿，誰是奪重茵。"]'),
('73f1536f-06e9-4faa-a051-676717806e6d','送楊中允宰常熟','胡宿','宋','宋诗','song-poetry','','[]','丹舸傍江潯，嘔啞遠櫓音。',120,'全唐诗/poet.song.10000.json','["丹舸傍江潯，嘔啞遠櫓音。", "新科持片玉，能政引孤琴。", "美進宮坊秩，榮歸里閈心。", "名參天下雋，歌著邑中黔。", "地志連香徑，家園带武林。", "吳山幾屏秀，楚水一篙深。", "晚鼓停餘疊，秋帆卧半陰。", "平時接方驥，後夜望橫參。", "陶菊何妨醉，江毫且剩吟。", "悠悠河上別，千里鬰朋簪。"]'),
('962875a4-a927-44b2-8053-bb212ae8e6b6','郡齋招子美','胡宿','宋','宋诗','song-poetry','','[]','月色初藏桂，年芳漸有梅。',144,'全唐诗/poet.song.10000.json','["月色初藏桂，年芳漸有梅。", "人情欣臘破，天意許春回。", "陰雪迎風解，寒澌向日開。", "午枰宜試著，卯甕好嘗醅。", "寓興題紅葉，乘閒步紫苔。", "長吟溪上曲，偏憶洛中才。", "絕墨淩崖石，高文拂斗魁。", "詩鋒無敢犯，酒戶少能陪。", "綠髮裁方鬒，丹心未肯灰。", "琴書聊偃仰，魚鳥暫徘徊。", "蔚豹雖藏霧，蟠螭已得雷。", "只愁騰踏去，相望隔蓬萊。"]'),
('f2962a46-fc9d-4351-8828-72bb27e8c3ef','送晉陵王宰銓調','胡宿','宋','宋诗','song-poetry','','[]','盤錯才無滯，弦歌政有聲。',72,'全唐诗/poet.song.10000.json','["盤錯才無滯，弦歌政有聲。", "及瓜青紙詔，謁帝紫微城。", "節並霜松峻，心同冰玉清。", "十槳行色貴，三府辟書榮。", "驛樹紛紅葉，江蘋老紫莖。", "祇應中宿路，雙節急歸程。"]'),
('cb0cf981-18d6-416e-b028-8f096916503f','送祁陽黄宰','胡宿','宋','宋诗','song-poetry','','[]','邑控三湘遠，帆經百舍遲。',72,'全唐诗/poet.song.10000.json','["邑控三湘遠，帆經百舍遲。", "天文瞻翼軫，江色泛漣漪。", "丹闕傾心戀，蒼山舉目疑。", "歡杯憑秫米，騷思託蘭旗。", "竹律寬無害，琴堂靜不欺。", "期年行奉詔，虎帳對堯眉。"]'),
('f8418845-b272-47ea-84ed-84f4aa861119','上客','胡宿','宋','宋诗','song-poetry','','[]','上客何爲者，平生富義名。',96,'全唐诗/poet.song.10000.json','["上客何爲者，平生富義名。", "飛鈐師鬼谷，談笑敵神兵。", "然諾千金重，交游萬戶輕。", "平臺置酒召，碣館側身迎。", "土缶邀秦擊，銅盤劫楚盟。", "縱橫三寸舌，厭飫五侯鯖。", "龍種騰長坂，霜雕刮太清。", "誰能彈劍鋏，北海有長鯨。"]'),
('65e22e7b-84fa-42f1-86c6-f38c6a847a5f','送黄推官','胡宿','宋','宋诗','song-poetry','','[]','秀極武夷峰，清才氣所融。',96,'全唐诗/poet.song.10000.json','["秀極武夷峰，清才氣所融。", "香名傳日下，勝範迪時中。", "大對承三道，清篇滯半通。", "新吟池草綠，故事幕蓮紅。", "參畫文無害，沈英位未充。", "談高起廢疾，檄壯愈頭風。", "圭璧嚴書殿，房心敞帝宮。", "行頒上方筆，客特薦揚雄。"]'),
('2e882df7-045a-48e5-9f89-401ff28471e5','早秋','胡宿','宋','宋诗','song-poetry','','[]','金商纔換暑，雲葉早驚秋。',72,'全唐诗/poet.song.10000.json','["金商纔換暑，雲葉早驚秋。", "大火宵中散，清光日下浮。", "凉心遺翠簟，遠夢繞滄洲。", "蕙圃殘香薄，筠溪碧蔭稠。", "小窗聊寄傲，虛閣鎮端憂。", "带眼渾移盡，還同沈隠侯。"]'),
('fc8afcf4-0723-4958-ba94-72f87cf59169','明堂大禮','胡宿','宋','宋诗','song-poetry','','[]','路寢尊嚴配，明廷考舊圖。',120,'全唐诗/poet.song.10000.json','["路寢尊嚴配，明廷考舊圖。", "房心通氣象，太紫狀規模。", "翊衛多儀縟，齋祠至信孚。", "籩羞甘菲薄，鼎味却鮮腴。", "日月垂天象，鸞龍奮寶跗。", "樂均諧睿律，禮蕝潤宸謨。", "劍珮千官拱，梯航四海趨。", "謙恭虛小次，登降謹黄衢。", "德盛三靈格，恩流萬物蘇。", "甘泉陪法從，千載喜歌虞。"]'),
('49561316-e387-4b19-b749-c14ac9c77f35','禮畢慶成','胡宿','宋','宋诗','song-poetry','','[]','路寢凝中宇，星文直大辰。',120,'全唐诗/poet.song.10000.json','["路寢凝中宇，星文直大辰。", "總章裁往範，齋駕奉明禋。", "惟聖能嚴父，於皇重饗親。", "永懷深肅僾，昭事極精純。", "鍾律咸韶古，衣冠黼黻新。", "九金徠貢職，萬玉儼朝倫。", "夷夏觀殊禮，乾祗享至仁。", "參祠七世廟，再降六天神。", "萬寶成秋野，千祥擁禁宸。", "睿恩覃四海，壽域躋斯民。"]'),
('3dbb2909-071f-412b-9e04-df7fbaf8a381','召赴天章寶文閣觀御集賜御書飛白扇子羣玉殿錫宴','胡宿','宋','宋诗','song-poetry','','[]','阿閣藏仙籍，英輿侍睟儀。',120,'全唐诗/poet.song.10000.json','["阿閣藏仙籍，英輿侍睟儀。", "珍函開二典，聖藻煥重離。", "河洛斯文在，盤盂乃訓垂。", "寶跗親許視，瑞物遍容窺。", "白鳳隨毫舉，蒼龍應墨奇。", "好文逢漢后，觀象值庖犧。", "溢幅榮分賜，班觴曲示慈。", "柏梁晨煦洽，仙莢晝陰移。", "和樂韶音美，承平鎬酒遲。", "再陪瑶水宴，千載慶茲時。"]'),
('273461e1-f67b-47d6-8519-f788ad1d48fb','館中錫宴','胡宿','宋','宋诗','song-poetry','','[]','紫殿程書廣，鴻都校籍成。',240,'全唐诗/poet.song.10000.json','["紫殿程書廣，鴻都校籍成。", "宸心睠儒學，慈宴詔樞衡。", "供帳來金闥，臚傳下玉京。", "三山開秘宿，七閣敞修楹。", "革履趨朝暇，華貂映席明。", "弁繁星錯落，佩雜玉鏘鳴。", "爐靜飄芳蕙，圖開識禁橙。", "壺均天所酒，鼎薦帝餘羹。", "夏屋彰仁洽，衢樽樂治平。", "丹樓晨唱近，碧樹曉寒輕。", "宇內年書有，人間月就盈。", "非烟舒渥旨，愛日助皇情。", "鳬藻深歡意，魚蒲溢頌聲。", "蕭斯蒙湛湛，露彼仰英英。", "故事留東觀，崇恩自上卿。", "何言挈瓶陋，亦玷舉觴榮。", "已重高門地，還歌食野苹。", "微生徒棗鈍，弱植但葵傾。", "就日欣逢旦，瞻河喜見清。", "更期紆翠葆，千載詫登瀛。"]'),
('34188eae-3df4-436a-9fe3-a63bd0335cf9','詔祀西太一宮','胡宿','宋','宋诗','song-poetry','','[]','至道希夷內，神威造化中。',288,'全唐诗/poet.song.10000.json','["至道希夷內，神威造化中。", "行棋延羽駕，推策敞琳宮。", "秘寢觚稜峻，嚴扉坐狄雄。", "天人凝睟表，日月在方瞳。", "離坎精神集，房心氣象通。", "中黄安戊己，遥翠拱轘嵩。", "陪享衣裳盛，登羞火棗豐。", "層壇霏顥露，甲帳肅靈風。", "波靜流寒瓦，霜清入曉銅。", "廊虛鳴尺蠖，樓迥倚晴虹。", "行馬依芳樹，棲禽占碧叢。", "游光宵自燭，雕靄晝常濛。", "大壯親規近，甘泉舊典崇。", "平時闢閶闔，盡日訪崆峒。", "綵仗交輪奐，天香鬥鬰葱。", "野長迷七聖，庭闊舞千童。", "祼鬯歆惟德，笙歌悅亶聰。", "蟠螭負金石，翔鶴下絲桐。", "法度昭神祖，文章炳鉅公。", "鼎期扶更遠，山瑞委無窮。", "用九乾元正，生三太極空。", "木龍雖有寓，芻狗本無功。", "迎氣陽郊始，均禧宇縣同。", "權衡樞極右，號令斗杓東。"]'),
('9d06e734-0e9d-44ab-b902-5bc9ae692040','郊丘侍祀','胡宿','宋','宋诗','song-poetry','','[]','太極生真主，中原有聖人。',120,'全唐诗/poet.song.10000.json','["太極生真主，中原有聖人。", "圜丘尊上帝，大旅合羣神。", "行馬帷宮肅，乘龍法駕馴。", "禮容光日月，文德動星辰。", "劍履陪祠古，咸英作樂新。", "東方虛小次，午陛徹華茵。", "吉土繇誠享，高穹以道親。", "燭壇光景集，升燎福祥臻。", "寒霽三冬色，恩融四海春。", "萬靈今受記，長此奉堯仁。"]'),
('a77a07c3-6db7-4a1b-b92a-8c5e7461a0d1','奉貢殿山亭奉詔觀橙','胡宿','宋','宋诗','song-poetry','','[]','弄色金橙熟，朝元玉軑襄。',120,'全唐诗/poet.song.10000.json','["弄色金橙熟，朝元玉軑襄。", "寶奩登美實，齋蹕駐清光。", "高葉參雲碧，繁苞壓樹黄。", "鮮明當早旭，採摘有新霜。", "原廟已云薦，大家猶未嘗。", "分頒顔在咫，捧拜手盈香。", "凡果深何幸，孤根遠見將。", "五行含戊己，二水出瀟湘。", "來植清琳館，叨升白璧堂。", "更依仙掌側，日夕近芬芳。"]'),
('3c865f3b-0fa2-4be3-bc7f-cea70a7f4903','西圃櫻桃','胡宿','宋','宋诗','song-poetry','','[]','一春紅日色，刻意借鮮妍。',72,'全唐诗/poet.song.10000.json','["一春紅日色，刻意借鮮妍。", "露葉深成翳，風枝猛欲燃。", "黄金爲彈重，赤水得珠圓。", "甘實行宮薦，香名麗賦傳。", "色欺丹魄上，味出紫梨前。", "玉果誇珍實，何曾入象筵。"]'),
('802451eb-9a36-4dc5-b47c-0166230615a2','和蔡君謨閣前紫柏','胡宿','宋','宋诗','song-poetry','','[]','秀植登中禁，靈根記大方。',240,'全唐诗/poet.song.10000.json','["秀植登中禁，靈根記大方。", "纖枝乘十雨，勁節誓千霜。", "雲幹仍稠直，烟華稍鬰蒼。", "綠陰疏未合，翠鬣儼相望。", "育質從新甫，標名壓豫章。", "三休依寶構，一溉引天潢。", "瑞露通晨浥，靈風繞夜翔。", "蠹蟫驚閣爋，啼狖憶巖光。", "地惠覃行葦，人情樂樹楊。", "保無禽鹿踐，知免斧斤傷。", "遠勢興毫末，孤標出衆芳。", "寒葭寧可倚，幽草固難藏。", "庭鶴宜留側，臺烏莫近傍。", "未經鸞隠葉，不使麝居香。", "松操同凌雪，葵心共向陽。", "故情存澗壑，生意屬池隍。", "晝景斜臨石，禪機俯映堂。", "頌傳商廟桷，材入漢家梁。", "此世隆三代，何時構九房。", "瓌姿天所産，工度未應忘。"]'),
('26116f2c-2b70-4539-90e7-cc23218c65f7','後苑觀雙竹','胡宿','宋','宋诗','song-poetry','','[]','瑞植昭天産，祥枝感帝臨。',120,'全唐诗/poet.song.10000.json','["瑞植昭天産，祥枝感帝臨。", "均承元化力，同抱歲寒心。", "異稟笙簫質，全包律呂音。", "孤根皆出地，勁節約成林。", "蒙潤非烟近，含滋御水深。", "風前交吐籟，月底互翻陰。", "秋實思威鳳，春條宿綺禽。", "留觀停翠葆，託賞集華簪。", "蒼震猶乘卦，商巖近作霖。", "天支從此茂，長覆玉山岑。"]'),
('83643c34-e4fa-4cb4-9e3f-072885d52c3c','昭應宮小桃','胡宿','宋','宋诗','song-poetry','','[]','艷冶如無罪，何由謫絳宮。',72,'全唐诗/poet.song.10000.json','["艷冶如無罪，何由謫絳宮。", "不因輕阿姥，即是小仙公。", "丹臉翻啼雨，飛書却寄風。", "春溪迷柳曲，午影過牆東。", "密葉輕籠翠，繁陰半露紅。", "誰驚幽鳥散，千片觸簾櫳。"]'),
('c8a36e18-b472-4774-ab6f-df67aa3fe20a','吳興秋晚郡齋長句','胡宿','宋','宋诗','song-poetry','','[]','霽色初休雨，寒媒稍欲霜。',288,'全唐诗/poet.song.10000.json','["霽色初休雨，寒媒稍欲霜。", "崦嵫驚日晏，嵔𡾊喜年康。", "菰米迎冬熟，萍醅破社嘗。", "霅聲寄檻冷，卞色入樓蒼。", "弱援垂榴臉，幽叢亞菊芳。", "牛羊馴沃野，雁鶩悅滄浪。", "水市能爲楫，田家乞有漿。", "溪音挐競去，村語醉相將。", "自昔分天塹，茲州介水坊。", "貢絲標禹土，錯繡接吳疆。", "佳麗南朝後，鮮明茂苑旁。", "風華在安石，文物有東陽。", "柳客詩名馥，顔公筆勢翔。", "山川爲吐氣，日月欲爭光。", "異代虛墳柏，逢辰濫郡章。", "壤歌知自化，符守信非良。", "勇爵思長劍，高謨乏智囊。", "葵心拱宸極，藿食念巖廊。", "西戍方疲陝，中原久患羌。", "邊人思李牧，天子問中郎。", "臣僕今三世，腥羶彼一荒。", "山西雄占隴，河曲斗分潢。", "漢始城張掖，秦初地朔方。", "限戎深得策，遮虜大爲防。"]'),
('9695e816-f4d8-4e62-99ef-30bc70b5c384','題沃洲亭','胡宿','宋','宋诗','song-poetry','','[]','句水聲東轉，昭山勢北回。',144,'全唐诗/poet.song.10000.json','["句水聲東轉，昭山勢北回。", "三洲環白浪，一徑踏青苔。", "牖對遥岑敞，門迎別嶼開。", "鷗鷳如舊識，蘿桂是新栽。", "野氣霏霏入，川華剡剡來。", "老猿偷熟果，馴鴿下生臺。", "樵斧鳴岑寂，魚扉映曲隈。", "觀濠立莊惠，結社坐宗雷。", "格磔歸禽亂，嘔啞去櫓哀。", "看雲秋徙倚，弄月夜徘徊。", "珠且矜圓折，犀休衒辟埃。", "沃洲應祇爾，何用憶天台。"]'),
('bc62b2ba-82ba-46bc-863d-e8a3397bea7c','荷花','胡宿','宋','宋诗','song-poetry','','[]','露夕仙葩卷，風晨寶艷開。',96,'全唐诗/poet.song.10000.json','["露夕仙葩卷，風晨寶艷開。", "妖漦夏庭出，禍水漢宮來。", "玉冷埋秋骨，珠寒斂夜胎。", "河分龍浪灌，月借蕊淵栽。", "神襪能凌水，仙裾不惹埃。", "文魚纔可戲，鴆鳥莫爲媒。", "却死熬香釜，延年刻壽杯。", "息媯今不語，猶尚怨荆臺。"]'),
('962a1ed2-e6a3-49ca-84a2-3e7b6f3546d1','菁菁在中沚','胡宿','宋','宋诗','song-poetry','','[]','周雅傳遺詠，菁莪播淑聲。',72,'全唐诗/poet.song.10000.json','["周雅傳遺詠，菁莪播淑聲。", "育材方被化，在沚自敷榮。", "得地偏蒙潤，乘時並擢英。", "託根分曲渚，入學隸司成。", "行葦仁同洽，山萊詠可并。", "聖恩均雨露，挺質愧微生。"]'),
('9b90284d-52ff-4242-a4d5-365b1cc74ccf','釣臺','胡宿','宋','宋诗','song-poetry','','[]','遺魄知何許，孤風不可攀。',96,'全唐诗/poet.song.10000.json','["遺魄知何許，孤風不可攀。", "星辰歸碧落，道德寄青山。", "堯舜錙銖內，巢由爾汝間。", "草萊升御榻，韋布揖龍顔。", "圭組無由屈，烟蘿却自還。", "幾峰雲冉冉，數里水潺潺。", "孤竹清何隘，磻溪老未閒。", "獨留冰雪操，千古凜人寰。"]'),
('af399e52-d412-48c7-a3c0-058b2ace51d4','送黄孝先','胡宿','宋','宋诗','song-poetry','','[]','日下東京旅，才華變世雄。',99,'全唐诗/poet.song.10000.json','["日下東京旅，才華變世雄。", "高門真偉器，正始得遺風。", "鳴玉來江表，英聲滿洛中。", "銀鉤專墨妙，犀柄擅談叢。", "一札公車詔，千鈞矍相弓。", "卿才歸樸斫，英彀入牢籠。", "佛寺題名塔，天家奏試宮。", "鷦{冥鳥}有短羽，亦恐附鴛鴻。"]'),
('a5503f90-a78e-4e4f-83ff-cdd4b15c4bf0','送校理薛學士','胡宿','宋','宋诗','song-poetry','','[]','帝設英雄彀，朝多俊乂官。',96,'全唐诗/poet.song.10000.json','["帝設英雄彀，朝多俊乂官。", "玉羈收汗血，珠網獲飛鸞。", "仙籍分丹桂，香名藹秀蘭。", "新從平樂試，入奉柏梁歡。", "辨色趨霜戟，催班近露盤。", "閣芸開縹帙，堤柳據歸鞍。", "詩就雞林買，書成太乙觀。", "行聞延體貌，坡上有金鑾。"]'),
('10c052d7-0ec4-44d6-80b0-47e8f354dc7f','和原甫侍讀從幸後苑觀稻之什','胡宿','宋','宋诗','song-poetry','','[]','稼殿秋香熟，烟畦早景鮮。',96,'全唐诗/poet.song.10000.json','["稼殿秋香熟，烟畦早景鮮。", "玉虬乘暇日，銅雀報豐年。", "壓地黄雲重，含風寶粒堅。", "三登繄帝力，一豫俯天田。", "幸厠標章讀，仍陪從蹕宣。", "賜禾知禮厚，視草覺恩偏。", "釐席思前問，經帷惜外遷。", "妙詩深雅意，王政食爲先。"]'),
('e8501c03-14b8-443f-87d9-0d0406393617','送梅堯臣宰建德','胡宿','宋','宋诗','song-poetry','','[]','縣枕秋江側，銅章滯雋旄。',96,'全唐诗/poet.song.10000.json','["縣枕秋江側，銅章滯雋旄。", "長安去日遠，單父戴星勞。", "秀水遥通楫，嵐峰欲妒袍。", "文絃一琴古，仙舄兩鳬高。", "家樹喧朝鵲，鄉亭寂夜獒。", "土風清是楚，才意苦于騷。", "訟少停黴索，吟多費健毫。", "平時洛中社，相憶醉含桃。"]'),
('05eec3d3-c0f7-4c41-89bb-2b67aa2b0de9','送劉學士出守衡陽','胡宿','宋','宋诗','song-poetry','','[]','需奏登中掖，除書出上臺。',120,'全唐诗/poet.song.10000.json','["需奏登中掖，除書出上臺。", "獸隨朝带結，隼映使旌開。", "地接朱陵近，人從藏室來。", "蠹蟫侵舊帙，浮蟻入離杯。", "嶺勢遥連楚，星文却視魁。", "雲依蒼野住，雁隔楚峰回。", "夕夢驚湘瑟，春心託隴梅。", "南方本寬教，東里復多才。", "駟馬榮星駕，千金慶壽罍。", "未應嗟遠守，素志在循陔。"]'),
('b9162185-ae89-4437-a573-b8ef554b9937','送蘇賢良之任豫章','胡宿','宋','宋诗','song-poetry','','[]','三道膠西策，詳延俯瑞蓂。',144,'全唐诗/poet.song.10000.json','["三道膠西策，詳延俯瑞蓂。", "帝臨宣室坐，人拱太微庭。", "捷思誰加點，危言自據經。", "文成洛紙貴，詔下武泥馨。", "起草分宮筆，監州駕屏星。", "心存雲氣闕，夢繞斧文屏。", "南國標江紀，西山占地靈。", "檻泉通水府，窗戶接巖扃。", "凉月依滕閣，孤風泊孺亭。", "案書休犯慮，齋酒且忘形。", "界道宮牆紫，規蒲禁地青。", "歸來開院直，鼇頂架滄溟。"]'),
('0d42a67a-b05f-4e1b-9a8d-6cbeb58c030c','送刁總赴句容簿','胡宿','宋','宋诗','song-poetry','','[]','佳邑控江湄，春來赴牒歸。',96,'全唐诗/poet.song.10000.json','["佳邑控江湄，春來赴牒歸。", "波平雙槳渡，日上亂鶑飛。", "狎野晨耕早，蹊田晝訟稀。", "縣圖標地肺，家巷接烏衣。", "沼靜窺珍羽，樓閒數翠微。", "山香蒸䭀熟，溪蕊摘蒓肥。", "有客懷金社，因君拂玉徽。", "嵩雲南去遠，猶向柳依依。"]'),
('e14304c9-b83a-486c-8958-4052b80e8d51','送劉閱東遊','胡宿','宋','宋诗','song-poetry','','[]','臯壤乏生涯，羈遊越絕賒。',96,'全唐诗/poet.song.10000.json','["臯壤乏生涯，羈遊越絕賒。", "一區揚子宅，四壁長卿家。", "囷粟知誰指，囊錢苦自嗟。", "秋林驚脫葉，夕枕怨啼鴉。", "海月隨孤棹，天風曳落霞。", "山城饒露蔓，水驛遍霜葭。", "孝子蘭方秀，先生菊未華。", "楚轅無久滯，把酒待回車。"]'),
('683911e4-86a8-4785-8646-bb5a67dd0a6a','江城立春','胡宿','宋','宋诗','song-poetry','','[]','天上陽旛舉，人間漏箭長。',72,'全唐诗/poet.song.10000.json','["天上陽旛舉，人間漏箭長。", "稍驚池面綠，初覺柳腰黄。", "遲日延三舍，條風振百昌。", "酒凝前臘味，梅带故年芳。", "雪意思王囿，雲情憶帝鄉。", "青門行樂處，漸近好煙光。"]'),
('ebbc19cd-206b-4c77-8c10-aefa42bf6509','賞花釣魚應制','胡宿','宋','宋诗','song-poetry','','[]','平圃回天仗，昆池降帝輿。',72,'全唐诗/poet.song.10000.json','["平圃回天仗，昆池降帝輿。", "晨葩纔隠蝶，新藻復藏魚。", "露重香英濕，風長釣綫舒。", "乳鶑遷谷近，朱鮪躍淵初。", "禹律鏗金奏，堯樽遍石渠。", "乘時覃惠宴，不是樂觀魚。"]'),
('6a67f6ef-9516-4e99-aef3-51c3d8a0d882','辛夷','胡宿','宋','宋诗','song-poetry','','[]','百卉迎韶律，辛夷花最先。',96,'全唐诗/poet.song.10000.json','["百卉迎韶律，辛夷花最先。", "與春宜有舊，造物底無偏。", "棠棣先饒韡，山櫻未敢燃。", "倚風遥可愛，犯雪不勝妍。", "影亂梅花地，香迷豆蔻天。", "紅啼昨夜雨，紫妬曉來煙。", "上藥能全命，靈滋合永年。", "帝家瓊圃在，此物未應捐。"]'),
('e9b50ece-ec83-4f28-ac8e-08f7d1c47f04','館中同舍城西小飲','胡宿','宋','宋诗','song-poetry','','[]','信馬斗城西，芳郊春漸熙。',72,'全唐诗/poet.song.10000.json','["信馬斗城西，芳郊春漸熙。", "早煙銷禁樹，初溜入天池。", "桃作新正臉，梅留故臘枝。", "甕香浮蟻日，村翳浴蠶時。", "聊把今朝臂，同伸即席眉。", "徘徊惜歸馭，風晚水生漪。"]'),
('afed52b2-9b58-4d0e-846b-cb3259e1d875','講畢周禮詔賜御筵','胡宿','宋','宋诗','song-poetry','','[]','典禮惟周舊，經文在魯餘。',120,'全唐诗/poet.song.10000.json','["典禮惟周舊，經文在魯餘。", "西清開縹帙，東面授丹書。", "訪道前釐席，崇風厚石渠。", "研覃忘日旰，圖繪極霞舒。", "千載逢亨際，三冬罷講初。", "聖懷輕璧馬，慈宴樂蒲魚。", "妙技通神細，清商按曲徐。", "爐香分漢殿，鼎味出堯除。", "諸老恩同醉，孤臣藝最疏。", "至仁何以報，忠義即瓊踞。"]'),
('8c11bde6-0ca2-45e1-b24d-2e4c146707c8','丁巳歲觀玉皇冊禮','胡宿','宋','宋诗','song-poetry','','[]','寶冊尊徽號，香泥潔武都。',96,'全唐诗/poet.song.10000.json','["寶冊尊徽號，香泥潔武都。", "齋心期太乙，恭己答元符。", "玉輅嚴清制，琅函秘聖謨。", "竹宮陳帝拜，嵩極動神呼。", "彩霧霏三境，祥輝燭九區。", "況當精歲出，仍與上辛俱。", "永接千齡統，長膺五老圖。", "清編流景鑠，禮自百王無。"]'),
('e2ad82da-bcbc-4822-b870-b2e7e888dd93','溪竹','胡宿','宋','宋诗','song-poetry','','[]','可愛壇東竹，更籠清淺流。',72,'全唐诗/poet.song.10000.json','["可愛壇東竹，更籠清淺流。", "行根侵島嶼，脫籜滿汀洲。", "夜迥疑篩月，風多欲戰秋。", "紫莖同入畫，青石伴垂鉤。", "葉裏藏雌翠，陰中下戲鷗。", "秦松無用笑，千畝更封侯。"]'),
('da7edd22-c985-44da-8206-17e8d075f933','憶東園','胡宿','宋','宋诗','song-poetry','','[]','越鳥戀南柯，春來怨別多。',24,'全唐诗/poet.song.10000.json','["越鳥戀南柯，春來怨別多。", "冷風如可御，爭奈簡書何。"]'),
('ab1dbb5d-ceaf-4af1-9688-8e737df6eeb8','橫山','胡宿','宋','宋诗','song-poetry','','[]','此地橫青嶂，當年動紫氛。',24,'全唐诗/poet.song.10000.json','["此地橫青嶂，當年動紫氛。", "將軍精爽在，可解勒遺文。"]'),
('2cc162b1-c569-4f88-a03d-9edea0f827e9','漫成','胡宿','宋','宋诗','song-poetry','','[]','日醉風酣百卉開，錦韉爭躍大堤來。',32,'全唐诗/poet.song.10000.json','["日醉風酣百卉開，錦韉爭躍大堤來。", "城東有客歌盆久，不敢將春上老臺。"]'),
