('ef748699-1620-4808-a3dd-5daec54e5943','夫人閤端午帖子  其五','胡宿','宋','宋诗','song-poetry','','[]','廣殿回雕輦，滄池漾綵舟。',24,'全唐诗/poet.song.10000.json','["廣殿回雕輦，滄池漾綵舟。", "堯心順時令，不是重嬉遊。"]'),
('b71166cf-997e-42d8-a4f2-d8890443ce5f','夫人閤端午帖子  其六','胡宿','宋','宋诗','song-poetry','','[]','魚龍曼衍夸宮戲，湘虙浮沈衒水嬉。',32,'全唐诗/poet.song.10000.json','["魚龍曼衍夸宮戲，湘虙浮沈衒水嬉。", "齊上聖皇千萬壽，飄然仙樂在瑶池。"]'),
('342641be-2ca4-45ed-978a-31f95b7620b6','夫人閤端午帖子  其七','胡宿','宋','宋诗','song-poetry','','[]','故事順時羞角黍，舊儀乘節浴蘭湯。',32,'全唐诗/poet.song.10000.json','["故事順時羞角黍，舊儀乘節浴蘭湯。", "人間凉麥欣時豫，天上薰風愛日長。"]'),
('e1dd9bd6-26c6-4505-9b9b-ad4cd5c3de55','夫人閤端午帖子  其八','胡宿','宋','宋诗','song-poetry','','[]','續命由來宜綵縷，辟邪相向佩靈符。',32,'全唐诗/poet.song.10000.json','["續命由來宜綵縷，辟邪相向佩靈符。", "夏鈞調樂長生酒，歲歲宮中祝聖圖。"]'),
('52af1db8-a71a-443f-8281-cdc0f4744b51','夫人閤端午帖子  其九','胡宿','宋','宋诗','song-poetry','','[]','宮中應節垂金縷，天上迎祥捧玉巵。',32,'全唐诗/poet.song.10000.json','["宮中應節垂金縷，天上迎祥捧玉巵。", "更奏開元羽衣曲，年年長願侍瑶池。"]'),
('41fb4603-e74d-44a0-832a-9554793a4b5b','夫人閤端午帖子  其一○','胡宿','宋','宋诗','song-poetry','','[]','彩艾相傳禳故氣，香茅競愛結靈芳。',32,'全唐诗/poet.song.10000.json','["彩艾相傳禳故氣，香茅競愛結靈芳。", "炎洲正覺仙遊盛，化國偏知日景長。"]'),
('952e7cd6-3062-46c2-a487-860d42b5ff12','挽莊懿皇太后詞  其一','胡宿','宋','宋诗','song-poetry','','[]','仙李含芳遠，菖華席慶殊。',48,'全唐诗/poet.song.10000.json','["仙李含芳遠，菖華席慶殊。", "俔天周作合，夢日漢爲符。", "宮祲生長信，山光卜鮒鰅。", "寶臺泉底路，千古凝金鳬。"]'),
('1521963b-edba-47b9-a5b9-fdc323c95479','挽莊懿皇太后詞  其二','胡宿','宋','宋诗','song-poetry','','[]','愍冊追榮極，攢宮改卜良。',48,'全唐诗/poet.song.10000.json','["愍冊追榮極，攢宮改卜良。", "玉衣秋自冷，銀海夜偏長。", "浪隔三山藥，香空九子堂。", "雲陵西望遠，嵩樹鬰蒼蒼。"]'),
('ff7ab70b-4b57-49e4-a074-0869bcb1c911','挽仁宗皇帝詞  其一','胡宿','宋','宋诗','song-poetry','','[]','上主乘炎曆，真人握寶符。',48,'全唐诗/poet.song.10000.json','["上主乘炎曆，真人握寶符。", "垂衣臨太極，脫屣厭中區。", "議上尊仁號，傳歸大聖圖。", "陵宮葬冠劍，萬國共號呼。"]'),
('7eee981c-428b-4b14-a1de-05b8089076cd','挽仁宗皇帝詞  其二','胡宿','宋','宋诗','song-poetry','','[]','帝者因山葬，天王下度悲。',48,'全唐诗/poet.song.10000.json','["帝者因山葬，天王下度悲。", "壽原三聖接，神駕萬靈馳。", "怨入笳簫曲，威陳劍舄儀。", "空留人馬迹，不復到瑶池。"]'),
('a73d435b-8b1b-4bc1-894c-f8b90fd1f159','挽仁宗皇帝詞  其三','胡宿','宋','宋诗','song-poetry','','[]','七月朝同軌，千齡訖此辰。',48,'全唐诗/poet.song.10000.json','["七月朝同軌，千齡訖此辰。", "霜華清禁仗，雲氣護靈輴。", "鳳篆驚遺札，龍顔感舊真。", "更思羣玉宴，血淚灑孤臣。"]'),
('33536915-264d-459a-9c23-dc4b7cb49a38','挽仁宗皇帝詞  其四','胡宿','宋','宋诗','song-poetry','','[]','淵默無爲化，聰文上叡才。',48,'全唐诗/poet.song.10000.json','["淵默無爲化，聰文上叡才。", "休兵藏武庫，躋俗集春臺。", "忽歎祇宮沒，真成杞國哀。", "徒傳方士說，奇藥在蓬萊。"]'),
('0865623f-787a-44ad-831b-ff509e61bb07','挽仁宗皇帝詞  其五','胡宿','宋','宋诗','song-poetry','','[]','曾是陪華幄，居常奉景輿。',48,'全唐诗/poet.song.10000.json','["曾是陪華幄，居常奉景輿。", "邇英參訪道，阿閣待觀書。", "聖學知風自，神毫拂霧餘。", "那知柏梁宴，便到哭宮車。"]'),
('c6f98e17-2de1-4dd2-80bd-5cfd5f98da43','挽英宗皇帝詞  其一','胡宿','宋','宋诗','song-poetry','','[]','神器傳歸重，時龍來久乘。',48,'全唐诗/poet.song.10000.json','["神器傳歸重，時龍來久乘。", "告成遺玉檢，請代爽金縢。", "同軌遵周制，因山卜漢陵。", "臨朝常願治，天意邈難凴。"]'),
('26b4a11e-cee4-4b6b-89d2-9f5e6961df91','挽英宗皇帝詞  其二','胡宿','宋','宋诗','song-poetry','','[]','順斗臨天下，乘雲厭世間。',48,'全唐诗/poet.song.10000.json','["順斗臨天下，乘雲厭世間。", "異香消甲帳，奇藥隔仙山。", "神策良難問，訾黄不可攀。", "西流終古恨，伊洛共潺潺。"]'),
('01cbd7b5-5d22-4ae6-844e-01d141914970','挽溫成皇后詞  其一','胡宿','宋','宋诗','song-poetry','','[]','彤管留遺範，霓旌逼上仙。',48,'全唐诗/poet.song.10000.json','["彤管留遺範，霓旌逼上仙。", "地傷瑶水後，人哭樂池邊。", "采翟行將駕，斑龍跼未前。", "真軿不可問，知在幾重天。"]'),
('2f6810b7-b935-4289-87d3-310db7d95554','挽溫成皇后詞  其二','胡宿','宋','宋诗','song-poetry','','[]','氛祲生層掖，神華返上清。',48,'全唐诗/poet.song.10000.json','["氛祲生層掖，神華返上清。", "禮成金璽重，仙去玉衣輕。", "楚挽悲芳甸，凝笳怨碧城。", "宸心懷輔佐，儀典極哀榮。"]'),
('9bd4782b-5434-4a1f-8e4e-d236507fd1ea','挽莊惠皇太后詞  其一','胡宿','宋','宋诗','song-poetry','','[]','早護珠庭質，曾參玉几遺。',48,'全唐诗/poet.song.10000.json','["早護珠庭質，曾參玉几遺。", "寶琮榮冊號，華榜盛宮儀。", "天上霓軒去，人間黼帳移。", "聖情同舜慕，寒日慘雲旗。"]'),
('4bcc124e-69d0-49c1-a981-b35c33dd45ef','挽莊惠皇太后詞  其二','胡宿','宋','宋诗','song-poetry','','[]','曉引禁城西，凝笳怨不歸。',48,'全唐诗/poet.song.10000.json','["曉引禁城西，凝笳怨不歸。", "月消三讓魄，劫盡六銖衣。", "鞏樹寒無色，嵩雲慘欲霏。", "濯龍門外路，車馬更依依。"]'),
('f6db1b66-86e9-4831-978b-929648f2d9c8','寄會稽張待制','胡宿','宋','宋诗','song-poetry','','[]','長安廄吏躍花驄，竹馬遥分浙水東。',64,'全唐诗/poet.song.10000.json','["長安廄吏躍花驄，竹馬遥分浙水東。", "遠勢早推賢相子，任誠真有古人風。", "稽山一鎮居封內，阿閣三休聳禁中。", "不及臨滄陪置酒，憶君千里寄書筒。"]'),
('e9ebfc1b-84ec-4880-90e3-b2281196da99','與周元明遊南園','胡宿','宋','宋诗','song-poetry','','[]','一遍芳菲欲滿林，回塘過雨曉來深。',64,'全唐诗/poet.song.10000.json','["一遍芳菲欲滿林，回塘過雨曉來深。", "紅妝珠珮交花影，白馬春衫度柳陰。", "向老追攀多强意，隨時風物但驚心。", "眼前百事輸年少，猶解因君放浪吟。"]'),
('88c05452-9117-476e-b2a3-5ea530d62a81','滄浪亭','胡宿','宋','宋诗','song-poetry','','[]','竄逐本無罪，羈窮向此忘。',48,'全唐诗/poet.song.10000.json','["竄逐本無罪，羈窮向此忘。", "野煙含悵望，落日滿滄浪。", "亂草荒來綠，幽蘭死亦香。", "楚魂招不得，秋色似瀟湘。"]'),
('2eb31d9a-070c-4245-960a-5794d906df10','秀峰寺','胡宿','宋','宋诗','song-poetry','','[]','宿枕依鄉館，天機斗覺清。',48,'全唐诗/poet.song.10000.json','["宿枕依鄉館，天機斗覺清。", "一聞山鳥語，瞥起野麋情。", "峭木摇霜氣，疏泉曳玉聲。", "簡書催俗駕，窗日兩竿明。"]'),
('68955623-adf6-459c-850b-887e4e69ecc6','寄蘇臺知府蔣密學','胡宿','宋','宋诗','song-poetry','','[]','清德臨藩第二回，東南時望滯鹽梅。',64,'全唐诗/poet.song.10000.json','["清德臨藩第二回，東南時望滯鹽梅。", "武林間歲移星座，溫樹多年直斗魁。", "楚客江山供逸思，吳王風月屬高才。", "空傳宴寢凝香句，文酒無因得仰陪。"]'),
('810a35d1-34a2-49a0-8bf9-230bfa813e63','寄子美學士','胡宿','宋','宋诗','song-poetry','','[]','臯橋羈旅有梁鴻，洛下嚶嚶信未通。',64,'全唐诗/poet.song.10000.json','["臯橋羈旅有梁鴻，洛下嚶嚶信未通。", "金谷輕爲年少客，滄浪翻作主人翁。", "山川勝氣生吟次，風月高情寄飲中。", "身外不須論得喪，儻來軒冕古今同。"]'),
('d9a7fa2f-8767-4f17-bb48-a9c87ff3cd1c','送太守晏大夫','胡宿','宋','宋诗','song-poetry','','[]','畫角城頭向晚悲，鄧侯歸旆已臨歧。',64,'全唐诗/poet.song.10000.json','["畫角城頭向晚悲，鄧侯歸旆已臨歧。", "西郊祖帳傾簪紱，南國離聲動管絲。", "千里去思歌邵父，三年遺愛泣吳兒。", "甘棠寂寞江邊路，正是清陰蔽芾時。"]'),
('4019a9a1-4607-42c5-94cf-e427ab1666b5','田舍','胡宿','宋','宋诗','song-poetry','','[]','農家秋物成，腰鐮刈新穀。',48,'全唐诗/poet.song.10000.json','["農家秋物成，腰鐮刈新穀。", "得食鷄豚肥，飽霜梨栗熟。", "牧童唱田歌，孺子宰社肉。", "野老醉亦謳，愛此羲皇俗。"]'),
('41e0812d-709f-48f8-bcd0-e748d8bd2a00','感懷','胡宿','宋','宋诗','song-poetry','','[]','高秋感憀慄，中夜起盤桓。',84,'全唐诗/poet.song.10000.json','["高秋感憀慄，中夜起盤桓。", "啼螿思月底，哀鴻查雲端。", "遺蜩尚號節，初鵙早催寒。", "新霜霑客鬢，凄風入人肝。", "拂枕了無寐，取琴不能彈。", "壯圖成齟齬，老淚空汍瀾。", "逢辰今匪易，行志古良難。"]'),
('8f07f1d5-7825-4903-b263-57c86fb74b64','張公洞','胡宿','宋','宋诗','song-poetry','','[]','一室是仙鄉，深巖石燕翔。',48,'全唐诗/poet.song.10000.json','["一室是仙鄉，深巖石燕翔。", "隔雲青瑟轉，拂水紫芝香。", "滴露驚神冷，靈襟徹頂凉。", "浮雲應不遠，衣袂好相將。"]'),
('78db6ef5-bf05-4120-97a4-cdcbca0af61e','酬杭州知府蔣密學以移漕見贈之什','胡宿','宋','宋诗','song-poetry','','[]','雕章傳贈至蘇臺，盥手焚香日幾回。',64,'全唐诗/poet.song.10000.json','["雕章傳贈至蘇臺，盥手焚香日幾回。", "玉札已叨三錫命，瑶華兼枉二南才。", "清明花卉迎前發，紫翠湖山滿望來。", "曾是絳紗爲弟子，故時經帙許重陪。"]'),
('5e9a7039-82b6-4ef6-8554-e086867728fa','覽海東相公伊川集','胡宿','宋','宋诗','song-poetry','','[]','將相文章主籥臣，風流曾冠玉堂人。',64,'全唐诗/poet.song.10000.json','["將相文章主籥臣，風流曾冠玉堂人。", "夢回方丈停批鳳，句就伊川止獲麟。", "洛下勝遊空綠野，郢中高調絕陽春。", "猶欣正始遺音在，三復能還舊觀神。"]'),
('3750d7f4-7e25-46e7-b0a5-68dd1971dd05','句  其一','胡宿','宋','宋诗','song-poetry','','[]','風花飛有態，烟絮墜無痕。',12,'全唐诗/poet.song.10000.json','["風花飛有態，烟絮墜無痕。"]'),
('f66ff94f-7e48-449f-9aff-c267b4064605','句  其二','胡宿','宋','宋诗','song-poetry','','[]','點筆乍驚蟾滴漬，□□□□□漿寒。',16,'全唐诗/poet.song.10000.json','["點筆乍驚蟾滴漬，□□□□□漿寒。"]'),
