('f9ee3d51-f787-4c32-9d46-060caa570e6f','句  其四','胡宿','宋','宋诗','song-poetry','','[]','雨別荆臺夢，風迴越水樵。',12,'全唐诗/poet.song.10000.json','["雨別荆臺夢，風迴越水樵。"]'),
('9c5d5c44-4d6c-4ade-87a2-6123c0cb51c4','句  其五','胡宿','宋','宋诗','song-poetry','','[]','青女偷飛一夜霜。',8,'全唐诗/poet.song.10000.json','["青女偷飛一夜霜。"]'),
('5786ce52-c2c7-4d8f-896e-7fb357977395','句  其六','胡宿','宋','宋诗','song-poetry','','[]','武林天下奇，巽亭境中絕。',12,'全唐诗/poet.song.10000.json','["武林天下奇，巽亭境中絕。"]'),
('0cc9a217-e47c-4e63-ba76-81aa738f0f36','秋日白鷺亭向夕有感','王琪','宋','宋诗','song-poetry','','[]','白鷺敞西軒，檐宇窮爽塏。',168,'全唐诗/poet.song.10000.json','["白鷺敞西軒，檐宇窮爽塏。", "千峰若連環，翠色不可解。", "是時天宇曠，六幕無纖靄。", "金斗熨秋江，素練橫衣带。", "乾坤清且歛，氣象朝昏改。", "蘆花作雪風，飛舞來滄海。", "九霄汀鷺起，萬里檣烏快。", "月上三山頭，鳥沒橫塘外。", "蒼茫洲渚寥，錯落星斗大。", "開尊屏絲竹，披襟向蕭籟。", "余生本江湖，偃蹇欣所會。", "清興雖自廢，苦嗜亦吾累。", "魚龍憑夜濤，四面忽滂湃。", "安得燃犀燈，煌煌發水怪。"]'),
('3be1e2b5-080e-438a-a999-c329065b85df','詠玉蕊花','王琪','宋','宋诗','song-poetry','','[]','玉蕊生禁林，地崇姿亦貴。',72,'全唐诗/poet.song.10000.json','["玉蕊生禁林，地崇姿亦貴。", "散漫陰谷中，蓬茨復何異。", "清芬信幽遠，素彩非妖麗。", "蒼煙蔽山日，瓊瑶爲之晦。", "歲久自扶疏，岩深愈凝邃。", "請觀唐相吟，俗眼無輕視。"]'),
('819e2a6c-69b9-4ff4-8211-e602a940e772','九曲池','王琪','宋','宋诗','song-poetry','','[]','越調隋家曲，當年亦九成。',48,'全唐诗/poet.song.10000.json','["越調隋家曲，當年亦九成。", "哀音已亡國，廢詔尚留名。", "儀鳳終沉影，鳴蛙祇沸聲。", "凄凉不可問，落日背蕪城。"]'),
('40cade8a-b4c0-4164-9d00-9ffc4a6b280f','金陵賞心亭','王琪','宋','宋诗','song-poetry','','[]','千里秦淮在玉壺，江山清麗壯吳都。',64,'全唐诗/poet.song.10000.json','["千里秦淮在玉壺，江山清麗壯吳都。", "昔人已化遼天鶴，舊畫難尋卧雪圖。", "冉冉流年去京國，蕭蕭華髮老江湖。", "殘蟬不會登臨意，又噪西風入座隅。"]'),
('53e35384-8f38-4b02-a4b6-2fa36a3fe54d','吳中曉寒曲','王琪','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','大澤穹天莽同色，碧瓦閶門曉花白。',128,'全唐诗/poet.song.10000.json','["大澤穹天莽同色，碧瓦閶門曉花白。", "石岩左右斷行人，洞庭一夜冰千尺。", "曾持漢節單于壘，北風如刀割人耳。", "知憐凍足苦雙摧，一生不向遐方履。", "憑誰贈我紫衣裘，中吳風土清且柔。", "令嚴氣正天地肅，長歌白苧臨寒流。", "玉蘭酒熟金醅溢，太白連雲尚殊□。", "書窗半掩晝始開，幾日紅梅斷消息。"]'),
('85b5e4bf-1e86-4d7c-af59-361e97dde761','清輝殿觀唐明皇山水石字歌','王琪','宋','宋诗','song-poetry','','[]','皇家四葉恢聖功，天臨日燭清華戎。',192,'全唐诗/poet.song.10000.json','["皇家四葉恢聖功，天臨日燭清華戎。", "漢條靜治洽柔教，老心稽古開神聰。", "有唐英主稱好文，仙毫灑落驅風雲。", "壯哉山水有奇字，煥乎八法存翠珉。", "自從棄置咸陽道，蘚駁煙滋委宮草。", "天開神贊會休辰，甄收再作皇居寶。", "如何淪棄三百春，迎逢睿鑒來紫宸。", "奎鉤粲粲光華動，羣玉森森氣象新。", "丹籞春妍瑞靄深，文梁藻棟結芳林。", "鴻翔鳳翥徑方丈，杯流泉湧蒙親臨。", "鯫臣榮幸從金輿，鉤婉魂驚拭目初。", "多慚攬筆非清藻，唯慶千齡際帝圖。"]'),
('d0460f3d-53ed-459c-9653-ad2546ea575c','無弦琴','王琪','宋','宋诗','song-poetry','','[]','寂寞之淳音，其爲樂至深。',24,'全唐诗/poet.song.10000.json','["寂寞之淳音，其爲樂至深。", "應嫌鼓腹者，獨自撫弦琴。"]'),
('d02b6293-119b-4486-9e73-00c187d8594a','答永叔問','王琪','宋','宋诗','song-poetry','','[]','班班疏雨寒無定，皎皎圓蟾望欲闌。',32,'全唐诗/poet.song.10000.json','["班班疏雨寒無定，皎皎圓蟾望欲闌。", "應在浮雲儘深處，更憑絲竹一催看。"]'),
('2e1c2701-79e6-4732-b799-ea7216085530','紅梅','王琪','宋','宋诗','song-poetry','','[]','館娃宮裏舊精神，粉瘦瓊寒露蕊新。',32,'全唐诗/poet.song.10000.json','["館娃宮裏舊精神，粉瘦瓊寒露蕊新。", "園吏無端偷折去，鳳城從此有雙身。"]'),
('2aac62fc-c4c6-4cc2-9cb0-f547dfd4ac6f','送安公歸頂山瑞石菴','王琪','宋','宋诗','song-poetry','','[]','談空一紀餘，重出訪巖居。',48,'全唐诗/poet.song.10000.json','["談空一紀餘，重出訪巖居。", "身是汾陽嗣，囊惟郭璞書。", "公侯倒屣後，泉石結茆初。", "山頂收榛栗，經秋信莫疏。"]'),
('fde74cf0-9fe7-4ec2-855f-39389eebb718','垂虹亭','王琪','宋','宋诗','song-poetry','','[]','紅橋跨浪二千尺，橋上危亭在水心。',32,'全唐诗/poet.song.10000.json','["紅橋跨浪二千尺，橋上危亭在水心。", "六月火雲燒萬里，夜來風細似秋深。"]'),
('58cee796-baec-4d85-b63e-4fa684af1cd1','題招隠寺','王琪','宋','宋诗','song-poetry','','[]','蒼崖何蟠回，嘗爲隠君宅。',72,'全唐诗/poet.song.10000.json','["蒼崖何蟠回，嘗爲隠君宅。", "孰謂人琴亡，松風正蕭瑟。", "花閑雪英舞，鹿去巖泉冽。", "經聲草堂迥，天香中夜發。", "月落山氣深，清猿嘯亦絕。", "如何人外迹，輕爲世網別。"]'),
('245360c7-4c93-484b-a12c-a0b613f21ad8','絕句  其一','王琪','宋','宋诗','song-poetry','','[]','香溪春老誤尋芳，只有愁雲映夕陽。',32,'全唐诗/poet.song.10000.json','["香溪春老誤尋芳，只有愁雲映夕陽。", "今日重來已如此，何須更問海生桑。"]'),
('7de317bc-45b8-43ae-8569-aa537593e820','絕句  其二','王琪','宋','宋诗','song-poetry','','[]','正月初弦二月賒，小園春事已如麻。',32,'全唐诗/poet.song.10000.json','["正月初弦二月賒，小園春事已如麻。", "强誇力健因移石，不減公忙爲種花。"]'),
('6c38be56-1cb3-42ac-a50d-57965630f341','暮春游小園','王琪','宋','宋诗','song-poetry','','[]','一叢梅粉褪殘妝，塗抹新紅上海棠。',32,'全唐诗/poet.song.10000.json','["一叢梅粉褪殘妝，塗抹新紅上海棠。", "開到荼䕷花事了，絲絲天棘出莓牆。"]'),
('5b2ea1f0-7643-4af8-8521-ebeee296c40a','句  其一','王琪','宋','宋诗','song-poetry','','[]','春風吹孤雲。',6,'全唐诗/poet.song.10000.json','["春風吹孤雲。"]'),
