('8be37e3a-9191-4880-b1c0-465f95cfba9b','到州有感呈通判','周洙','宋','宋诗','song-poetry','','[]','白雲深處雙輪過，紅旆叢中五馬來。',48,'全唐诗/poet.song.10000.json','["白雲深處雙輪過，紅旆叢中五馬來。", "父子華顛忻會聚，簪裾青眼喜遊陪。", "趨庭日有朱衣戲，從此無心詫老萊。"]'),
('629be825-6924-476c-a077-8f5bf013a94f','句','周洙','宋','宋诗','song-poetry','','[]','憑君點數西南景，枕上觀山有幾州。',16,'全唐诗/poet.song.10000.json','["憑君點數西南景，枕上觀山有幾州。"]'),
('2085b08f-a2a3-400a-81c8-c717f48bc311','句','王益','宋','宋诗','song-poetry','','[]','不逢星漢使，誰識是靈槎。',12,'全唐诗/poet.song.10000.json','["不逢星漢使，誰識是靈槎。"]'),
('04e4bcc7-86dd-49b8-a852-b2c03bea3397','題天章寺','孫沔','宋','宋诗','song-poetry','','[]','茂林脩竹碧谿頭，梵宇深沈鎖翠幬。',32,'全唐诗/poet.song.10000.json','["茂林脩竹碧谿頭，梵宇深沈鎖翠幬。", "從此崇山頻企望，朝陽高處有松楸。"]'),
('0a597eef-ed97-4fce-9959-33e99f6db8c4','題子陵釣臺  其一','孫沔','宋','宋诗','song-poetry','','[]','舊交爲帝不能邀，百尺雙臺照暮濤。',64,'全唐诗/poet.song.10000.json','["舊交爲帝不能邀，百尺雙臺照暮濤。", "逸迹已將山共永，清名仍與月爭高。", "魯連解難終辭祿，龍伯持傾只釣鼇。", "列傳古碑言未盡，一灘風竹自蕭騷。"]'),
('d1fcb4d4-c756-418d-927d-b77c92901a98','題子陵釣臺  其二','孫沔','宋','宋诗','song-poetry','','[]','中興曾作故人看，抗節唯憐七里灘。',64,'全唐诗/poet.song.10000.json','["中興曾作故人看，抗節唯憐七里灘。", "枯枿卧沙疑野艇，叢篁生岸憶長竿。", "天邊舊迹星辰動，江上餘基水石寒。", "應笑渭濱周呂望，白頭因獵從和鑾。"]'),
('6f986c4a-5876-47cf-81bc-0fa7c2b0f08b','酬答王仲儀龍圖','孫沔','宋','宋诗','song-poetry','','[]','海東霜隼品仍多，萬里秋天數刻過。',64,'全唐诗/poet.song.10000.json','["海東霜隼品仍多，萬里秋天數刻過。", "狡兔積年安茂草，弋人終日望滄波。", "青鵁獨擊歸林麓，皁頰羣飛入網羅。", "爲謝文登賢太守，求方逐惡意如何。"]'),
('7faec6a8-fc15-4ac6-a157-59c6dd9de6e2','句','孫沔','宋','宋诗','song-poetry','','[]','新治甬上居，閑逸安暮齒。',12,'全唐诗/poet.song.10000.json','["新治甬上居，閑逸安暮齒。"]'),
('1b5a42f0-a5d9-4b12-9920-d377fc37973d','南園','周元明','宋','宋诗','song-poetry','','[]','熳爛花時錦繡張，無端下馬繫垂楊。',32,'全唐诗/poet.song.10000.json','["熳爛花時錦繡張，無端下馬繫垂楊。", "山亭水閣笙歌地，合與行人作醉鄉。"]'),
('ced066f5-a8d7-419c-ad2c-25fb00d2d7a6','送程給事知越州','李柬之','宋','宋诗','song-poetry','','[]','文行學曾顔，才名孰可攀。',48,'全唐诗/poet.song.10000.json','["文行學曾顔，才名孰可攀。", "仁風清郡國，和氣滿江山。", "暫抑提雄漕，行當簉近班。", "須知攬轡暇，大智養閑閑。"]'),
('2bf0d5df-41cf-4644-a914-857ff29869b3','句  其一','李柬之','宋','宋诗','song-poetry','','[]','莫教獨欠赤松遊。',8,'全唐诗/poet.song.10000.json','["莫教獨欠赤松遊。"]'),
('dd963df7-c8c0-4818-800a-0fe40af7781c','句  其二','李柬之','宋','宋诗','song-poetry','','[]','下客拋官獨自回。',8,'全唐诗/poet.song.10000.json','["下客拋官獨自回。"]'),
('79a4593b-fda0-431d-8955-5c7011699774','老蘇先生挽詞  其一','趙概','宋','宋诗','song-poetry','','[]','稱味欒城舊，潜光谷口棲。',48,'全唐诗/poet.song.10000.json','["稱味欒城舊，潜光谷口棲。", "雄文聯組繡，高論吐虹霓。", "遽忽悲丹旐，無因祀碧雞。", "徒嗟太丘德，位不至公圭。"]'),
('95c5ed23-37ce-46dc-8255-a9d69916a545','老蘇先生挽詞  其二','趙概','宋','宋诗','song-poetry','','[]','侍從推詞伯，君王問子虛。',48,'全唐诗/poet.song.10000.json','["侍從推詞伯，君王問子虛。", "早通金匱學，晚就曲臺書。", "露泣時難駐，琴亡韵亦疏。", "臧孫知有後，里閈待高車。"]'),
('18c6a8c8-3d24-4119-854b-b59ae91eeeed','送梵才大師歸天台','趙概','宋','宋诗','song-poetry','','[]','建剎存真意，崇臺表大因。',48,'全唐诗/poet.song.10000.json','["建剎存真意，崇臺表大因。", "中藏般若偈，外護赤城神。", "花雨長霏晝，松風自掃塵。", "媿心同范寧，蓮社阻相親。"]'),
('fb811971-d48f-4266-8231-13732e75fe3e','來燕堂聯句','趙概','宋','宋诗','song-poetry','','[]','賢侯謝郡歸，從遊樂吾黨。',240,'全唐诗/poet.song.10000.json','["賢侯謝郡歸，從遊樂吾黨。", "林泉富餘地，卜築疏陳莽。", "是時春正中，來燕音下上。", "若賀大厦成，喜留衆賓賞。", "得名因笑談，揮墨粲題榜。", "所夸賢豪盛，豈止池榭廣。", "人心樂且閒，鳥意頡而頏。", "吟罇敞花軒，醉枕酣風幌。", "輕雲薄藻棟，初日麗珠網。", "紅袂生暗香，清弦泛餘響。", "林深隠飛蓋，岸曲遲去槳。", "波光欄檻明，竹氣衣巾爽。", "虛容凉樾入，影與文漣蕩。", "晨飈轉綠蕙，夕雨滋膏壤。", "嘉辰喜盍朋，命駕期屢往。", "觴詠陶淑真，世俗豈吾倣。", "得以爲勝遊，蕭然散煩想。", "公子固好士，世德復可像。", "今此大基構，不圖專奉養。", "美哉風流存，來葉足師仰。"]'),
('d4e5914a-461f-4169-b47c-93b1007e71af','句','趙概','宋','宋诗','song-poetry','','[]','滁水西偏郡，豐山北際樓。',12,'全唐诗/poet.song.10000.json','["滁水西偏郡，豐山北際樓。"]'),
('51458b50-f5a8-46fb-820b-180bda9c6614','廩江','詹先野','宋','宋诗','song-poetry','','[]','武夷溪九曲，曲曲可垂鈎。',24,'全唐诗/poet.song.10000.json','["武夷溪九曲，曲曲可垂鈎。", "自得溪山樂，何須公與侯。"]'),
('accf7314-59a1-4e3b-9f61-18ac8177598d','正月望夕供養大阿羅漢畫像作','宋庠','宋','宋诗','song-poetry','','[]','端月戒熙陽，望舒秀圓極。',108,'全唐诗/poet.song.10000.json','["端月戒熙陽，望舒秀圓極。", "洗心乘佳節，瞻像洗慈德。", "穆穆屋漏尊，虛堂與神寂。", "繪境紛自奇，法性非所得。", "人貌含天虛，彷彿若真覿。", "示現隨三界，精感超六識。", "華燈列清場，寶炷熏梵席。", "妙意隨春融，疑懷逐冰釋。", "欲讚已忘言，拳拳自終夕。"]'),
('4b287534-33ed-417f-aabc-63c6c372fa14','嘯臺','宋庠','宋','宋诗','song-poetry','','[]','孤壁橫天畿，巋然袤尋丈。',276,'全唐诗/poet.song.10000.json','["孤壁橫天畿，巋然袤尋丈。", "恭承晉高士，嘗此攄遐想。", "臨風挹勝軌，意若無今曩。", "當塗昔戰龍，典午方搆象。", "忠賢履危運，鱗羽嬰密網。", "烈烈熾邦刑，耽耽翦人望。", "嵇呂膏碪斧，濤舒受羈鞅。", "先生機且神，妙用包羣枉。", "兀爾謝將迎，隤然寄昏放。", "禮法雖我讎，智恬非外奬。", "惻愴廣武游，留連步兵釀。", "朅來桑梓國，憑高念長往。", "舒嘯萬籟先，浮精九皇上。", "歸禽宛頸還，秣駟臨芻仰。", "當日天地心，寥寥共悲壯。", "咄嗟涉千祀，隠軫存遺壤。", "臨岸知是非，俎豆猶彷像。", "我來一傾耳，城隅斷餘響。", "梟鶚愁空林，狐狸語平莽。", "高韵邈已徂，清銘復誰賞。", "嘗聞史氏傳，塗窮輒怊悵。", "正人與直轡，何代非流蕩。", "淳風日已微，投辭謝精爽。"]'),
('d7126d65-cf90-4079-b23d-e774ef33810c','入謁馬上作','宋庠','宋','宋诗','song-poetry','','[]','殘月鼕鼓喧，中衢幰輪鶩。',156,'全唐诗/poet.song.10000.json','["殘月鼕鼓喧，中衢幰輪鶩。", "九關忽洞闢，萬蓋黕雲布。", "燭亂建章星，塵迷華陰霧。", "車幅避鳴騶，鑾音聽朝御。", "嗟予亦何爲，簉此珍羣羽。", "野鶴載軒愁，狂狙裹衣怒。", "肅穆未央朝，蹣跚壽陵步。", "人生固有志，躁靜各成趣。", "生當伏農畎，乃爾汙賢路。", "峨弁束蓬顛，吞腥滿饑嗉。", "樂育過阿陵，增裨乏塵露。", "徒懷一割志，但恐流芳暮。", "且復竢逡巡，南山有場圃。"]'),
('428b3a2f-9260-47a4-ba07-b9b3c4b58ddc','習彥威','宋庠','宋','宋诗','song-poetry','','[]','四海習彥威，英英出江漢。',96,'全唐诗/poet.song.10000.json','["四海習彥威，英英出江漢。", "高韵凌風翔，雕文奪星爛。", "感激陽秋辭，姦雄非所憚。", "蜀弱自爲正，曹强乃名亂。", "陰忤柄臣意，飄然去恩館。", "驅車自北門，四顧興長歎。", "終焉謝病免，猶得爲人半。", "緬矣身後名，臨風寄悽惋。"]'),
('751404d1-5ce8-4599-b2b3-ca5896fbfd00','有邑子夜宿話余先疇蕪廢','宋庠','宋','宋诗','song-poetry','','[]','臨邛久倦客，彭澤賦歸來。',120,'全唐诗/poet.song.10000.json','["臨邛久倦客，彭澤賦歸來。", "念我何爲者，趣時良殆哉。", "一身仕東觀，三載寄靈臺。", "望見故鄉樹，頻更緹管灰。", "曉車愁蹇蹇，春耜負莓莓。", "虛名自韁鎖，豐壤成汙萊。", "目想社枌老，心知門柳摧。", "神阡迷馬鬣，柏表被狸災。", "一聞里人語，夜靜成多懷。", "他日還燕泣，前憂成誤哀。"]'),
('cff0b200-1273-490f-919b-310d3e0b4024','留別知郡職方楊員外','宋庠','宋','宋诗','song-poetry','','[]','予本草茅士，世無鐘鼎榮。',288,'全唐诗/poet.song.10000.json','["予本草茅士，世無鐘鼎榮。", "在昔未勝冠，先疇弓冶傾。", "茹荼濱十死，屬纊存微生。", "分遂甯牛飯，誰希莊雁鳴。", "龍具泣妻子，練裙悲弟兄。", "慈誨斷軻織，遺書開晏楹。", "感激侏儒飽，呻吟裘氏聲。", "下武纂丕構，協風翔四瀛。", "紛馳賁丘帛，高豎當衢旌。", "鸞翮不暇戢，驥材方自呈。", "車徒首燕路，冠蓋溢秦京。", "文章趙元叔，脣舌婁君卿。", "列邸曳裙入，羣公交幣迎。", "僕嘗不自料，奮迹希時英。", "弟子許都養，詞人嗤老傖。", "一旦褐衣召，千慙昆玉名。", "安知軾蛙賤，但覺軒鴻輕。", "初命六百石，關掌列侯城。", "居然懵操决，無術裨澄清。", "天炎屢來集，冤獄紛以盈。", "誚讓使臺檄，流離民屋征。", "結課諒無最，黜幽茲有萌。", "晚遘金閨彥，傳瑞提千兵。", "爲僚篤古義，賞善多新評。"]'),
('e6099ff4-2f40-40bf-9de4-c2d454468492','獻臣學士與余通書因成感詠','宋庠','宋','宋诗','song-poetry','','[]','夫君班揚儔，抱槧羣玉府。',180,'全唐诗/poet.song.10000.json','["夫君班揚儔，抱槧羣玉府。", "久讀未見書，躬抽繫年譜。", "墜緒獲先秦，亡篇出東魯。", "上泝三皇墳，旁探百家語。", "怪牒汲郡來，幽經茂陵聚。", "英哲資繕藏，緹油盡刊補。", "蒸青勁竹殘，削誤規刀苦。", "種別踰九流，星羅軼千部。", "顧我寡見聞，蒙薰異倫伍。", "祕帙樂共披，譌文許交舉。", "家㨭互紛綸，郵谿戲旁午。", "初無班嗣嗤，更免許慈拒。", "矧余羈官久，寂寞繄茅宇。", "禮乏贈酒瓻，疑增照觴怒。", "尚頼啟新編，時時發聾瞽。"]'),
('4097b5d1-ff9e-4431-800f-b732055efb65','左散騎常侍東海徐公','宋庠','宋','宋诗','song-poetry','','[]','徐公真丈夫，不獨文章伯。',144,'全唐诗/poet.song.10000.json','["徐公真丈夫，不獨文章伯。", "江南兵未解，主憂臣慘戚。", "公願紓其難，苦求使上國。", "庶獲一言伸，少息苞茅責。", "其君驚且歎，執手涕沾臆。", "謂言知爾晚，何此忠義激。", "天子叱在殿，誚讓雷霆赫。", "公亦從容對，曾不渝神色。", "仁者必有勇，斯亦古遺直。", "書大略其小，我有春秋癖。", "所以此詩中，不言公翰墨。", "庶警事君心，勉旃希令德。"]'),
('a20a055a-96f5-4c8f-8b5f-81503dbe7f35','夏日晚出芙蓉堂','宋庠','宋','宋诗','song-poetry','','[]','哲匠昔締構，文榱面清池。',168,'全唐诗/poet.song.10000.json','["哲匠昔締構，文榱面清池。", "回環水光合，左右雲容披。", "蒼烟限壘斷，空碧盈軒垂。", "蕙綠不待染，荷圓皆中規。", "戲魚觸新藻，幽鷺翹空坻。", "初筍半遺籜，殘跗猶抱枝。", "我來冰未泮，倏此亙炎曦。", "節物一以換，余懷焉獨怡。", "內慚固陋質，本乏廊廟姿。", "印綬紛璀錯，旌旄森陸離。", "林狙裹華黻，野鹿駭金羈。", "負山力已竭，傾日心空疲。", "知此危殆辱，斯言非我欺。", "橫琴不成調，慷慨念歸期。"]'),
('1aa57402-64e6-4560-99e7-d9206d33a8a1','秋晚禁廬獨坐','宋庠','宋','宋诗','song-poetry','','[]','霜日薄西牖，境寂趣自閒。',72,'全唐诗/poet.song.10000.json','["霜日薄西牖，境寂趣自閒。", "風篁宿天籟，海碧沈雲山。", "宮樹未全落，棲烏相與還。", "心疑蹈虛宇，跡乃塵清班。", "自顧丘壑志，何施軒冕顔。", "終當謝緋服，戢翼榆枋間。"]'),
('b13dbc55-ccec-47fb-b3d4-c004779844d5','孔明','宋庠','宋','宋诗','song-poetry','','[]','漢家亂無象，賢才戢鱗翼。',120,'全唐诗/poet.song.10000.json','["漢家亂無象，賢才戢鱗翼。", "武侯霸王器，隆中事耕殖。", "堂堂劉豫州，介紹徐元直。", "一聞卧龍譽，三駕荒廬側。", "士爲知己用，陳辭薄霄極。", "說吳若轉丸，抗魏猶卷席。", "談笑馭關張，從容羈梁益。", "持邦二紀餘，君臣絕纖隙。", "浮埃蔽穹壤，大節淪金石。", "梁甫不復聞，懷賢涕霑臆。"]'),
('1b9ed0d3-fdfc-4631-bf7e-962d3f290e67','筠亭','宋庠','宋','宋诗','song-poetry','','[]','歲晚檀欒姿，山中映孤宇。',36,'全唐诗/poet.song.10000.json','["歲晚檀欒姿，山中映孤宇。", "聲繁天籟吟，影動仙幢舞。", "即境是真如，黄花間幽圃。"]'),
('ed3be7b0-3d6c-4cf6-82d7-e9cd439fb6a8','嘗假馬于親舊不獲因感而成詠','宋庠','宋','宋诗','song-poetry','','[]','東方昔借車，尼父嘗假蓋。',96,'全唐诗/poet.song.10000.json','["東方昔借車，尼父嘗假蓋。", "一馬茲不全，夷涂出如閡。", "人無托乘寵，朝罕均茵載。", "策足本乏謀，臨風嗟有待。", "京洛富華廄，權奇出青海。", "翩翩陌上郎，滅沒爭星邁。", "珂音雜鸞響，韉勢動霞綵。", "東郭獨何爲，徒行履將敗。"]'),
('fa16278f-b2a3-49a1-92e5-c7f0b6734fdb','穀城主簿王崇者少得養生禪寂之道中年棄官入漢陰武當之間邈與世絕又有吳人山者自遠携母與王同隠時余方貧病慨然慕之因爲詩代書以寄二子且托王尋耕釣之地相與邇者竝以敘懷云','宋庠','宋','宋诗','song-poetry','','[]','余本丘壑人，失計蹈塵網。',240,'全唐诗/poet.song.10000.json','["余本丘壑人，失計蹈塵網。", "軒冕忽韁鎖，風波若流蕩。", "高羽顛宏羅，奔驂僨歸鞅。", "衆僞緣境滋，千憂共身長。", "進乏汗馬勞，居畏濡鵜賞。", "力命頻遘迍，幽憂思獨往。", "聞君集漢陰，遁世久忘象。", "因溜爲鳴琴，憑巖作煙幌。", "復有延陵季，亦善南趎養。", "築宇近親仁，耕田或歌壤。", "且言掛瓢處，一徑捫蘿上。", "杳若御風遊，蕭蕭骨毛爽。", "芝朮紛異苗，麏鼯結幽響。", "老木森千尋，丹藤垂百丈。", "洞谷答嘯歌，雲霞代鄰黨。", "咨予倦遊者，緬邈期真賞。", "之子幸我憐，試煩翦幽莽。", "儻獲蝸牛居，即謝海禽饗。", "時從漁父魚，聊植仙人杖。", "漸脫區中緣，永託無生奬。"]'),
('5b6275c6-bc29-4c55-a7bc-8f9d39dfa0b3','和答李學士見寄長韵','宋庠','宋','宋诗','song-poetry','','[]','璇源多清派，蘭谷無絕芳。',216,'全唐诗/poet.song.10000.json','["璇源多清派，蘭谷無絕芳。", "之子相門裔，高才映周行。", "妙年弄文史，雅志含圭璋。", "中歲困官簿，銖兩爭低昂。", "一通金閨籍，荏苒潘鬢霜。", "剖符屢麾阮，執戟更疲揚。", "聞君近多暇，歸偃三經堂。", "左右褫紳組，縱橫羅巾箱。", "安驅仁義塗，弭節名聲場。", "戰酣道始勝，心泰無癯尪。", "壯思挾飛藻，詔我臨霞章。", "我時坐鈴閣，寂寞如禪房。", "開緘一快讀，雋味腴且長。", "高義溢句流，清風隨篇翔。", "感人不無意，在水河湯湯。", "吾匪辯音者，空冀懷仁藏。", "矧屬歲躔暮，百卉皆芸黄。", "何以謝君子，松柏同蒼蒼。"]'),
('d36d08cf-ff3f-4186-beb9-ecb67c3e0d8e','和答吳充學士見寄長韵','宋庠','宋','宋诗','song-poetry','','[]','多士秀王國，珍羣鶩天衢。',168,'全唐诗/poet.song.10000.json','["多士秀王國，珍羣鶩天衢。", "其間延陵季，煜煜承華跗。", "盛藻班蔡流，芳年終賈徒。", "籤芸擁石室，札綈紛鴻都。", "刊僞富清暇，壯思彌天隅。", "投我塵外什，粲然風義俱。", "幽襟恣申詠，不覺頹陽烏。", "渴吻潄仙液，饑腸涵道腴。", "衰翁牽夙尚，騷雅嘗馳驅。", "疲足道雖頓，流波心未渝。", "過門輒大嚼，臨博猶狂呼。", "詎云獲真賞，聊復愜所娛。", "矧繄絕唱贈，無脛來明珠。", "報之乏瓊玖，寶玩徒區區。"]'),
('258d4f75-3920-4b4c-ae9d-0b5a200f46a0','歲晚許昌城隅登樓作','宋庠','宋','宋诗','song-poetry','','[]','孤城何巑岏，西北有層構。',120,'全唐诗/poet.song.10000.json','["孤城何巑岏，西北有層構。", "我來一長眺，正迫歲陰候。", "嚴風挫萬物，霜雪復交寇。", "冬日苦易頹，羲車劇馳驟。", "宵月不相讓，空弦映矢彀。", "潦收陂面闊，木落山骨瘦。", "生平丘壑心，顧慕獨延脰。", "箕峰紫氛結，潁瀨瓊波潄。", "想像逃名夫，幽居翳仙竇。", "願言追遐蹤，人間謝譏詬。"]'),
('a2d8d242-bbb1-4aa1-bb7f-6e9e353756a2','天禧初僑寓安陸有宅一區嘗于齋前手植橘樹纔尺餘許未幾擢第隨牒遊方天聖庚午冬屏居畿邑守舍兒自安陸饋余丹橘一篋因曰此即齋前所植撫物懷舊悽然不平者久之因成感詠','宋庠','宋','宋诗','song-poetry','','[]','昔年封蘗栽，生意頗柔脆。',120,'全唐诗/poet.song.10000.json','["昔年封蘗栽，生意頗柔脆。", "今茲見丹實，落落如星麗。", "斯果號難成，常踰豫章歲。", "孤根何爲者，尚記吾廬地。", "蔽芾詎因棠，連蜷乃同桂。", "厥包千里遥，守舍重緹惠。", "金顆照病眸，霜津益痟肺。", "却算去里年，十聽秋鴻唳。", "無復陸績懷，寧圖李衡計。", "他時攀樹悲，詎減金城涕。"]'),
('6392e668-81ed-451f-9c96-7fb22d41590e','歲晏出沐感事內訟一首','宋庠','宋','宋诗','song-poetry','','[]','山海有完士，希世無良籌。',264,'全唐诗/poet.song.10000.json','["山海有完士，希世無良籌。", "偶穿東郭履，遂別野人舟。", "不恥篆刻賦，來肩英俊游。", "私智甚鳬短，塵容若鴟愁。", "備員太史氏，補屬富民侯。", "姑學了官事，何嘗分主憂。", "日貪斗食利，歲感星躔周。", "中都富才彥，方駕若龍虯。", "茂先善史漢，平津治春秋。", "高文用司馬，格五寵虞丘。", "間闊路逢葛，繽紛人召鄒。", "桑羊興賈豎，安國出縲囚。", "汲鄭貴交盛，徐陳英藻遒。", "況乃天下樞，雄雌來九州。", "衣冠徑複道，鼓吹出長楸。", "席上萬錢箸，橋邊八列騶。", "雍容緩魯玦，意氣拂吳鉤。", "咨予良不韙，瓴甓厠珠璆。", "吹竽昔已濫，在梁今可尤。", "臺閣魏舒被，風霜蘇季裘。", "有志謝軒鶴，無機防海鷗。", "恭竢杜陵課，誅茅歸故疇。"]'),
('ed157806-10d4-4fe5-98d7-8ee44b3d2189','送上元勾簿吳昌卿','宋庠','宋','宋诗','song-poetry','','[]','長安鼕鼓喧，里舍隙塵曉。',264,'全唐诗/poet.song.10000.json','["長安鼕鼓喧，里舍隙塵曉。", "有客駐歌驪，歸途指江徼。", "晨庖爨蘇冷，窮巷鄉輿少。", "乃肯顧我廬，歡言復悲嘯。", "悲嘯誠易知，夫君韵經奇。", "才高洛陽賈，賦動楚湘纍。", "平昔應賢詔，覽德揚英蕤。", "孚尹傾寶肆，沛艾絡仙羈。", "獻書北闕下，對策東堂垂。", "逢吉旦兼暮，諧音塤且箎。", "天官選初筮，黄綬聊藏器。", "三釜樂及親，尺檄甘爲吏。", "邇來預冬集，再調鬰奇意。", "羣公亟爲言，力命乃相戾。", "奏牘輒報聞，官書責勤蒞。", "簿領百里佐，風煙六朝地。", "銷魂南浦行，拄頰西山氣。", "君子永來譽，勝襟無累欷。", "行矣勿載譁，鄉枌方省家。", "春橈碎溪月，曉帆弄江霞。", "長洲紛藉草，故樹雜生花。", "予心若爲處，歲晏竚疏麻。"]'),
('f2623dfd-8997-45e3-9947-8aff8359d078','京師故僚以余退居近畿數賜存問因敘懷自感','宋庠','宋','宋诗','song-poetry','','[]','病餘頗厭肉，欣得僧廬蔬。',96,'全唐诗/poet.song.10000.json','["病餘頗厭肉，欣得僧廬蔬。", "僧窗亦明潔，可以觀我書。", "弟兄冷相對，因著柏酒醉。", "酹餘欲拈筆，狀乃爾狼狽。", "我老固有素，未至形苶具。", "其事故可知，寧復論年數。", "阿連吾語汝，我計當何取。", "學道既無成，何如事農圃。"]'),
('77049deb-84eb-4356-959e-513876e9dfb8','冬至攝事南郊齋宮感懷作','宋庠','宋','宋诗','song-poetry','','[]','履至謹冬祀，攝職叨上公。',180,'全唐诗/poet.song.10000.json','["履至謹冬祀，攝職叨上公。", "洗心奉明誡，祗宿城南宮。", "芳歲正遒莫，熙陽殊未融。", "西郊淡頹景，北牖來朔風。", "騖野騁歸獸，緣雲號征鴻。", "夕坐無晤言，情條結深衷。", "自撫韋布陋，奚堪廊廟崇。", "觀瞻動衆目，跼蹐愁我躬。", "自古經緯才，因勢猶汙隆。", "夔禹值虞奮，孔墨遭周窮。", "如何一介士，蔑著橫草功。", "仰被天宇施，遂濟人爵豐。", "較能劣涓𡏖，荷寵踰華嵩。", "物理自非是，神鑒安可蒙。", "區區謝病志，終冀回天聰。"]'),
('89a2d6d8-e851-4db1-8eb5-b452d8c2862a','念衰二首  其一','宋庠','宋','宋诗','song-poetry','','[]','勁風吹北林，落葉舞南牖。',96,'全唐诗/poet.song.10000.json','["勁風吹北林，落葉舞南牖。", "歲序忽已高，崢嶸薄星斗。", "大化驅羣物，始終迭相授。", "羲和亦何爲，挾日但西走。", "少壯馳目前，衰頹躡人後。", "星星兩霜鬢，伴我老成醜。", "學道苦嗟晚，捫心更餘咎。", "茲意將奈何，投身就杯酒。"]'),
('a95483ff-5eb2-4fe5-b4bd-8f72d7eb7d21','念衰二首  其二','宋庠','宋','宋诗','song-poetry','','[]','衰容覽青銅，寒光了無隠。',144,'全唐诗/poet.song.10000.json','["衰容覽青銅，寒光了無隠。", "照我顛上毛，星星罕餘鬒。", "持此將奈何，歲月屢遒盡。", "少壯罕聞道，下士乃爲哂。", "操綆遽汲深，持矛復夸楯。", "任重力疾顛，塗窮計方窘。", "上孤明主恩，下違昔賢準。", "憂悔從中來，老至非無眹。", "尚忝麾守尊，居慚政條敏。", "孤心企寒柏，萬境付朝菌。", "往失奚足追，來戒或堪引。", "明發丘壑情，予將治歸軫。"]'),
('21f4b122-a74b-4f26-bf9d-65ae1c05f0e9','湖山','宋庠','宋','宋诗','song-poetry','','[]','空水渺澄鮮，蒼山復盤踞。',36,'全唐诗/poet.song.10000.json','["空水渺澄鮮，蒼山復盤踞。", "沙草媚苔磯，雲柯抱巖樹。", "畸人茲與留，脫世如遺屨。"]'),
('aabad642-f67d-4771-852d-37dbc141ca86','登大明寺塔','宋庠','宋','宋诗','song-poetry','','[]','故歲摇落時，憑高望揚越。',240,'全唐诗/poet.song.10000.json','["故歲摇落時，憑高望揚越。", "流光不我與，復此值凋節。", "孤塔踞層岡，仙盤湧㵳泬。", "病足攀危梯，寸晷或三歇。", "浩蕩佛界寬，凌兢客心折。", "遠岫幾培塿，空江一明滅。", "海日棲簷題，霜風語鈴舌。", "荒墟自今古，大塊靡封埒。", "豁若醯覆開，醒如豆聰撤。", "哀哉人間世，小智互紛結。", "豕蝨論是非，蠻蝸定雄傑。", "倀倀百代俗，唧唧九流說。", "推致無窮中，秋毫共飄瞥。", "聖人小天下，樂意遺來哲。", "矧余蒙鄙姿，輕蹈榮利轍。", "溷濁六塵并，讙呶太和泄。", "薄言真境游，追悟生理缺。", "洗心刻來誓，回步懲曩跌。", "甘露多餘滋，聖關有幽鐍。", "咄嗟朝市人，此路非爾躡。"]'),
('24283e94-23b0-42d7-9178-721335ca5fde','哭公實學士','宋庠','宋','宋诗','song-poetry','','[]','高子北方士，才爲國之華。',240,'全唐诗/poet.song.10000.json','["高子北方士，才爲國之華。", "靈襟絕塵藻，麗藻紛春葩。", "雖云服韁鎖，高意籠青霞。", "子昔久蒙潤，逢辰亨乃嘉。", "聯飛奉臺閣，相顧引龜緺。", "鮑叔不予怯，楚臣寧汝瑕。", "詔書頻出沐，歸轡屢回車。", "時過蔣生徑，或詣子雲家。", "柏將松竝悅，人與室非遐。", "自謂百年分，風期何所嗟。", "君命良不淑，浮生茲有涯。", "沈疴犯霜露，幽讖發龍蛇。", "美志一朝盡，餘哀千古賒。", "招魂知是否，生肘詎真耶。", "塗斤失郢匠，膝席夭長沙。", "青黄飾溝木，藩褥墜風花。", "世事一以謬，何言定隆窊。", "都門執謳紼，原路引哀笳。", "夕雲旌外慘，春日塚頭斜。", "自此掩瑶軫，其誰知伯牙。"]'),
('54e24e8e-89e9-4624-863c-27e66071f760','壬子歲四月甲申夜紀夢','宋庠','宋','宋诗','song-poetry','','[]','積雨暗長夜，山行經險巇。',156,'全唐诗/poet.song.10000.json','["積雨暗長夜，山行經險巇。", "悲風撼林木，崖谷蔽參差。", "遠聞豺虎號，鬼燐弄光輝。", "十步九失足，中心祗自持。", "所適既迢遞，黽勉焉可爲。", "道旁見明燭，抵宿依茅茨。", "開戶念生客，喜逢主翁慈。", "暖湯趣妻子，然薪爲更衣。", "艱難又奚怨，少息非所期。", "雞鳴夜將旦，熟寐百無知。", "欣戚一以忘，何有安與危。", "生死宇宙內，曠懷亦如斯。", "聊紀夢中事，誰當賡我詩。"]'),
('748f61a5-d22d-4896-87f0-e18a1b59fb6c','過曹氏墳庵在灊皖間蜀僧修靜自天柱退居于此','宋庠','宋','宋诗','song-poetry','','[]','出郭屏僕從，取徑問樵牧。',120,'全唐诗/poet.song.10000.json','["出郭屏僕從，取徑問樵牧。", "短松新被岡，青嶂遠遮屋。", "雞犬無四鄰，日月自兩轂。", "阿師厭機緣，脫迹謝塵俗。", "是心大圓明，一室了具足。", "汲泉烹細芽，支鐺炊脫粟。", "默坐契從三，諸方付藏六。", "我來同友生，得飽徑眠熟。", "稍爲微風醒，已歎畏景促。", "買山知幾時，所惜負松菊。"]'),
('5384ac44-9fdd-43e0-899e-6147c192f104','水月','宋庠','宋','宋诗','song-poetry','','[]','湖上纖羅收，天邊夕蟾映。',36,'全唐诗/poet.song.10000.json','["湖上纖羅收，天邊夕蟾映。", "皎潔銀界寬，虛明佛心定。", "可愛不可持，乾坤共孤影。"]'),
('c7f1bc1b-74d1-4e87-8457-f19f1e42b698','余卧病畿邑御史王君假守潭楚道出于舍下特見存訪且尋先子之舊欽承風儀因爲詩抒感云','宋庠','宋','宋诗','song-poetry','','[]','病客卧窮里，衡扉掩殘春。',288,'全唐诗/poet.song.10000.json','["病客卧窮里，衡扉掩殘春。", "隳官道家藏，竄跡農廛民。", "朝羅噪饑雀，暮席流芳塵。", "尸居怳踰歲，踵息動彌旬。", "忽訝絳鞲隸，傳呼越郊畛。", "蹀躞千餘騎，雍容兩朱輪。", "言是楚邦守，來過安邑貧。", "固宜辨貴棄，乃爾存艱辛。", "此道古爲重，餘風今已淪。", "物色認平素，載言接慇懃。", "始悟先子舊，早篤嘗僚親。", "孤心極摧櫓，感涕浩盈巾。", "追念舞勺歲，已識棲鸞人。", "師筵奉函席，學舍操書筠。", "童牙自忘醜，詩鉢或娛賓。", "公時摛句賞，謂是天麒麟。", "親擘彩牋贈，勉我期日新。", "汝南丏題品，有道定人倫。", "自爾一暌剌，中年嬰世紛。", "天聖紹休緒，頓網橫無垠。", "鸞鵠不藏翼，虯蝸無遁鱗。", "余時濫隗始，驤首摩蒼旻。", "司徒揖元叔，天子第平津。", "甲科廷尉屬，再命宮坊臣。"]'),
('230caaf3-c97a-4cbb-be24-0a571c4aecc5','去年三月禊飲池上歲月易得忽復暮春因再宴僚屬作','宋庠','宋','宋诗','song-poetry','','[]','前茲屬元巳，置酒蒼烟臺。',204,'全唐诗/poet.song.10000.json','["前茲屬元巳，置酒蒼烟臺。", "芳序忽復周，春風正徘徊。", "懽言速僚友，亟使具觥盃。", "長渠溢芳溜，列坐浮香來。", "靈囂合衆樂，隠若南山雷。", "舞袂紛雜襲，賓冠儼崔嵬。", "美人前爲壽，顔色如瓊瑰。", "況我千萬日，行樂無疑猜。", "新歌裊天衢，興視行雲回。", "我時語四座，茲賞誠難哉。", "妙顔無再朱，白髮惟相催。", "跖蹻盈聖智，孔顔罹憂摧。", "區區百世後，美惡同塵灰。", "吾欲挈瑶斗，踞海爲金罍。", "挹茲忘憂物，與爾同嘲諧。", "天地爲一朝，長短何足哀。", "魯陽久不作，白日任西頹。"]'),
('1694f3c9-4f49-4c31-96c2-d15653836992','奉詔止雨宿齋建隆觀','宋庠','宋','宋诗','song-poetry','','[]','漢家候神館，奉詔穰沈災。',144,'全唐诗/poet.song.10000.json','["漢家候神館，奉詔穰沈災。", "解纓就齋幕，恍若躋蓬萊。", "雲羅絓朝舄，露掌承仙杯。", "衆真拱象帝，寶宇正崔嵬。", "爐烟薰太虛，重陰爲之開。", "單枕不成寐，俗魂自驚猜。", "心迷坐忘術，萬慮無根來。", "天雞殊未鳴，霜雁有餘哀。", "借問麋鹿姿，云胡塵國台。", "構極謝隆棟，裨山劣纖埃。", "上慚稷契名，下愧丙魏才。", "惟餘止足戒，臨路空徘徊。"]'),
('ac0548c8-37b0-44de-948f-f6a5f4f1136a','念古','宋庠','宋','宋诗','song-poetry','','[]','賢哉邴曼容，出處知所據。',156,'全唐诗/poet.song.10000.json','["賢哉邴曼容，出處知所據。", "官餘六百石，輒自移疾去。", "富貴非不懷，殆辱亦先慮。", "嗟我材下中，叨恩最蕃庶。", "堯庭納言職，軒野方明御。", "服衮作槐班，曳履南宮署。", "雖經斥免誚，尚玷高華處。", "徒有守直弦，何能借前箸。", "愚甘六馬對，讒恨三物詛。", "年來感衰疾，倦鳥思返翥。", "抗心望先哲，俯首慚昔譽。", "西景尚可收，歸轅未云遽。", "儻以人望人，期君或吾恕。"]'),
('a8dfdc82-dfa2-4963-853e-58bd96b66a7b','己巳歲除夜有感','宋庠','宋','宋诗','song-poetry','','[]','明晦互推斥，中都芳歲闌。',216,'全唐诗/poet.song.10000.json','["明晦互推斥，中都芳歲闌。", "星迴迫舊次，籥暖送餘寒。", "來辰繭有緒，去境環無端。", "天運故相易，人心那獨安。", "懷此不能寐，攬衣强盤桓。", "疏恐緩餘带，危惕整塵冠。", "耿耿燭焰直，凄凄霜氣酸。", "城頭隕高木，庭下敗叢蘭。", "撫臆累新欷，掩觴沈故懽。", "况乃蹈世網，虛名爭控摶。", "挾冊濫書府，振纓玷王官。", "東序羅圭瑞，西雍集鵷鸞。", "昏瞳眩寶肆，短翼厠仙翰。", "縱爾值藏疾，何容久素餐。", "泛泛騷客鳬，坎坎詩人檀。", "寧無要路津，所畏在蹣跚。", "枳棘附驥尾，緯蕭戲龍蟠。", "寄語拙艱者，無竢學邯鄲。"]'),
('cc61dfe2-b63f-4ebf-8b6a-5f7c0e47b602','王粲','宋庠','宋','宋诗','song-poetry','','[]','秦川貴公子，避地來荆州。',96,'全唐诗/poet.song.10000.json','["秦川貴公子，避地來荆州。", "流離世道喪，簡脫天姿遒。", "歲時不我與，假日賦銷憂。", "妍辭縟非霧，逸韵鏘鳴球。", "曹師下南服，置酒臨滄洲。", "慷慨前爲壽，高譚王霸籌。", "歸來奉丞相，攝組登華輈。", "獨步今已矣，空餘清漢流。"]'),
('cc2747d2-5c83-4019-888d-867f92361ad9','漢將三首  其一','宋庠','宋','宋诗','song-poetry','','[]','漢家開絕域，日夕羽書聞。',72,'全唐诗/poet.song.10000.json','["漢家開絕域，日夕羽書聞。", "朝那殺都尉，北地敗將軍。", "沙明疑晝雪，氣黑似秋雲。", "片月就城偃，長蛇隨陣分。", "冰藏馬窟路，血沫劍星文。", "直置鴻毛命，聊圖麟閣勳。"]'),
('5a0e517f-03a4-4d16-a112-944a7c03487a','漢將三首  其二','宋庠','宋','宋诗','song-poetry','','[]','頻年隨校尉，晚節事輕車。',72,'全唐诗/poet.song.10000.json','["頻年隨校尉，晚節事輕車。", "瞻烽數奔命，辭第詎爲家。", "輕齎絕瀚海，間道襲昆邪。", "雙鞬朝負羽，三鼜夜鳴笳。", "金痍先雨覺，蓬鬢後霜華。", "如何差六級，遽使抱長嗟。"]'),
('03f04c99-2192-4ee1-ae2f-6caaee306ca8','漢將三首  其三','宋庠','宋','宋诗','song-poetry','','[]','薄伐乃中謀，和親非上策。',96,'全唐诗/poet.song.10000.json','["薄伐乃中謀，和親非上策。", "匈奴負漢恩，男兒喜邊檄。", "故歲出定襄，今年救張掖。", "沙平落日黄，月迥遥峰白。", "急擊右地兵，連俘月支馘。", "幕府省文書，家人非尺籍。", "夜拔五嶺旗，晨追六騾迹。", "陛下焚謗書，孤臣勒燕石。"]'),
('fe8cba0b-c21f-4b23-92c6-6b968df6963c','雨夜秋興示仲氏子京','宋庠','宋','宋诗','song-poetry','','[]','秋律盪華序，濃雲生夕陰。',240,'全唐诗/poet.song.10000.json','["秋律盪華序，濃雲生夕陰。", "羣芳伴雨泣，百竅隨風吟。", "衰螢滅遥徑，倦翼翔故林。", "暗隙濕已逗，孤燈青欲沈。", "愁人此遥夜，萬慮集幽衿。", "歡緒未盈尺，憂端已越尋。", "借問所以然，出處謬素心。", "家世本丘壑，才具非璆琳。", "靈根夙已殞，野服良所欽。", "搴芝幽澗畔，擉鱉故溪潯。", "擉爾濫官牒，今焉旅華簪。", "兄弟見羈鞅，交朋頼幽箴。", "爾講壞壁簡，我攀羣玉岑。", "嚴枚交逸藻，潘陸嗣清音。", "羣才方搆厦，短綆徒汲深。", "狂迷頓纓鹿，踉蹌乘軒禽。", "歸來翳編翟，況乃貫愁霖。", "求薪動踰桂，鬻賦靡酬金。", "原病固爲累，朔饑非所任。", "猶欣共姜被，歲宴樂愔愔。"]'),
('0c459c2e-5e6f-4b3f-a07b-02519c6d7b79','寄題職方周員外廬山笑臺','宋庠','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','周郎有舊隠，遠在南山陲。',168,'全唐诗/poet.song.10000.json','["周郎有舊隠，遠在南山陲。", "一笑偶爲樂，九層遂成基。", "旁連醉令石，却眺社僧碑。", "地遠雲物秀，巖深松桂滋。", "當時騖高興，益友相攀追。", "樂聖自鼓腹，談經亦軒眉。", "風猿助清嘯，谷鳥參朋嬉。", "忽引朝閨籍，久乖林下期。", "頭白二千石，高蓋復來思。", "活活弄新溜，蒼蒼援故枝。", "雖云未投紱，良足紓煩疲。", "余懷本丘壑，世路方馽羈。", "願言獨往客，緬邈心空馳。", "稅駕或未晚，從君歌紫芝。"]'),
('37a5f3d5-8629-4ce8-ab09-58c0dba5115f','歲暮北亭懷子京宛丘二首  其一','宋庠','宋','宋诗','song-poetry','','[]','歲晏坐孤壁，心馳千里餘。',48,'全唐诗/poet.song.10000.json','["歲晏坐孤壁，心馳千里餘。", "何言共被樂，方歎專城居。", "野闊江海漫，風高天地虛。", "願言逐歸鳥，無翼將焉如。"]'),
('372fccce-5ab9-47b7-b915-ded793f3dfb5','歲暮北亭懷子京宛丘二首  其二','宋庠','宋','宋诗','song-poetry','','[]','摇落江都城，風塵宛丘道。',48,'全唐诗/poet.song.10000.json','["摇落江都城，風塵宛丘道。", "天涯遥相望，離思何草草。", "迴澤騰麏䴥，滄洲叫鳬鴇。", "星歲日云徂，在原歎方浩。"]'),
('93df7dc6-7b68-43b6-b66b-affe03f8677b','游山簡習池','宋庠','宋','宋诗','song-poetry','','[]','昔日白接䍦，時時詣諸習。',48,'全唐诗/poet.song.10000.json','["昔日白接䍦，時時詣諸習。", "累榭今已頹，清池尚堪挹。", "遥源乳竇響，敗防流沙急。", "況復蘭蕙時，幽香遠相襲。"]'),
('8bc532fd-402f-4e2a-bda6-ff2b0369116c','魚梁','宋庠','宋','宋诗','song-poetry','','[]','八月霜潦收，江槎絕烟渚。',48,'全唐诗/poet.song.10000.json','["八月霜潦收，江槎絕烟渚。", "竹落如網裁，淵鱗劇雲聚。", "鷖鳥爭食飛，兒童荷叉語。", "去乙鯿項肥，吳羹免轑釜。"]'),
('a1b02ca5-5b47-4320-9d99-003e005696c6','正月望夜聞影燈之盛齋中孤坐因寫所懷','宋庠','宋','宋诗','song-poetry','','[]','漢家太一昏祠日，寶炬神燈徧京室。',192,'全唐诗/poet.song.10000.json','["漢家太一昏祠日，寶炬神燈徧京室。", "仁壽先從殿裏開，纖阿正傍樓前出。", "傳聞陌上樂康年，寶騎如龍人若仙。", "驂驔始見斗城曲，爛熳還逢星漢邊。", "妍歌巧笑競賡續，萬狀晶熒奪人目。", "洛橋羅韈自生塵，楚國香纓不藏燭。", "五侯四姓共豪華，況乃經過趙李家。", "迷路非關武陵水，添妝祗爲壽陽花。", "九門啟鑰光如晝，若箇游人不回首。", "春宵病客獨無悰，挾冊焚香坐虛牖。", "坐久更闌可奈何，著書自古窮愁多。", "鐘磬笙竽盡鄰里，誰能載酒來相過。"]'),
('0f2fbbb9-5563-4f09-9175-d4286852d929','吳侍郎生朝','宋庠','宋','宋诗','song-poetry','','[]','朝端舊記生賢日，使節臨門恩有秩。',160,'全唐诗/poet.song.10000.json','["朝端舊記生賢日，使節臨門恩有秩。", "詔書感會形溫辭，宴品豐華動私室。", "降崧孕昴誠不誣，史簡詩絃互褒述。", "賢人挹道隨汙隆，忽向西臺就安逸。", "門弧紀旦還復周，瑞霰連天芳歲遒。", "塤音箎曲會中坐，蘭叢玉樹來西州。", "稱觴獻壽私庭裏，別得人生行樂意。", "貳官禮樂春闈卿，托蹟逍遥漆園吏。", "病尹論交情最深，因聲附祝成孤吟。", "願將明哲保身智，遺我摧頹知止心。"]'),
('59fb526c-7848-47c1-b651-2f4e4131482d','玉宸殿竝三枝牡丹歌','宋庠','宋','宋诗','song-poetry','','[]','中天帝圃蕃英蕤，氤氳嘉祥凝朝曦。',128,'全唐诗/poet.song.10000.json','["中天帝圃蕃英蕤，氤氳嘉祥凝朝曦。", "竹間芳種易封殖，疊萼三葩同茂枝。", "慶雲景宿共靈意，鴻英託寓茲爲美。", "華夷面內始竝柯，慈孝歡心遂聯蘤。", "雲旂羽葆駐天臨，玩此能無悅聖心。", "幽香自逐德馨遠，麗色更緣眉彩深。", "因生軼草兼平露，薦祉神庭幸同侶。", "盛開已被帝琴風，縱落猶成佛天雨。"]'),
('b93cc2ba-72b4-4eec-85d3-5bf8b917b682','安福殿千葉雙頭竝枝白牡丹歌','宋庠','宋','宋诗','song-poetry','','[]','三月春風滿瑶水，珍叢瑞薄紛難紀。',160,'全唐诗/poet.song.10000.json','["三月春風滿瑶水，珍叢瑞薄紛難紀。", "皭若茲花四照中，揚蕤獨茂千齡祉。", "千齡丕應在重葩，雙吐瓊房彰協華。", "秀跗即鏤平臺雪，寶豔寧爭台嶺霞。", "球欄黼幄遥相映，姑射仙姿玉虛境。", "結根已近堯蓂階，借媚非關漢蓮井。", "天襟多豫玩羣芳，彼美幽姿首效祥。", "都緣剩沐太和潤，況自頻分私照光。", "憑休託粹成奇質，一卉時來遂逢吉。", "願將藥品誌佳名，永續芝房騰茂實。"]'),
('e9533e85-990f-497d-91a0-45e965d7d983','感花','宋庠','宋','宋诗','song-poetry','','[]','前日來攀小園樹，枝頭蓓蕾無萬數。',64,'全唐诗/poet.song.10000.json','["前日來攀小園樹，枝頭蓓蕾無萬數。", "今朝置酒來賞花，已有殘英伴飛絮。", "春花如此將奈何，白日雖遲終不住。", "鶑歌蝶舞兩矜春，見我長嗟亦飛去。"]'),
('0f504b33-0135-4b70-924c-39716c72986e','南禪院','宋庠','宋','宋诗','song-poetry','','[]','王舍多幽剎，林居訪凈人。',48,'全唐诗/poet.song.10000.json','["王舍多幽剎，林居訪凈人。", "旁行經葉古，寶色梵天春。", "風閣鈴如語，烟溪樹勝輪。", "道場聊抖擻，認得客衣塵。"]'),
('7376bb9a-304e-4869-9b14-af60c9aeba0d','和楊學士和答中丞晏尚書西園玩菊','宋庠','宋','宋诗','song-poetry','','[]','憭慄衆芳歇，金英無與儔。',48,'全唐诗/poet.song.10000.json','["憭慄衆芳歇，金英無與儔。", "香疑飲潭日，歡似漉巾秋。", "潤蘤霜華入，薰叢野色留。", "郢蘭休自咤，冰玉此賡酬。"]'),
('a4b5e5f9-8912-4d43-bf7e-a97d2da8c323','春夕聞雁','宋庠','宋','宋诗','song-poetry','','[]','春夕坐神臯，天長北雁號。',48,'全唐诗/poet.song.10000.json','["春夕坐神臯，天長北雁號。", "來思繫書足，去羨順風毛。", "瑞鵠天淵暖，啼烏禁樹高。", "夫君自江海，避弋莫爲勞。"]'),
('d4832eaa-025c-4170-a75d-b3d76c3a2ae1','馬上見梅花初發','宋庠','宋','宋诗','song-poetry','','[]','瞥見江南樹，繁英照苑牆。',48,'全唐诗/poet.song.10000.json','["瞥見江南樹，繁英照苑牆。", "無雙春外色，第一臘前香。", "雲葉遥驚目，瓊枝昔斷腸。", "莫吹羌塢笛，容易損孤芳。"]'),
('af62af92-6964-4d9f-a999-9183e0264733','西陂','宋庠','宋','宋诗','song-poetry','','[]','歲晏西陂好，澄波共夕陽。',48,'全唐诗/poet.song.10000.json','["歲晏西陂好，澄波共夕陽。", "戲魚來有暈，驚鶩去無行。", "荇葉疏猶碧，蘭苕老更香。", "裴回歸鞅晚，併爲似滄浪。"]'),
('ae122943-0b95-43a5-b0a8-67e3a8fcb207','新月','宋庠','宋','宋诗','song-poetry','','[]','稍傍夕樓明，娟娟底有情。',48,'全唐诗/poet.song.10000.json','["稍傍夕樓明，娟娟底有情。", "眉纖鬭蛾出，鉤曲誤魚驚。", "欲暗猶銜岫，將斜更上楹。", "刀頭君自晚，莫枉桂初生。"]'),
('7bab472d-2155-4519-9e5c-3782a02ff90a','過璨師房','宋庠','宋','宋诗','song-poetry','','[]','病客塵纓外，幽齋法境中。',48,'全唐诗/poet.song.10000.json','["病客塵纓外，幽齋法境中。", "庭喧施鳥食，坐拂去花風。", "茗溜沈甌綠，檀烟入篆紅。", "忘言一相對，何處妄求空。"]'),
('e3a596a2-b62d-4eae-b5df-76e33aae1d19','送外門朱秀才見訪都下却歸安陸舊隠','宋庠','宋','宋诗','song-poetry','','[]','白髮游梁晚，青山念楚歸。',48,'全唐诗/poet.song.10000.json','["白髮游梁晚，青山念楚歸。", "魂銷雖得別，戰勝却成肥。", "障日都門蓋，迎烟磵路衣。", "試尋南圃樹，今長幾多圍。"]'),
('927789bd-5575-4b88-9b4b-5fdbc6ef7815','次韵和吳侍郎謝王陝州寄酒','宋庠','宋','宋诗','song-poetry','','[]','遥聞齋酎絜，來佐客觴酣。',48,'全唐诗/poet.song.10000.json','["遥聞齋酎絜，來佐客觴酣。", "棠野歌新續，兵厨興舊諳。", "竹供醅上色，蘭獻液中甘。", "欲識西臺勝，厭厭夜雪庵。"]'),
('ed1a1175-0c10-462b-8510-b9f3e52aaa49','建隆寺北池亭','宋庠','宋','宋诗','song-poetry','','[]','寶剎開初地，滄浪繞故城。',48,'全唐诗/poet.song.10000.json','["寶剎開初地，滄浪繞故城。", "芰蓮俱野色，鳬鴇各秋聲。", "岸闊烟無著，窗虛日易明。", "歸驂誰訝久，正爲濯塵纓。"]'),
('fee0941a-3fa6-4f45-93aa-26ef1021bd60','前歲春僕與獻臣同餞常山公于苑西曾未再朞已均師門之痛兼承即日親奉攢塗追往悼今哽涕無已因成短詩抒感諒心契之同戚也','宋庠','宋','宋诗','song-poetry','','[]','昔歲西郊餞，曾瞻出守麾。',48,'全唐诗/poet.song.10000.json','["昔歲西郊餞，曾瞻出守麾。", "今年東第哭，便嘆哲人萎。", "辰巳空成讖，膏肓不遇醫。", "詰朝聞衮斂，心折寢門悲。"]'),
('d4a00f5a-cf02-48c1-a81c-97f295250576','贈兵部尚書魯肅簡公挽詞三首  其一','宋庠','宋','宋诗','song-poetry','','[]','應運推邦直，乘時講化源。',48,'全唐诗/poet.song.10000.json','["應運推邦直，乘時講化源。", "不冠嘗可奏，問樹本無言。", "亮節裨初載，清風裕後昆。", "忽嗟梁木壞，褒冊賁忠魂。"]'),
('963d27b2-0ca4-412e-877a-353d6c57d091','贈兵部尚書魯肅簡公挽詞三首  其二','宋庠','宋','宋诗','song-poetry','','[]','昔事重明邸，俄陶萬物鈞。',48,'全唐诗/poet.song.10000.json','["昔事重明邸，俄陶萬物鈞。", "專懷長孺直，終損武侯神。", "舟壑先成夜，桃蹊遂不春。", "惟餘麗牲刻，終古誌名臣。"]'),
('6e4cfbbf-67b3-4c1a-963b-d0169064e6dd','贈兵部尚書魯肅簡公挽詞三首  其三','宋庠','宋','宋诗','song-poetry','','[]','偉望巖巖峻，忠言諤諤昌。',48,'全唐诗/poet.song.10000.json','["偉望巖巖峻，忠言諤諤昌。", "門無謝恩客，帷有獻書囊。", "王駿封侯晚，臧孫樹德長。", "都門蕭鼓發，行路泣云亡。"]'),
('1781a569-5fa2-4695-828b-7b190a49eec2','送黄昱赴太平州理掾','宋庠','宋','宋诗','song-poetry','','[]','閩錄家聲茂，唐銓吏格平。',48,'全唐诗/poet.song.10000.json','["閩錄家聲茂，唐銓吏格平。", "新資掾三語，舊榜佛千名。", "月苦鄉魂極，春寒酒意輕。", "高材難偶俗，慎勿對參卿。"]'),
('38c6f08a-914a-482d-aaec-ea98504b4332','送比部馬員外二浙提點刑獄','宋庠','宋','宋诗','song-poetry','','[]','西漢爲郎選，南方奉使才。',48,'全唐诗/poet.song.10000.json','["西漢爲郎選，南方奉使才。", "書隨星火落，帆拂斗牛開。", "束笴聞民悅，丹毫絕吏猜。", "奈矜持節重，無客對銜杯。"]'),
('eb946203-6ddc-4a55-ad30-39e22c034e4d','秋日小雨後作','宋庠','宋','宋诗','song-poetry','','[]','晚陌收殘雨，高軒冒夕霏。',48,'全唐诗/poet.song.10000.json','["晚陌收殘雨，高軒冒夕霏。", "風乾移舊響，月破隠空圍。", "敗葉相將舞，寒雲不肯飛。", "興無潘掾筆，何術寫心微。"]'),
('6ebbdc10-7cd5-4a03-8b3f-f5b0f6df3fdf','送英州理掾朱舅','宋庠','宋','宋诗','song-poetry','','[]','遠補參卿掾，來過乞墅甥。',48,'全唐诗/poet.song.10000.json','["遠補參卿掾，來過乞墅甥。", "秋悲先雁引，曉涕伴參橫。", "薏子期蠲疾，梅花幸寄聲。", "片言無異俗，陰德在鄉閎。"]'),
('53d01d1f-4e73-4778-a456-f557d4fab8fc','送從兄祕校咸赴衢州都掾','宋庠','宋','宋诗','song-poetry','','[]','倦客睢園遠，迎家越絕長。',48,'全唐诗/poet.song.10000.json','["倦客睢園遠，迎家越絕長。", "聊甘督罰掾，羞比入貲郎。", "汗竹書縢密，炊菰宴具香。", "蘭臺英藻盛，方信乃宗彊。"]'),
('6c71c5ff-f790-4f2c-b0d9-eaf4ac8db554','送宗弟祕校壬赴建州理掾','宋庠','宋','宋诗','song-poetry','','[]','補吏唐資淺，遊方漢牒遥。',48,'全唐诗/poet.song.10000.json','["補吏唐資淺，遊方漢牒遥。", "貪榮親及祿，詎悔俊沈僚。", "葛詠同根庇，松期晚歲凋。", "曾孫柔俗美，前識缿筩銷。"]'),
('575663b8-3484-4fa5-8a7f-944150f8e1f8','相州春日','宋庠','宋','宋诗','song-poetry','','[]','北土無繁卉，空亭有暝陰。',48,'全唐诗/poet.song.10000.json','["北土無繁卉，空亭有暝陰。", "狂飛憎野絮，多舌恨春禽。", "地燥山如朽，池寒水不深。", "生平箕潁志，軒冕獨何心。"]'),
('34bebca7-d1e0-4bea-a543-778e08c0ee67','送太常王素博士許昌通理','宋庠','宋','宋诗','song-poetry','','[]','連佐陪京郡，愁銜出祖杯。',48,'全唐诗/poet.song.10000.json','["連佐陪京郡，愁銜出祖杯。", "新曹拋野蕝，舊第老公槐。", "府檄迎車遠，戎牙宴豆開。", "遥知傾坐日，方歎阿𨽜才。"]'),
('b368439d-fccb-474e-8b4e-f3c5db0deca5','秋夜禁直聞雨','宋庠','宋','宋诗','song-poetry','','[]','徼道千廬地，宵霖八月天。',48,'全唐诗/poet.song.10000.json','["徼道千廬地，宵霖八月天。", "牀棲吳簟竹，窗濕漢宮錢。", "幕影翻層浪，簷聲響細泉。", "空階何所得，併是廢愁眠。"]'),
('f04ef571-bd86-4d23-9a65-81f14a11f3ae','臨春水','宋庠','宋','宋诗','song-poetry','','[]','盡日臨春水，非關問要津。',48,'全唐诗/poet.song.10000.json','["盡日臨春水，非關問要津。", "舟行魚避檝，岸坐草留人。", "香萼千紅糝，苔花小翠鱗。", "已堪遺俗慮，何必擉江濱。"]'),
('4d609024-70d3-4fcc-87b6-68304c366d6d','東方欲曉','宋庠','宋','宋诗','song-poetry','','[]','烏渴催宵漏，雞鳴引曙光。',48,'全唐诗/poet.song.10000.json','["烏渴催宵漏，雞鳴引曙光。", "山西河闇淡，天北斗低昂。", "銀燭香猶燼，瑶琴冷未張。", "何須開寶鑑，容鬢定蒼蒼。"]'),
('3b4843b9-2c46-40c2-9ad8-a80f0717eff6','掖門待漏','宋庠','宋','宋诗','song-poetry','','[]','曉陌千槐落，嚴扉萬蓋留。',48,'全唐诗/poet.song.10000.json','["曉陌千槐落，嚴扉萬蓋留。", "浮雲低觀闕，殘漏急章溝。", "斗柄遥臨殿，參旗側映樓。", "如何軒上鶴，獨憶海天秋。"]'),
('c9c631c7-edbe-4a9a-b46b-315347e13338','和吳侍郎題寶應僧房白雞冠花','宋庠','宋','宋诗','song-poetry','','[]','野卉秀禪庭，瑶華發素英。',48,'全唐诗/poet.song.10000.json','["野卉秀禪庭，瑶華發素英。", "託根真不染，肖質似先鳴。", "露葉疑藏羽，烟蕤更作纓。", "何妨依忍草，休辯好丹名。"]'),
('9fe5e054-7a75-49dc-98cd-67c5c2f94417','秋蝶','宋庠','宋','宋诗','song-poetry','','[]','百卉芳心罷，空園蝶影微。',48,'全唐诗/poet.song.10000.json','["百卉芳心罷，空園蝶影微。", "雖逢已凉節，尚作有情飛。", "露菊聊堪採，風蘭或可依。", "履霜從此懼，君意定何歸。"]'),
('648df7f9-77ba-494c-a897-34e67fbe23e4','登大明寺塔','宋庠','宋','宋诗','song-poetry','','[]','寂寞南朝寺，徘徊北顧人。',48,'全唐诗/poet.song.10000.json','["寂寞南朝寺，徘徊北顧人。", "鐘聲含曉籟，塔相湧仙輪。", "弔古千齡恨，觀空萬法塵。", "三車何處在，歸鞅欲迷津。"]'),
('6de5b8ac-5a40-4741-a408-464e953963af','燈夕齋中香火獨坐招希元不至','宋庠','宋','宋诗','song-poetry','','[]','掩室維摩病，從昏太一祠。',48,'全唐诗/poet.song.10000.json','["掩室維摩病，從昏太一祠。", "誰言鼓吹夕，獨禮天人師。", "燭燼委寒檠，茗華浮縹瓷。", "同袍不我顧，宴坐復何思。"]'),
('e8a2fd30-17e8-4a96-ad7b-685859b55ab8','送刁繹從事自龍舒西赴青城宰','宋庠','宋','宋诗','song-poetry','','[]','東別羣舒國，西踰二劍天。',48,'全唐诗/poet.song.10000.json','["東別羣舒國，西踰二劍天。", "才高鄴都檄，政竚武城絃。", "莋馬征蹄苦，巖雞瑞羽鮮。", "離愁知遠近，萬里到橋邊。"]'),
('c24e3db3-d26f-4369-8a44-175dae0fcb1c','疾風','宋庠','宋','宋诗','song-poetry','','[]','天陸箕躔動，林簫萬籟空。',48,'全唐诗/poet.song.10000.json','["天陸箕躔動，林簫萬籟空。", "扶摇莊海北，悲眩魯門東。", "貪誡詩人隧，清思賦客雄。", "何因知勁草，霜陌盡飛蓬。"]'),
('f2885410-a9d7-4ab3-afdd-92ea27a47c25','朝謁建隆寺','宋庠','宋','宋诗','song-poetry','','[]','郡國高皇廟，天龍釋帝居。',48,'全唐诗/poet.song.10000.json','["郡國高皇廟，天龍釋帝居。", "兵銷擒布後，臺聳畏軒餘。", "寶榻成蓮坐，戎韜入貝書。", "守臣榮就望，屏息拜前除。"]'),
('b67975ad-4784-408f-8c1e-871c20c360fd','遲明出都謝雪龍門佛祠途中復遇雪','宋庠','宋','宋诗','song-poetry','','[]','路闊三條陌，雲低九鼎門。',48,'全唐诗/poet.song.10000.json','["路闊三條陌，雲低九鼎門。", "鐃風催騎響，裘霰減貂溫。", "谷曉天花亂，林空苑絮繁。", "周麰農意切，一一願流根。"]'),
('75fd2cd1-ca1d-41fb-8e85-76b3a06b2601','晚歸馳道遇雨馬上作','宋庠','宋','宋诗','song-poetry','','[]','朝雨雜輕霾，濃陰暮未開。',48,'全唐诗/poet.song.10000.json','["朝雨雜輕霾，濃陰暮未開。", "天低五里霧，日晦九成臺。", "宮溜輕淙玉，坊車小隠雷。", "不愁馳道遠，寶色夾千槐。"]'),
('96f75e3e-6465-4507-8072-8909d7b724b0','河陽寒食','宋庠','宋','宋诗','song-poetry','','[]','關輔陪京外，年華禁火中。',48,'全唐诗/poet.song.10000.json','["關輔陪京外，年華禁火中。", "柳矜河上綠，花獻酒邊紅。", "野市鞦韆月，春樓觱篥風。", "三州六鑽燧，安得不衰翁。"]'),
('aad7224d-a7fe-499a-a50a-6d12616829e6','晚晴','宋庠','宋','宋诗','song-poetry','','[]','斜日紅初斂，晴山翠欲流。',48,'全唐诗/poet.song.10000.json','["斜日紅初斂，晴山翠欲流。", "休歌陌婦怨，寧作賈胡留。", "物意如相樂，吾生有底愁。", "早分好風月，更上庾公樓。"]'),
('722ea9d6-4285-4606-8872-ac992912b570','贈中書令沂國王文正公挽詞二首  其一','宋庠','宋','宋诗','song-poetry','','[]','揆路同寅業，師垣出守麾。',48,'全唐诗/poet.song.10000.json','["揆路同寅業，師垣出守麾。", "終無三令喜，便集兩楹悲。", "衮職嗟何補，天心感憗遺。", "幽泉空漏淎，非復作霖時。"]'),
('4ee485ca-67f7-4dc2-aff0-ba21008188ad','贈中書令沂國王文正公挽詞二首  其二','宋庠','宋','宋诗','song-poetry','','[]','自昔榮歸衮，今茲駭閱川。',48,'全唐诗/poet.song.10000.json','["自昔榮歸衮，今茲駭閱川。", "天愁摧柱日，星痛殞箕年。", "素履遺儒範，忠謀溢吏篇。", "空餘洧鄉陌，長似峴碑前。"]'),
('f2729e97-6262-4cfb-943d-26616b97ef1e','錢侯東齋','宋庠','宋','宋诗','song-poetry','','[]','北里開公第，東齋集俊游。',48,'全唐诗/poet.song.10000.json','["北里開公第，東齋集俊游。", "祕書家有副，甲令世傳侯。", "鳳竹供聯冊，鯖盤入宴羞。", "門前多鶴蓋，不爲騁長楸。"]'),
('bc6a8125-5f73-40ba-8981-b457c90407c6','贈駙馬都尉李和文公挽詞二首  其一','宋庠','宋','宋诗','song-poetry','','[]','曲里猶龍族，西京尚主侯。',48,'全唐诗/poet.song.10000.json','["曲里猶龍族，西京尚主侯。", "勳華傳舊鉞，名理寄虛舟。", "得疾真無妄，觀生遂若休。", "偏嗟荀令沼，回作逝川流。"]'),
('9d3a9460-8b49-40aa-a9fb-6de302dfa729','贈駙馬都尉李和文公挽詞二首  其二','宋庠','宋','宋诗','song-poetry','','[]','北第琴樽歇，東原旌旆飛。',48,'全唐诗/poet.song.10000.json','["北第琴樽歇，東原旌旆飛。", "清風邈無所，此路是長違。", "野闊車吞響，天愁日抱輝。", "空餘門下客，魚鳥歎何依。"]'),
('0c9abc06-5248-431c-a6d1-9741f9e7e454','獨坐郡圃北齋','宋庠','宋','宋诗','song-poetry','','[]','宿雨催秋物，清風卷歲華。',48,'全唐诗/poet.song.10000.json','["宿雨催秋物，清風卷歲華。", "殘蜩初去柳，寒蝶尚尋花。", "密篠留蒼霧，紅梨染落霞。", "城頭八九子，日昃亂啼鴉。"]'),
('49837b04-efa8-4af8-883d-de3524b39f44','贈太子太保晁文公挽詞二首  其一','宋庠','宋','宋诗','song-poetry','','[]','帝禁留辭範，儒林老棟材。',48,'全唐诗/poet.song.10000.json','["帝禁留辭範，儒林老棟材。", "方期割牲禮，遽近奠楹災。", "歲晏巢鵀逝，天秋弔鶴來。", "宗工銘盛德，千古照泉臺。"]'),
('5eec2edd-0812-4cd8-b9c8-07657c4ee1ea','贈太子太保晁文公挽詞二首  其二','宋庠','宋','宋诗','song-poetry','','[]','几杖辭榮久，龍蛇感歲遷。',48,'全唐诗/poet.song.10000.json','["几杖辭榮久，龍蛇感歲遷。", "留春太史記，成佛謝公緣。", "素蓋寒雲外，哀簫落月前。", "無煩樵牧禁，行路拜新阡。"]'),
('2cdd1fb5-c601-4a69-bffe-ac1c34646ddd','贈司徒兼侍中宋宣獻挽詞四首  其一','宋庠','宋','宋诗','song-poetry','','[]','一世文爲伯，三階象有光。',48,'全唐诗/poet.song.10000.json','["一世文爲伯，三階象有光。", "何言隆棟吉，忽歎夜舟藏。", "襚禮朝頒冊，哀音路過喪。", "善人今不與，神理太茫茫。"]'),
('9ecd74ea-b710-46fc-8cb3-80ef3fe2ef67','贈司徒兼侍中宋宣獻挽詞四首  其二','宋庠','宋','宋诗','song-poetry','','[]','梁木萎邦哲，乘輿哭第家。',48,'全唐诗/poet.song.10000.json','["梁木萎邦哲，乘輿哭第家。", "斂恩周衮里，追品漢貂華。", "素禮初無悔，浮生遂有涯。", "斯文從此喪，誰與辨咬哇。"]'),
('19b49278-eb8b-4476-808b-085f3b37d3b7','贈司徒兼侍中宋宣獻挽詞四首  其三','宋庠','宋','宋诗','song-poetry','','[]','舛運明生疾，忠懷語絕偷。',48,'全唐诗/poet.song.10000.json','["舛運明生疾，忠懷語絕偷。", "空榮人曳履，終隔相封侯。", "太史藏書法，門生助紼謳。", "惟餘文獻謚，不復嘆平頭。"]'),
('7adac54e-5021-4d28-b293-19dcdc4db736','贈司徒兼侍中宋宣獻挽詞四首  其四','宋庠','宋','宋诗','song-poetry','','[]','宗工天下寶，歸葬國西原。',48,'全唐诗/poet.song.10000.json','["宗工天下寶，歸葬國西原。", "野闊簫聲苦，雲愁旐影昏。", "如存三事禮，不返九京魂。", "河海空成淚，難酬國士恩。"]'),
('6874d011-2e83-42f1-b211-4948438faa34','別墅冬霽','宋庠','宋','宋诗','song-poetry','','[]','宅隠羊曇墅，門連仲蔚蒿。',48,'全唐诗/poet.song.10000.json','["宅隠羊曇墅，門連仲蔚蒿。", "銜盃思左蟹，舒嘯憶東臯。", "楚桂風生穴，莊魚浪溢濠。", "平生丘壑志，終願寄民曹。"]'),
('98be1f4b-b77a-44f2-ba93-b7366af9b46e','冬霽','宋庠','宋','宋诗','song-poetry','','[]','夜枕鴻違漢，霜天雀噪園。',48,'全唐诗/poet.song.10000.json','["夜枕鴻違漢，霜天雀噪園。", "回車長者轍，曝背野人暄。", "墨溜沈寒沼，松醪湛凍樽。", "誰能穿雪履，待詔魯班門。"]'),
('21e21717-dc40-46fc-bcd7-721a99e6f049','贈太傅中書令張文節公挽詞三首  其一','宋庠','宋','宋诗','song-poetry','','[]','素範流邦冊，昌言溢帝聰。',48,'全唐诗/poet.song.10000.json','["素範流邦冊，昌言溢帝聰。", "三台應天老，萬事問胡公。", "道有如絃直，生嗟委蛻窮。", "令君兼上傅，衮斂賁遺忠。"]'),
('98d287ee-b12b-4b18-80ea-590dd62b9b29','贈太傅中書令張文節公挽詞三首  其二','宋庠','宋','宋诗','song-poetry','','[]','昔命光三事，今嗟贖百身。',48,'全唐诗/poet.song.10000.json','["昔命光三事，今嗟贖百身。", "堂無織蒲妾，車有吐茵人。", "台坼層氛夜，槐凋故府春。", "空餘相國第，不與勢家鄰。"]'),
('2c518289-093c-4b85-969c-93c59a5eaaed','贈太傅中書令張文節公挽詞三首  其三','宋庠','宋','宋诗','song-poetry','','[]','平日開黄閣，茲辰奠素旗。',48,'全唐诗/poet.song.10000.json','["平日開黄閣，茲辰奠素旗。", "留侯嘗辟穀，巖說遂騎箕。", "天迥哀笳咽，林長導翣遲。", "行人此墮淚，何必峴亭碑。"]'),
('c63cc5da-a0ae-40c4-959d-28029381f4d5','次韵和吳侍郎再葺東亭兼懷晁公舊隠','宋庠','宋','宋诗','song-poetry','','[]','地占心齋舊，天扶藥喜身。',48,'全唐诗/poet.song.10000.json','["地占心齋舊，天扶藥喜身。", "高懷聊避寵，幽境更隨人。", "樹密添新籟，叢香續故春。", "婆娑榮路友，偏倚此相親。"]'),
('23b7892f-1dba-4f62-a56e-3269796f8cb3','夏夕雨霽','宋庠','宋','宋诗','song-poetry','','[]','積晦連空卷，繁蒸此夜收。',48,'全唐诗/poet.song.10000.json','["積晦連空卷，繁蒸此夜收。", "峰催雲去夏，珪伴月迎秋。", "樹老殘煙入，庭虛爽氣留。", "長康惟半黠，孤詠費冥搜。"]'),
('eb1bde96-1767-4b02-a0e9-5d9c58546de1','北亭','宋庠','宋','宋诗','song-poetry','','[]','舊壁橫空苑，危亭納夕霏。',48,'全唐诗/poet.song.10000.json','["舊壁橫空苑，危亭納夕霏。", "野蟲多各韵，倦鳥忽同歸。", "木落驚秋晏，人愁念昨非。", "生平嵩潁志，尚或拂塵衣。"]'),
('779ee576-52db-4115-b95e-16b58336ae21','早春北亭見城隅荒寂','宋庠','宋','宋诗','song-poetry','','[]','荒城樓堞少，野色徧高低。',48,'全唐诗/poet.song.10000.json','["荒城樓堞少，野色徧高低。", "蔓草無名綠，幽禽取意啼。", "天形岡樹北，日脚嶺雲西。", "不覺凝笳動，春風引夕鼙。"]'),
('93219a71-9906-4c10-93d1-7993be3f9d3f','寓居寰內宰邑者數見存訪因成謝','宋庠','宋','宋诗','song-poetry','','[]','謝病非三最，爲氓乏一廛。',48,'全唐诗/poet.song.10000.json','["謝病非三最，爲氓乏一廛。", "何言羅爵尉，時駐舄鳬仙。", "華轍交深巷，餘香襲故氈。", "豬肝難設具，應作閔生憐。"]'),
('d5108550-7389-4d37-b06d-1ef6a3c499ac','得充國書報都中葺所居初成輒以自慰作一首寄子京','宋庠','宋','宋诗','song-poetry','','[]','昔貴三公第，今營一畝居。',48,'全唐诗/poet.song.10000.json','["昔貴三公第，今營一畝居。", "聊堪避燥濕，兼欲貯琴書。", "獸窟猶思騁，鷦巢不願餘。", "長安窮僻地，吾亦愛吾廬。"]'),
('03249ed6-7f44-4abb-bbb2-0f01fcd3e4ee','送晏延平宰邑分寧兼過鄉墅','宋庠','宋','宋诗','song-poetry','','[]','銅紐腰新綬，烏衣省故廬。',48,'全唐诗/poet.song.10000.json','["銅紐腰新綬，烏衣省故廬。", "鄉無夜行諺，楹有世藏書。", "楚潦蘭浮檝，潘園板御輿。", "蚩蚩吳俗美，庖刃一投虛。"]'),
('40a9aab7-39ee-4013-93e8-af431947a817','送靜海高簿','宋庠','宋','宋诗','song-poetry','','[]','城闕曙烏啼，行人歎解携。',48,'全唐诗/poet.song.10000.json','["城闕曙烏啼，行人歎解携。", "舊歡苹鹿散，新意棘鸞棲。", "淮月涵孤蚌，江雲雜斷霓。", "漉沙應搆賦，春澥正平隄。"]'),
('710ce1d3-5999-48a7-b16d-78cda396e938','魏花千葉','宋庠','宋','宋诗','song-poetry','','[]','露畹移珍樹，丹房一紺幃。',48,'全唐诗/poet.song.10000.json','["露畹移珍樹，丹房一紺幃。", "綃輕無奈疊，霞碎却相依。", "傃日香難斂，擎風力自微。", "他時零落恨，千片爲誰飛。"]'),
('b25f375c-b737-42a1-83f1-2517f589e69c','晏歲','宋庠','宋','宋诗','song-poetry','','[]','晏歲無情晚，陰飈昨夜聞。',48,'全唐诗/poet.song.10000.json','["晏歲無情晚，陰飈昨夜聞。", "芳條臨檻勁，短日轉樓曛。", "苔石收蒼暈，冰溪疊素紋。", "蒿蘭雖異種，霜至若爲分。"]'),
('6ed83713-aa5b-4744-b8b8-14373ec1b5fc','早春雪後見辛夷初發','宋庠','宋','宋诗','song-poetry','','[]','冒霰初分葉，驚春已作花。',48,'全唐诗/poet.song.10000.json','["冒霰初分葉，驚春已作花。", "鮮于紫艾綬，殷過赤城霞。", "破蓓香囊小，銜趺彩筆斜。", "騷人雖麗思，忍作桂旗車。"]'),
('0ce6055a-6cec-44db-99cf-5c8d7c2cd482','秋夕池上','宋庠','宋','宋诗','song-poetry','','[]','月御橫霄陸，溪樓敞夕霏。',48,'全唐诗/poet.song.10000.json','["月御橫霄陸，溪樓敞夕霏。", "神龜荷裏宿，仙驥露中飛。", "屏箑風摧暑，攀條客念歸。", "冶城空極望，憂樂意多違。"]'),
('5ae411a5-1928-40b6-aa1a-051f08b2d0f9','和友人晚出池上','宋庠','宋','宋诗','song-poetry','','[]','節物更徂候，幽衿屬釣臺。',48,'全唐诗/poet.song.10000.json','["節物更徂候，幽衿屬釣臺。", "蘭苕兼佩長，桂葉學旗開。", "鵲避驚弦去，魚隨晚餌來。", "謝塘多藻思，弭蓋一相陪。"]'),
('d7833b8a-e2fc-43f1-beda-9664efb65484','次韵和王密學冬暮書事','宋庠','宋','宋诗','song-poetry','','[]','歲晏陪京守，心閒俗自安。',48,'全唐诗/poet.song.10000.json','["歲晏陪京守，心閒俗自安。", "斗城供近望，天幕借餘歡。", "秀句然萁待，幽經濯手看。", "不因郵問數，誰識政條寬。"]'),
('26e0f6b3-4cd2-417d-b500-b22fabba8214','小橋','宋庠','宋','宋诗','song-poetry','','[]','野水危梁渡，凌虛一徑橫。',48,'全唐诗/poet.song.10000.json','["野水危梁渡，凌虛一徑橫。", "鄭車求代涉，漢櫂且專行。", "濠詠觀魚樂，圯書跪履情。", "斜陽葭菼岸，鷗鳥爲誰驚。"]'),
('793c8ded-d15b-402d-b22b-c3cc306d63b4','姚黄','宋庠','宋','宋诗','song-poetry','','[]','世外無雙種，人間絕品黄。',48,'全唐诗/poet.song.10000.json','["世外無雙種，人間絕品黄。", "已能金作粉，更自麝供香。", "脈脈翻霓袖，差差剪鵠裳。", "靈華餘幾許，遥遺菊叢芳。"]'),
('8b65561a-2601-42ff-889d-e9df27d224f8','歲晚餞客南亭二首  其一','宋庠','宋','宋诗','song-poetry','','[]','偶作津亭餞，還驚歲物非。',48,'全唐诗/poet.song.10000.json','["偶作津亭餞，還驚歲物非。", "蒼葭無際合，黄葉有聲飛。", "別恨隨人遠，鄉心著酒微。", "猶欣見山色，紆轡暫忘歸。"]'),
('3e2b3f23-be3a-4521-97a9-a826c6ff6c3e','歲晚餞客南亭二首  其二','宋庠','宋','宋诗','song-poetry','','[]','淮壤窮南界，亭臯坐渺然。',48,'全唐诗/poet.song.10000.json','["淮壤窮南界，亭臯坐渺然。", "平窺京口樹，斜落海門天。", "重霧多藏日，寒潮不送船。", "江山寧有助，私作楚騷憐。"]'),
('7cd5aaaf-31c8-4458-9fbc-9c1334013264','遥夜','宋庠','宋','宋诗','song-poetry','','[]','夜夕更籌永，霜飛歲籥空。',48,'全唐诗/poet.song.10000.json','["夜夕更籌永，霜飛歲籥空。", "斗杓常記候，蟾暈豫知風。", "過雁驚流弋，衰螢戀故叢。", "可堪鄉思發，夢繞兔園東。"]'),
('ecad881d-e71e-4075-be77-5c75a288cd0b','竹雞','宋庠','宋','宋诗','song-poetry','','[]','羽族何微眇，交交作好音。',48,'全唐诗/poet.song.10000.json','["羽族何微眇，交交作好音。", "遠聞真似語，寂聽本無心。", "倦舌沈荒塢，嬉羣聒翠林。", "鷦鷯王佐筆，從此異凡禽。"]'),
('0d2dfc42-e765-46e6-93d7-b7def9dbff5f','鬭鷄','宋庠','宋','宋诗','song-poetry','','[]','對壘毰毸地，雙驚滅玉塵。',48,'全唐诗/poet.song.10000.json','["對壘毰毸地，雙驚滅玉塵。", "長鳴非後郭，利嘴欲專秦。", "鴟領聊延敵，鷹揚願殺身。", "君恩定多少，引距即隨人。"]'),
('e3a1d31d-ea10-4e70-8544-c71f2cd35147','春渚','宋庠','宋','宋诗','song-poetry','','[]','溪上照奫淪，吾纓此濯塵。',48,'全唐诗/poet.song.10000.json','["溪上照奫淪，吾纓此濯塵。", "風清琴籟細，波浸沼毛春。", "處裔蛟何待，鳴雝鷺自馴。", "直鉤聊適興，底處餌文鱗。"]'),
('03c5facc-d6a3-4ba0-a07f-2405bec28dd5','晚霽','宋庠','宋','宋诗','song-poetry','','[]','斷續簷聲歇，徘徊隙影賒。',48,'全唐诗/poet.song.10000.json','["斷續簷聲歇，徘徊隙影賒。", "歸雲衝樹破，殘雨入樓斜。", "徑綠都成草，叢薰尚隠花。", "便同江海思，春水照軍牙。"]'),
('e81d515b-8efc-470b-a804-302110e2c973','負暄','宋庠','宋','宋诗','song-poetry','','[]','旭日東南霽，霜天病骨寒。',48,'全唐诗/poet.song.10000.json','["旭日東南霽，霜天病骨寒。", "心同陽藿展，志鄙夏畦難。", "東洛貂裘壞，西華葛被單。", "嵇慵聊自樂，愛景始三竿。"]'),
('b814c22a-b8ef-44a8-bca8-668461667019','惠泉','宋庠','宋','宋诗','song-poetry','','[]','濟物功偏厚，朝宗勢不迷。',48,'全唐诗/poet.song.10000.json','["濟物功偏厚，朝宗勢不迷。", "一航容宋葦，六斗異涇泥。", "潤溢呼魚轍，光分抱甕畦。", "寧同南國詠，酌飲變夷齊。"]'),
('eafd341e-b0b2-49a9-ac67-bdfb2fe2a710','有釋子以禪會圖貺余者此圖即今駙馬都尉李公所製繪故楊大年劉子儀及都尉環禪師等信一時之盛集瞻歎不足因成紀詠','宋庠','宋','宋诗','song-poetry','','[]','法集超初地，工毫構妙緣。',48,'全唐诗/poet.song.10000.json','["法集超初地，工毫構妙緣。", "星占世外聚，月寫相中圓。", "指指誰標諭，心心自默傳。", "惟應阿堵處，俱是到忘筌。"]'),
('b1e8fd97-dd85-4f54-8a86-3b4b06d3bf57','對月','宋庠','宋','宋诗','song-poetry','','[]','蕭寂東軒坐，徘徊月馭來。',48,'全唐诗/poet.song.10000.json','["蕭寂東軒坐，徘徊月馭來。", "風休凉暈缺，旬破晚弦開。", "紫漢沈星樹，仙莖逼露杯。", "誰憐故林鵲，終夕自驚猜。"]'),
('ae79cc34-bf82-4d0e-8120-104e52b80721','得告上冢','宋庠','宋','宋诗','song-poetry','','[]','拜墓標唐令，褒親漏漢恩。',48,'全唐诗/poet.song.10000.json','["拜墓標唐令，褒親漏漢恩。", "永懷凄欲寄，忠訓藹如存。", "宰樹錦城陌，農疇潁曲村。", "異時裁敘傳，容或記臯門。"]'),
('09a8958b-4cc0-42da-bc60-fff2d802dd88','立秋後一日凉風蕭瑟便若感人','宋庠','宋','宋诗','song-poetry','','[]','倏忽徂炎罷，驚秋自此辰。',48,'全唐诗/poet.song.10000.json','["倏忽徂炎罷，驚秋自此辰。", "殘蜩空愛露，孤扇欲辭人。", "嵩少千尋嶺，滄浪萬里津。", "如何一乘興，烟策弄飈輪。"]'),
('acc1769e-d693-422b-a3a4-711d3640bc1c','河陽秋思六首  其一','宋庠','宋','宋诗','song-poetry','','[]','關外山河闊，城邊卉木腓。',48,'全唐诗/poet.song.10000.json','["關外山河闊，城邊卉木腓。", "露濃蟬始罷，風急燕猶飛。", "不雨雲中薄，澄沙水自微。", "善哉吾祖歎，能此送將歸。"]'),
('d1d7c47b-d893-45d4-bdb3-98cee07b28ca','河陽秋思六首  其二','宋庠','宋','宋诗','song-poetry','','[]','自古悲秋物，多傷黯黯魂。',48,'全唐诗/poet.song.10000.json','["自古悲秋物，多傷黯黯魂。", "鱸魚輕客宦，紈扇感君恩。", "潁瀨寒明野，嵩雲側露村。", "此中知止地，歸去掩柴門。"]'),
('e9f516d6-5354-4693-8f2f-1a45895f8fb8','河陽秋思六首  其三','宋庠','宋','宋诗','song-poetry','','[]','芳序雖云晚，華顛亦已新。',48,'全唐诗/poet.song.10000.json','["芳序雖云晚，華顛亦已新。", "蛩鳴偏傍耳，燕去不辭人。", "山隠棲巖路，朝嬰佩玉身。", "故溪應更好，前夜夢垂綸。"]'),
('3a7547eb-4b18-4455-9f3d-7a561f875cb9','河陽秋思六首  其四','宋庠','宋','宋诗','song-poetry','','[]','出處因年警，多慚與願違。',48,'全唐诗/poet.song.10000.json','["出處因年警，多慚與願違。", "於陵終不仕，疏傅幾時歸。", "江柳寒陰瘦，畦菘晚葉肥。", "寄聲溪上鳥，且莫背人飛。"]'),
('4712db92-1f3d-47f1-b88b-94562e84a9d1','河陽秋思六首  其五','宋庠','宋','宋诗','song-poetry','','[]','久雨收寒潦，層颸蕩薄埃。',48,'全唐诗/poet.song.10000.json','["久雨收寒潦，層颸蕩薄埃。", "鳴蛙鼓吹歇，高雁弟兄來。", "食肉嗟謀短，關弓任世猜。", "故園三徑在，新菊幾叢開。"]'),
('73b4238e-3905-48a8-8023-df3a564f9ec6','河陽秋思六首  其六','宋庠','宋','宋诗','song-poetry','','[]','秋物自能晚，秋聲何足悲。',48,'全唐诗/poet.song.10000.json','["秋物自能晚，秋聲何足悲。", "歡應隨壯去，病已與衰期。", "斗遠終難挹，天高不易欺。", "此心丘壑戀，匪石恐難移。"]'),
('9f6bed4c-9e0b-4945-aa58-d50c35610fde','雨霽','宋庠','宋','宋诗','song-poetry','','[]','曉雨纔收潤，高軒一爽神。',48,'全唐诗/poet.song.10000.json','["曉雨纔收潤，高軒一爽神。", "雪峰將變夏，桃蠹漸辭春。", "霽隙微陽淡，陰牆積蘚勻。", "空餘稚圭宅，蛙響徧諸鄰。"]'),
('441f65c9-9b52-4a03-ae9a-4e2b28bcf61b','小圃雨霽','宋庠','宋','宋诗','song-poetry','','[]','風雨殘秋罷，年芳遂悄然。',48,'全唐诗/poet.song.10000.json','["風雨殘秋罷，年芳遂悄然。", "黄花沉暮蝶，蒼柳嘯孤蟬。", "霽日高彌淡，曛霞冷不鮮。", "忽聞雙鶴唳，心斷故谿田。"]'),
('6a9c4b0f-5dba-42d4-8428-98cfaebdc4cb','霽後','宋庠','宋','宋诗','song-poetry','','[]','小雨春膏潤，微波晚照空。',48,'全唐诗/poet.song.10000.json','["小雨春膏潤，微波晚照空。", "壺光遥送電，梁影半傾虹。", "珍樹疏煙合，坳塘暗溜通。", "羲皇誰可上，靖節有窗風。"]'),
('a17b6b76-9325-43b9-a33f-d83e7a695317','凌景陽寺丞與韓綜監簿蔡襄秀才雪夕會飲聯詩數十韵以相示因成詩句','宋庠','宋','宋诗','song-poetry','','[]','歲籥愁雲暮，朋簪夕宴開。',48,'全唐诗/poet.song.10000.json','["歲籥愁雲暮，朋簪夕宴開。", "賢如潁川聚，興是剡溪來。", "瀉酒蟾波溜，雕章燭刻催。", "三英知絕擬，況復是平臺。"]'),
('65f191c5-1c3e-442d-8e5d-774b8214ed01','漢濱北樓','宋庠','宋','宋诗','song-poetry','','[]','一水東流闊，諸峰右轉深。',48,'全唐诗/poet.song.10000.json','["一水東流闊，諸峰右轉深。", "蟾規欲破暈，天杵不盈尋。", "浦逗分風席，洲喧避繳禽。", "憑高機事息，併爲漢川陰。"]'),
('a693371d-0b0b-4532-b989-c5d27959566d','晨謁宮門小雨初過','宋庠','宋','宋诗','song-poetry','','[]','宮漏籤聲急，天街雨脚微。',48,'全唐诗/poet.song.10000.json','["宮漏籤聲急，天街雨脚微。", "曉寒凌禁樹，春氣裛朝衣。", "瑞霧輕猶濕，香塵重不飛。", "雞人傳鑰出，華旭滿彤闈。"]'),
('b8040031-3653-4d82-8527-94d4639c5d34','淮上','宋庠','宋','宋诗','song-poetry','','[]','晚歲清淮路，淹留數問津。',48,'全唐诗/poet.song.10000.json','["晚歲清淮路，淹留數問津。", "風平天合水，舟進樹迎人。", "饑鶩貪魚沒，高鴻望渚遵。", "楚鄉梅柳意，相慰似先春。"]'),
('0a55a6b0-f2ca-4235-a26c-d2c7e956f1e2','北樓三首  其一','宋庠','宋','宋诗','song-poetry','','[]','地迥樓堪倚，天長日更勞。',48,'全唐诗/poet.song.10000.json','["地迥樓堪倚，天長日更勞。", "何須雲渺渺，況自葉騷騷。", "脫兔橫岡遠，冥鴻避弋高。", "四愁休徧詠，俱是一霑袍。"]'),
('17c93342-af3b-4bc8-bafc-639a4e60b472','北樓三首  其二','宋庠','宋','宋诗','song-poetry','','[]','孤堞神坰畔，平原歲琯陰。',48,'全唐诗/poet.song.10000.json','["孤堞神坰畔，平原歲琯陰。", "驚麏時易藪，倦鳥即投林。", "日舍翻車恨，天旄伏櫪心。", "蓬池八十首，半是爲登臨。"]'),
('725fa52e-cc87-4f14-967e-e79d9df1a439','北樓三首  其三','宋庠','宋','宋诗','song-poetry','','[]','危檻倚孤城，風襟俗慮醒。',48,'全唐诗/poet.song.10000.json','["危檻倚孤城，風襟俗慮醒。", "天高鴻類𩾐，雲散日如萍。", "疊巘斜銜岫，回川曲抱汀。", "騷愁千古地，椒醑弔遺靈。"]'),
('6a6c8dd3-ffc3-4a65-bcdd-1c003ea254de','送兩浙轉運道卿學士二首  其一','宋庠','宋','宋诗','song-poetry','','[]','彼美閨臺彥，胡爲江海行。',48,'全唐诗/poet.song.10000.json','["彼美閨臺彥，胡爲江海行。", "真貪子舍養，不厭使軺輕。", "茂草姑蘇苑，蒼山越絕城。", "莫因羊酪味，終擬笑諸傖。"]'),
('0ef736ff-5e84-4fab-a6e6-3e6446b2972c','送兩浙轉運道卿學士二首  其二','宋庠','宋','宋诗','song-poetry','','[]','新歲郵中問，殘冬湖外書。',48,'全唐诗/poet.song.10000.json','["新歲郵中問，殘冬湖外書。", "歡同烹鯉日，情是斷金餘。", "澤節行臺峻，天垣右席虛。", "不應周吏課，朝紱企歸歟。"]'),
('5da5fb56-6d48-491d-8922-7aae96c0f4e1','晚登東樓懷子京鎮陽二首  其一','宋庠','宋','宋诗','song-poetry','','[]','洛表樓堪倚，燕陲望不窮。',48,'全唐诗/poet.song.10000.json','["洛表樓堪倚，燕陲望不窮。", "秋聲南送雁，寒意北隨風。", "歛暝關雲黑，銜規苑日紅。", "凋年霜霰惡，慎勿損荆叢。"]'),
('ca19dbe5-a521-402d-887e-4375c2cab2fb','晚登東樓懷子京鎮陽二首  其二','宋庠','宋','宋诗','song-poetry','','[]','周界西窮陝，常山北盡邊。',48,'全唐诗/poet.song.10000.json','["周界西窮陝，常山北盡邊。", "關河相望日，容鬢各衰年。", "蓬亂將風野，禽稀欲雪天。", "治戎如有暇，莫惜賦歸田。"]'),
('09b5c263-20be-4f90-9f83-9d387f9d3bae','秋圃感物','宋庠','宋','宋诗','song-poetry','','[]','秋葉霜前綠，秋池雨後清。',48,'全唐诗/poet.song.10000.json','["秋葉霜前綠，秋池雨後清。", "殘蟬多默默，寒蝶强輕輕。", "丹果林梢熟，黄花草際明。", "心慚逃相客，世外掩柴荆。"]'),
('79f0b0d6-c93b-47fc-ba5b-6d9a9f510dfd','羣玉殿十二月二十三日錫宴  其一','宋庠','宋','宋诗','song-poetry','','[]','歲晏彤帷敞，天深紫宇寬。',48,'全唐诗/poet.song.10000.json','["歲晏彤帷敞，天深紫宇寬。", "氣和先合樂，仗密不知寒。", "斟酌中衢飲，伊亞別殿歡。", "先春皇意悅，花滿從臣冠。"]'),
('66a0c65d-cb14-422a-8a92-e9927d4bfefa','羣玉殿十二月二十三日錫宴  其二','宋庠','宋','宋诗','song-poetry','','[]','寶翰揮文罷，瑶觴續宴初。',48,'全唐诗/poet.song.10000.json','["寶翰揮文罷，瑶觴續宴初。", "帝韶重舞鳳，玉藻更歌魚。", "景駐三休閣，歡留六尺輿。", "賜金將厚意，併入史臣書。"]'),
('19de4588-caa9-42ef-9b13-6c02238943e3','杜門','宋庠','宋','宋诗','song-poetry','','[]','苫宇切郊寰，荆扉度歲關。',48,'全唐诗/poet.song.10000.json','["苫宇切郊寰，荆扉度歲關。", "賓綦秋蘚合，童唱暮薪還。", "石上舂粱苦，牆東避世難。", "扊扅猶可爨，誰訪陋居顔。"]'),
('df3df9c0-7a40-495e-bffa-18758050d845','謀退四首  其一','宋庠','宋','宋诗','song-poetry','','[]','勤勤念耦耕，不是釣虛名。',48,'全唐诗/poet.song.10000.json','["勤勤念耦耕，不是釣虛名。", "皓魄圓猶缺，芳巵滿故傾。", "佩韋防事急，分肉倚心平。", "此意將誰語，臨深坐冶城。"]'),
('2cc5752d-12af-4f08-85ec-82b6855e7e9d','謀退四首  其二','宋庠','宋','宋诗','song-poetry','','[]','常聞疏少傅，知足遽辭官。',48,'全唐诗/poet.song.10000.json','["常聞疏少傅，知足遽辭官。", "祖道賓儀盛，揮金里宴歡。", "畏途非蠖屈，高志自鵬摶。", "行路賢哉歎，吾心良所安。"]'),
('5eade276-166b-4cd0-b7e3-88d19727edc2','謀退四首  其三','宋庠','宋','宋诗','song-poetry','','[]','昔日於陵子，遺榮自灌園。',48,'全唐诗/poet.song.10000.json','["昔日於陵子，遺榮自灌園。", "三分輕國爵，一世謝人諠。", "野笠鋤春隴，橫槔汲曉源。", "區區冒榮者，天壤亦何言。"]'),
('73d56121-f31e-409a-a18b-275639736475','謀退四首  其四','宋庠','宋','宋诗','song-poetry','','[]','濟世才無取，登朝運所遭。',48,'全唐诗/poet.song.10000.json','["濟世才無取，登朝運所遭。", "濡鵜真竊祿，汗馬本非勞。", "漢重商賢隠，堯嗟潁客高。", "古今閒自況，何翅九牛毛。"]'),
('6378dad6-4487-4a33-bcd1-a939b4108c6a','秋日漫興','宋庠','宋','宋诗','song-poetry','','[]','天淡雲摧險，風清水始波。',48,'全唐诗/poet.song.10000.json','["天淡雲摧險，風清水始波。", "暗蟲催紡緯，驚鵲報填河。", "宮扇紈規掩，仙盤露彩多。", "空餘歸客恨，芝朮老巖阿。"]'),
('759bd7aa-bd3f-4be9-b2a6-47e466ea24d8','晚庭','宋庠','宋','宋诗','song-poetry','','[]','蒼霤秋霖歇，高軒夕景遲。',48,'全唐诗/poet.song.10000.json','["蒼霤秋霖歇，高軒夕景遲。", "桐凋金井恨，蘭老玉琴悲。", "巢燕寒初失，風蟬晚屢移。", "黄昏禽語鬧，相喚宿何枝。"]'),
('533c8def-0e74-4a6a-af85-1e4edeb6c44f','送王秀才下第隨侍東去','宋庠','宋','宋诗','song-poetry','','[]','春色鄉枌老，波聲客櫂催。',48,'全唐诗/poet.song.10000.json','["春色鄉枌老，波聲客櫂催。", "林烏貪夕哺，都鷁怨風摧。", "處晦囊中穎，加餐案上杯。", "重來期歲晏，飛藻右鄒枚。"]'),
('2acffa88-cc43-4a96-ae0a-b4bb2ff998b7','送明州章從事','宋庠','宋','宋诗','song-poetry','','[]','東國有嘉招，歸心越絕遥。',48,'全唐诗/poet.song.10000.json','["東國有嘉招，歸心越絕遥。", "幾程淮蚌月，一信海鰌潮。", "蓮渚熏談席，霞天認賦標。", "時平軍版息，麗藻入雲謠。"]'),
('b5c4ba27-1cd0-4f1e-ab9f-03553607d0ac','郡圃洗心亭宴坐對春物因書所見','宋庠','宋','宋诗','song-poetry','','[]','盡晝山楹坐，居然外物身。',48,'全唐诗/poet.song.10000.json','["盡晝山楹坐，居然外物身。", "野葵能向日，怖鴿解投人。", "萬萼融朱蠟，平蕪識紺茵。", "須知無事處，堪養不才臣。"]'),
('393162ae-0c31-4566-9909-678b97f0c399','宿齋太一宮寄天休','宋庠','宋','宋诗','song-poetry','','[]','入暮鳬鐘警，乘凉鵠帳褰。',48,'全唐诗/poet.song.10000.json','["入暮鳬鐘警，乘凉鵠帳褰。", "霧來燈欲濕，螢過草疑燃。", "野氣樽浮桂，幽香席藉荃。", "無因招傲吏，同宿一壺天。"]'),
('0aae8295-202c-4009-875c-746798ff0eb4','殘春夜雨','宋庠','宋','宋诗','song-poetry','','[]','春色無情老，宵雲有恨低。',48,'全唐诗/poet.song.10000.json','["春色無情老，宵雲有恨低。", "輕寒借鴻駛，早暝入烏啼。", "晦燭風生幔，漂花溜漲溪。", "滴階兼被草，聊此況凄迷。"]'),
('0c3a90b6-735f-4925-8e88-adb40fce74ed','寒野','宋庠','宋','宋诗','song-poetry','','[]','芳歲行遒盡，高堂興耿然。',48,'全唐诗/poet.song.10000.json','["芳歲行遒盡，高堂興耿然。", "林號欲風野，雲綻已霜天。", "烏彩疑留日，鴻聲似惡弦。", "幽衿忽忘返，更爲月娟娟。"]'),
('c69bb337-a51f-4b6d-963c-fc43a48bbdfc','正月三日作','宋庠','宋','宋诗','song-poetry','','[]','迎春纔十日，應月已三蓂。',48,'全唐诗/poet.song.10000.json','["迎春纔十日，應月已三蓂。", "池面開新素，山光復舊青。", "灰飛空玉琯，醅動漲金瓶。", "剩作尋芳具，當筵忌獨醒。"]'),
('c6b97ee3-82ef-491a-86da-929d9d186fb2','奉送滁州趙學士','宋庠','宋','宋诗','song-poetry','','[]','灼灼書林彥，胡爲江海濱。',48,'全唐诗/poet.song.10000.json','["灼灼書林彥，胡爲江海濱。", "希遷杜陵客，出守始平人。", "夕夢螭階遠，前驅隼旆新。", "離觴君莫愬，去去易沾巾。"]'),
('82342f0e-fada-481f-bcc7-9add7add7a9b','代書寄奉寧樞密直諫議學士','宋庠','宋','宋诗','song-poetry','','[]','故秋嘗假道，倏忽改芳年。',48,'全唐诗/poet.song.10000.json','["故秋嘗假道，倏忽改芳年。", "三疊黄河上，千花白髮邊。", "冰消牛口渡，山綠虎牢天。", "東望無人會，滎陽太守賢。"]'),
('14a73d33-ca6a-4728-a608-7f57f9849b1a','憂闋詣臺先寄獻臣天休二學士','宋庠','宋','宋诗','song-poetry','','[]','去國三年恨，還臺九死餘。',48,'全唐诗/poet.song.10000.json','["去國三年恨，還臺九死餘。", "凄凉曾釜粟，感咽晏楹書。", "鮒勺懷窮轍，鷄棲整故車。", "惟當親益友，敘闊費漣如。"]'),
('035b06bb-fe6c-4ee4-bce4-e147dc2d0fad','春野五首  其一','宋庠','宋','宋诗','song-poetry','','[]','衡蓽負城開，春兼野色來。',48,'全唐诗/poet.song.10000.json','["衡蓽負城開，春兼野色來。", "煙扶霽日柳，雪惱故年梅。", "波影魚先動，林聲鳥並催。", "欣欣羣意悅，病骨獨邅回。"]'),
('b6842239-1088-48d8-9fd6-4d7f5b219b0f','春野五首  其二','宋庠','宋','宋诗','song-poetry','','[]','陂色入柴關，陽和遠近還。',48,'全唐诗/poet.song.10000.json','["陂色入柴關，陽和遠近還。", "平蕪隨蹇步，新水照衰顔。", "廢堞鳥聲樂，晴臯雉羽斑。", "一逢樵客語，無竢辦連環。"]');
